// ── KaTeX ─────────────────────────────────────────────────────────────────────
function useKaTeX() {
  const [ready, setReady] = useState(false);
  useEffect(() => {
    if (window.katex) { setReady(true); return; }
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://cdnjs.cloudflare.com/ajax/libs/KaTeX/0.16.9/katex.min.css";
    document.head.appendChild(link);
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/KaTeX/0.16.9/katex.min.js";
    s.onload = () => setReady(true);
    document.head.appendChild(s);
  }, []);
  return ready;
}
function M({ tex }) {
  const ref = useRef();
  useEffect(() => {
    if (!ref.current || !window.katex) return;
    try { window.katex.render(tex, ref.current, { throwOnError: false }); }
    catch { ref.current.textContent = tex; }
  }, [tex]);
  return <span ref={ref} />;
}

// ── Global styles ─────────────────────────────────────────────────────────────
const GS = ({profile} = {}) => {
  // Thème courant (fallback sur "ocean" si profile absent / sans pref)
  // On duplique la logique locale car getTheme est défini plus bas dans le fichier.
  const themePref = profile?.prefs?.theme;
  const scalePref = profile?.prefs?.fontScale;
  const themeMap = {
    ocean:      { bgLight:'#E8EAF0', bgDark1:'#1A1A2E', bgDark2:'#0F3460' },
    crepuscule: { bgLight:'#F3EEF8', bgDark1:'#2D1B4E', bgDark2:'#4A1F5C' },
    foret:      { bgLight:'#E8EFE9', bgDark1:'#0F2818', bgDark2:'#0A4030' },
    papier:     { bgLight:'#FFFFFF', bgDark1:'#475569', bgDark2:'#1E293B' },
  };
  const scaleMap = { normal: 1.0, grand: 1.15, tres_grand: 1.3 };
  const th = themeMap[themePref] || themeMap.ocean;
  const scale = scaleMap[scalePref] || 1.0;
  return (
  <style>{`
    @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@700;800;900&family=DM+Sans:wght@400;500;600&display=swap');
    :root {
      --am-bg-light: ${th.bgLight};
      --am-bg-dark-1: ${th.bgDark1};
      --am-bg-dark-2: ${th.bgDark2};
      --am-font-scale: ${scale};
    }
    *{box-sizing:border-box;margin:0;padding:0;}
    body{background:#dde1ea;display:flex;justify-content:center;align-items:center;min-height:100vh;font-family:'DM Sans',sans-serif;}
    /* Taille de texte globale : appliquée au conteneur racine via transform scale.
       Ainsi TOUS les px hardcodés suivent proportionnellement. */
    .am-scale-wrapper {
      transform: scale(var(--am-font-scale));
      transform-origin: center center;
    }
    @keyframes popIn  {0%{transform:scale(.78);opacity:0}70%{transform:scale(1.04)}100%{transform:scale(1);opacity:1}}
    @keyframes slideUp{from{transform:translateY(18px);opacity:0}to{transform:translateY(0);opacity:1}}
    @keyframes slideInLeft{from{transform:translateX(-100%);opacity:0}to{transform:translateX(0);opacity:1}}
    @keyframes shake  {0%,100%{transform:translateX(0)}20%{transform:translateX(-7px)}40%{transform:translateX(7px)}60%{transform:translateX(-4px)}80%{transform:translateX(4px)}}
    @keyframes fadeIn {from{opacity:0}to{opacity:1}}
    @keyframes sigmaFloat {
      0%,100%{transform:translateY(0px);}
      50%{transform:translateY(-14px);}
    }
    @keyframes shadowPulse {
      0%,100%{transform:scaleX(1);opacity:0.22;}
      50%{transform:scaleX(0.65);opacity:0.10;}
    }
    .pop-in  {animation:popIn   .32s cubic-bezier(.34,1.56,.64,1) both;}
    .slide-up{animation:slideUp .26s ease both;}
    .slide-in-left{animation:slideInLeft .28s cubic-bezier(.34,1.2,.64,1) both;}
    .shake   {animation:shake   .38s ease;}
    .fade-in {animation:fadeIn  .22s ease both;}
    .sigma-float{animation:sigmaFloat 3s ease-in-out infinite;}
    .sigma-shadow{
      width:70%;margin:0 auto;height:12px;
      background:radial-gradient(ellipse,rgba(0,0,0,0.35) 0%,transparent 75%);
      border-radius:50%;
      animation:shadowPulse 3s ease-in-out infinite;
    }
    @keyframes goldGlow {
      0%,100%{filter:drop-shadow(0 0 12px gold) drop-shadow(0 0 24px rgba(255,215,0,0.5));}
      50%{filter:drop-shadow(0 0 22px gold) drop-shadow(0 0 44px rgba(255,215,0,0.8));}
    }
    .sigma-gold{animation:sigmaFloat 3s ease-in-out infinite,goldGlow 2s ease-in-out infinite;}
    .katex{font-size:1em !important;}
    .katex-display{overflow-x:auto;overflow-y:hidden;}
    .katex .mtext span{white-space:normal !important; word-break:break-word;}
    ::-webkit-scrollbar{width:3px;}::-webkit-scrollbar-thumb{background:#CBD5E1;border-radius:99px;}
  `}</style>
  );
};

// ═══════════════════════════════════════════════════════════════════════════════
//  GRAPH SYSTEM
// ═══════════════════════════════════════════════════════════════════════════════

function mkC(x1, x2, y1, y2, W = 254, H = 158) {
  return {
    W, H, x1, x2, y1, y2,
    sx: x => ((x - x1) / (x2 - x1)) * W,
    sy: y => H - ((y - y1) / (y2 - y1)) * H,
  };
}

function mkPath(fn, c, steps = 90) {
  const { x1, x2, y1, y2, sx, sy } = c;
  let d = "", up = true;
  for (let i = 0; i <= steps; i++) {
    const x = x1 + (x2 - x1) * i / steps;
    const y = fn(x);
    const ok = isFinite(y) && y >= y1 - 0.5 && y <= y2 + 0.5;
    if (ok) {
      const px = sx(x).toFixed(1);
      const py = sy(Math.min(y2 + 0.4, Math.max(y1 - 0.4, y))).toFixed(1);
      d += up ? `M${px},${py}` : ` L${px},${py}`;
      up = false;
    } else { up = true; }
  }
  return d;
}

// Filled region between curve and x-axis
function mkShade(fn, x1, x2, c, steps = 60) {
  const pts = [];
  for (let i = 0; i <= steps; i++) {
    const x = x1 + (x2 - x1) * i / steps;
    const y = Math.max(c.y1, Math.min(c.y2, fn(x)));
    pts.push(`${c.sx(x).toFixed(1)},${c.sy(y).toFixed(1)}`);
  }
  const oy = c.sy(0).toFixed(1);
  return `M${pts[0]} ${pts.slice(1).map(p => `L${p}`).join(' ')} L${c.sx(x2).toFixed(1)},${oy} L${c.sx(x1).toFixed(1)},${oy} Z`;
}

// Axes + grid
function Axes({ c }) {
  const { W, H, x1, x2, y1, y2, sx, sy } = c;
  const ox = sx(0), oy = sy(0);
  const xs = [], ys = [];
  for (let x = Math.ceil(x1); x <= Math.floor(x2); x++) xs.push(x);
  for (let y = Math.ceil(y1); y <= Math.floor(y2); y++) ys.push(y);
  const range = (v, max) => Math.abs(v) <= max && v !== 0;
  const xSpan = x2 - x1, ySpan = y2 - y1;
  const xStep = xSpan > 8 ? 2 : 1;
  const yStep = ySpan > 8 ? 2 : 1;
  return (<>
    {xs.map(x => <line key={`gx${x}`} x1={sx(x)} y1={0} x2={sx(x)} y2={H} stroke="#E8EDF3" strokeWidth={0.5} />)}
    {ys.map(y => <line key={`gy${y}`} x1={0} y1={sy(y)} x2={W} y2={sy(y)} stroke="#E8EDF3" strokeWidth={0.5} />)}
    <line x1={2} y1={oy} x2={W - 5} y2={oy} stroke="#475569" strokeWidth={1.5} />
    <line x1={ox} y1={H - 2} x2={ox} y2={4} stroke="#475569" strokeWidth={1.5} />
    <polygon points={`${W},${oy} ${W-7},${oy-3} ${W-7},${oy+3}`} fill="#475569" />
    <polygon points={`${ox},0 ${ox-3},7 ${ox+3},7`} fill="#475569" />
    {xs.map(x => (<g key={`tx${x}`}>
      <line x1={sx(x)} y1={oy - 3} x2={sx(x)} y2={oy + 3} stroke="#475569" strokeWidth={1} />
      {x !== 0 && Math.abs(x) % xStep === 0 && range(x, 12) && (
        <text x={sx(x)} y={oy + 12} textAnchor="middle" fontSize="8" fill="#64748B" fontFamily="DM Sans">{x}</text>
      )}
    </g>))}
    {ys.map(y => (<g key={`ty${y}`}>
      <line x1={ox - 3} y1={sy(y)} x2={ox + 3} y2={sy(y)} stroke="#475569" strokeWidth={1} />
      {y !== 0 && Math.abs(y) % yStep === 0 && range(y, 12) && (
        <text x={ox - 5} y={sy(y) + 3} textAnchor="end" fontSize="8" fill="#64748B" fontFamily="DM Sans">{y}</text>
      )}
    </g>))}
    <text x={ox + 3} y={oy + 12} textAnchor="start" fontSize="8" fill="#64748B" fontFamily="DM Sans">O</text>
    <text x={W - 2} y={oy - 4} textAnchor="end" fontSize="9" fill="#94A3B8" fontFamily="DM Sans" fontStyle="italic">x</text>
    <text x={ox + 4} y={10} textAnchor="start" fontSize="9" fill="#94A3B8" fontFamily="DM Sans" fontStyle="italic">y</text>
  </>);
}

// Main graph renderer — preExtras renders BEHIND axes (e.g. shading)
function Graph({ spec }) {
  const {
    fn, fn2, xr = [-5, 5], yr = [-4, 4],
    color = "#2563EB", color2 = "#9333EA",
    label = "f", extras, preExtras,
  } = spec;
  const c = mkC(xr[0], xr[1], yr[0], yr[1]);
  const { W, H, sx, sy } = c;
  const lx = xr[1] - (xr[1] - xr[0]) * 0.09;
  const ly = fn(lx);
  const lOk = isFinite(ly) && ly >= yr[0] && ly <= yr[1];
  return (
    <svg viewBox={`0 0 ${W} ${H}`}
      style={{ width: "100%", maxHeight: 160, display: "block", background: "#FAFCFF", borderRadius: 8, border: "1px solid #E2E8F0" }}>
      {/* BACKGROUND layer: shading */}
      {preExtras && preExtras(c)}
      <Axes c={c} />
      <path d={mkPath(fn, c)} stroke={color} strokeWidth={2.2} fill="none" strokeLinecap="round" strokeLinejoin="round" />
      {fn2 && <path d={mkPath(fn2, c)} stroke={color2} strokeWidth={1.8} fill="none" strokeDasharray="6,3" />}
      {lOk && <text x={sx(lx) + 5} y={sy(ly) - 4} fontSize="10" fill={color} fontFamily="DM Sans" fontStyle="italic" fontWeight="bold">{label}</text>}
      {/* FOREGROUND layer: dots, labels */}
      {extras && extras(c)}
    </svg>
  );
}

// ── SVG helper primitives ─────────────────────────────────────────────────────
const gPt  = (x, y, c, col = "#EF4444") =>
  <circle key={`pt${x}${y}`} cx={c.sx(x)} cy={c.sy(y)} r={3.5} fill={col} stroke="#fff" strokeWidth={1} />;

const gDV  = (x, c, col = "#F59E0B") =>
  <line key={`dv${x}`} x1={c.sx(x)} y1={0} x2={c.sx(x)} y2={c.H} stroke={col} strokeWidth={1.2} strokeDasharray="5,3" />;

const gDH  = (y, c, col = "#F59E0B") =>
  <line key={`dh${y}`} x1={0} y1={c.sy(y)} x2={c.W} y2={c.sy(y)} stroke={col} strokeWidth={1.2} strokeDasharray="5,3" />;

const gTan = (fn, a, m, c, col = "#EF4444") =>
  <path key={`tan${a}`} d={mkPath(x => m * (x - a) + fn(a), c)} stroke={col} strokeWidth={1.8} fill="none" strokeDasharray="6,3" />;

// Shaded region between curve and x-axis
const gShade = (fn, x1, x2, c, col) =>
  <path key={`sh${x1}${x2}${col}`} d={mkShade(fn, x1, x2, c)} fill={col} stroke="none" />;

// Sign label (+ or −) placed at a position
const gSign = (x, y, sign, c, col) =>
  <text key={`sg${x}${y}`} x={c.sx(x)} y={c.sy(y)} textAnchor="middle" fontSize="13" fill={col} fontWeight="bold" fontFamily="DM Sans">{sign}</text>;

// Annotation label near a point
const gNote = (x, y, txt, c, col = "#374151") =>
  <text key={`nt${x}${y}`} x={c.sx(x) + 5} y={c.sy(y) - 5} fontSize="8.5" fill={col} fontFamily="DM Sans" fontWeight="600">{txt}</text>;

// Trend arrow (increase/decrease indicator) at a point on the curve
const gTrend = (fn, x, inc, c) => {
  const px = c.sx(x), py = c.sy(fn(x));
  const col = inc ? "#10B981" : "#EF4444";
  const pts = inc
    ? `${px - 5},${py + 4} ${px},${py - 4} ${px + 5},${py + 4}`
    : `${px - 5},${py - 4} ${px},${py + 4} ${px + 5},${py - 4}`;
  return <polygon key={`tr${x}`} points={pts} fill={col} opacity={0.75} />;
};

// Color constants
const C_POS = "rgba(16,185,129,0.15)";
const C_NEG = "rgba(239,68,68,0.13)";
const C_MAX = "#10B981";
const C_MIN = "#EF4444";

// ═══════════════════════════════════════════════════════════════════════════════
//  DRAG GRAPH — interactive inequality solver
// ═══════════════════════════════════════════════════════════════════════════════

// Numerical root-finder: find x where fn(x) = k
function findRoots(fn, k, xr, steps = 600) {
  const [x0, x1] = xr;
  const dx = (x1 - x0) / steps;
  const roots = [];
  let prev = fn(x0) - k;
  for (let i = 1; i <= steps; i++) {
    const x = x0 + i * dx;
    const curr = fn(x) - k;
    if (prev * curr < 0) {
      let lo = x - dx, hi = x;
      for (let j = 0; j < 24; j++) {
        const mid = (lo + hi) / 2;
        if ((fn(lo) - k) * (fn(mid) - k) < 0) hi = mid; else lo = mid;
      }
      const r = (lo + hi) / 2;
      if (roots.length === 0 || Math.abs(r - roots[roots.length - 1]) > 0.05)
        roots.push(r);
    }
    prev = curr;
  }
  return roots;
}

// Format x value for display on axis
const fmtX = x => {
  const r = Math.round(x * 10) / 10;
  return r === 0 ? "0" : String(r);
};

// Shade path above/below the dragged line
function mkDragShade(fn, k, type, xr, c, steps = 150) {
  const [x0, x1] = xr;
  const dx = (x1 - x0) / steps;
  const regions = [];
  let seg = null;
  for (let i = 0; i <= steps; i++) {
    const x = x0 + i * dx;
    const y = fn(x);
    const sat = (type === "<" || type === "≤") ? y < k : y > k;
    if (sat && !seg) seg = x;
    if (!sat && seg != null) { regions.push([seg, x]); seg = null; }
  }
  if (seg != null) regions.push([seg, x1]);
  return regions;
}

function DragGraph({ spec, onConclude }) {
  const { fn, xr, yr, questionTex, type, tipTex, padType, a } = spec;
  // phase: "drag" → "pad" → "done"
  const [phase, setPhase]     = useState("drag");
  const [k, setK]             = useState(0);
  const [dragging, setDragging] = useState(false);
  const [padVal, setPadVal]   = useState("");
  const [padState, setPadState] = useState("idle"); // idle|correct|wrong
  const svgRef = useRef(null);

  const c = mkC(xr[0], xr[1], yr[0], yr[1], 254, 158);
  const { W, H, sx, sy } = c;

  // Convert screen Y → math Y, clamped — only in drag phase
  const screenToK = useCallback((clientY) => {
    const rect = svgRef.current?.getBoundingClientRect();
    if (!rect) return 0;
    const py = (clientY - rect.top) / rect.height * H;
    const raw = yr[1] - (py / H) * (yr[1] - yr[0]);
    return Math.max(yr[0] + 0.4, Math.min(yr[1] - 0.4, raw));
  }, [yr]);

  const onStart = useCallback((e) => {
    if (phase !== "drag") return;
    e.preventDefault();
    setDragging(true);
    setK(screenToK(e.touches ? e.touches[0].clientY : e.clientY));
  }, [phase, screenToK]);

  const onMove = useCallback((e) => {
    if (!dragging) return;
    e.preventDefault();
    setK(screenToK(e.touches ? e.touches[0].clientY : e.clientY));
  }, [dragging, screenToK]);

  const onEnd = useCallback(() => setDragging(false), []);

  useEffect(() => {
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onEnd);
    window.addEventListener("touchmove", onMove, { passive: false });
    window.addEventListener("touchend", onEnd);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onEnd);
      window.removeEventListener("touchmove", onMove);
      window.removeEventListener("touchend", onEnd);
    };
  }, [onMove, onEnd]);

  const kR = Math.round(k * 10) / 10;
  const lineY = sy(kR);
  const roots = findRoots(fn, kR, xr);
  const shadeRegions = mkDragShade(fn, kR, type, xr, c);
  const shadeCol = (type === "<" || type === "≤") ? "rgba(239,68,68,.15)" : "rgba(16,185,129,.15)";
  const canProceed = phase === "drag" && roots.length > 0;

  // Validate the pad answer
  const validatePad = (val) => {
    if (padState !== "idle") return;
    const ok = val.trim() === a.trim();
    setPadState(ok ? "correct" : "wrong");
    setPhase("done");
    onConclude(ok);
  };

  // ── SVG Graph (shared between phases) ──────────────────────────────────────
  const svgGraph = (
    <div style={{position:"relative",borderRadius:10,overflow:"hidden",
      border:`1.5px solid ${phase==="done"&&padState==="correct"?"#10B981":phase==="done"?"#EF4444":"#E2E8F0"}`,
      background:"#FAFCFF",flexShrink:0,
      cursor:phase==="drag"?(dragging?"grabbing":"grab"):"default",
      touchAction:"none"}}>
      <svg ref={svgRef} viewBox={`0 0 ${W} ${H}`}
        style={{width:"100%",display:"block",maxHeight:155}}
        onMouseDown={onStart} onTouchStart={onStart}>
        {/* Shade (inequalities) */}
        {type && shadeRegions.map(([x1,x2],i)=>{
          const px1=Math.max(0,sx(x1)), px2=Math.min(W,sx(x2));
          if(px2<=px1) return null;
          return <rect key={i} x={px1} y={0} width={px2-px1} height={H} fill={shadeCol}/>;
        })}
        <Axes c={c}/>
        <path d={mkPath(fn,c,200)} stroke="#2563EB" strokeWidth={2.2} fill="none"
          strokeLinecap="round" strokeLinejoin="round"/>
        {/* Horizontal line */}
        <line x1={0} y1={lineY} x2={W} y2={lineY}
          stroke="#F59E0B" strokeWidth={10} strokeOpacity={dragging ? 0.22 : 0.08}/>
        <line x1={0} y1={lineY} x2={W} y2={lineY}
          stroke="#F59E0B" strokeWidth={2} strokeDasharray="5,3"/>
        {/* y=k label */}
        <rect x={W-38} y={lineY-9} width={38} height={13} rx={4}
          fill="#FAFCFF" fillOpacity={0.92}/>
        <text x={W-19} y={lineY+1.5} textAnchor="middle" fontSize={8.5}
          fill="#B45309" fontWeight="bold" fontFamily="DM Sans">y = {kR}</text>
        {/* Handle (only in drag phase) */}
        {phase==="drag"&&<>
          <circle cx={10} cy={lineY} r={10}
            fill={dragging?"#F59E0B":"#FEF3C7"} stroke="#F59E0B" strokeWidth={2}/>
          <text x={10} y={lineY+4} textAnchor="middle" fontSize={11}
            fill="#92400E" fontFamily="DM Sans" fontWeight="bold">⇕</text>
        </>}
        {/* Intersection points */}
        {roots.map((xi,i)=>{
          const px=sx(xi);
          if(px<4||px>W-4) return null;
          return (
            <g key={i}>
              <line x1={px} y1={lineY} x2={px} y2={sy(0)}
                stroke="#F59E0B" strokeWidth={1.2} strokeDasharray="3,3" strokeOpacity={0.7}/>
              <circle cx={px} cy={lineY} r={5.5} fill="#F59E0B" stroke="#fff" strokeWidth={1.5}/>
              <rect x={px-14} y={sy(0)+3} width={28} height={13} rx={5} fill="#F59E0B"/>
              <text x={px} y={sy(0)+12} textAnchor="middle" fontSize={8}
                fill="#78350F" fontWeight="bold" fontFamily="DM Sans">x={fmtX(xi)}</text>
            </g>
          );
        })}
      </svg>
      {/* Drag hint */}
      {phase==="drag"&&!dragging&&(
        <div style={{position:"absolute",bottom:5,left:"50%",transform:"translateX(-50%)",
          background:"rgba(30,41,59,.8)",borderRadius:20,padding:"3px 10px",
          fontSize:10,color:"#94A3B8",fontWeight:700,whiteSpace:"nowrap",pointerEvents:"none"}}>
          ☝️ Fais glisser la droite jaune
        </div>
      )}
      {/* "position locked" badge in pad/done phase */}
      {phase!=="drag"&&(
        <div style={{position:"absolute",top:5,right:5,
          background:"rgba(30,41,59,.85)",borderRadius:20,padding:"3px 8px",
          fontSize:9,color:"#94A3B8",fontWeight:700,pointerEvents:"none"}}>
          🔒 y = {kR}
        </div>
      )}
    </div>
  );

  return (
    <div style={{display:"flex",flexDirection:"column",gap:8,flexShrink:0}}>

      {/* Question banner */}
      <div style={{background:"#EFF6FF",borderRadius:10,padding:"7px 12px",
        fontSize:13,fontWeight:800,color:"#1D4ED8",
        display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
        <span>📐</span>
        <M tex={questionTex}/>
      </div>

      {/* SVG */}
      {svgGraph}

      {/* Live intersections */}
      <div style={{background:"#F8FAFC",border:"1.5px solid #E2E8F0",borderRadius:10,
        padding:"7px 12px",display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
        <span style={{fontSize:12}}>🎯</span>
        {roots.length===0
          ? <span style={{fontSize:11,color:"#94A3B8",fontWeight:600}}>Aucune intersection visible</span>
          : <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
              {roots.map((xi,i)=>(
                <span key={i} style={{background:"#FEF3C7",border:"1.5px solid #F59E0B",
                  borderRadius:7,padding:"2px 8px",fontSize:12,fontWeight:800,color:"#92400E",
                  fontFamily:"'DM Sans',sans-serif"}}>x = {fmtX(xi)}</span>
              ))}
            </div>
        }
        <span style={{marginLeft:"auto",fontSize:10,color:"#94A3B8",
          fontFamily:"'DM Sans',sans-serif",flexShrink:0}}>y = {kR}</span>
      </div>

      {/* Tip */}
      <div style={{background:"#EFF6FF",borderRadius:9,padding:"6px 11px",
        fontSize:11,color:"#3B82F6",fontWeight:600,flexShrink:0}}>
        💡 <M tex={tipTex}/>
      </div>

      {/* ── PHASE DRAG : bouton "Valider ma position" ── */}
      {phase==="drag" && canProceed && (
        <button onClick={()=>setPhase("pad")} className="pop-in" style={{
          padding:"12px",border:"none",borderRadius:12,
          background:"linear-gradient(135deg,#F59E0B,#D97706)",
          color:"#fff",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:800,
          cursor:"pointer",boxShadow:"0 5px 15px rgba(245,158,11,.35)",flexShrink:0}}>
          ✅ Position validée — je conclus ↓
        </button>
      )}

      {/* ── PHASE PAD : saisie de la solution ── */}
      {phase==="pad" && (
        <div className="fade-in" style={{flexShrink:0}}>
          <div style={{fontSize:12,fontWeight:700,color:"#475569",
            marginBottom:7,textAlign:"center"}}>
            {padType==="eq"
              ? "Maintenant tape l'ensemble solution S={…}"
              : "Maintenant tape l'ensemble solution"}
          </div>
          {padType==="eq"
            ? <EqPad  value={padVal} onChange={setPadVal} onValidate={validatePad}
                state={padState} correctAnswer={a}/>
            : <SolPad value={padVal} onChange={setPadVal} onValidate={validatePad}
                state={padState} correctAnswer={a}/>
          }
        </div>
      )}

      {/* ── PHASE DONE : feedback ── */}
      {phase==="done" && (
        <div className="fade-in" style={{
          background:padState==="correct"?"#ECFDF5":"#FEF2F2",
          border:`2px solid ${padState==="correct"?"#10B981":"#EF4444"}`,
          borderRadius:12,padding:"11px 14px",flexShrink:0}}>
          <div style={{fontSize:12,fontWeight:700,
            color:padState==="correct"?"#065F46":"#991B1B",marginBottom:4}}>
            {padState==="correct" ? "✅ Parfait !" : "❌ Pas tout à fait — la correction :"}
          </div>
          <div style={{fontSize:15,fontWeight:900,color:"#1E293B"}}>
            <M tex={padType==="eq" ? `S=${a}` : `S=\\,${a}`}/>
          </div>
        </div>
      )}
    </div>
  );
}
