// Single interactive cell: fixed value or hole to fill
function TCell({ cell, filled, active, validated, onActivate }) {
  if (!cell.hole) {
    const isArr = cell.kind === "arrow";
    return (
      <div style={{display:"flex",alignItems:"center",justifyContent:"center",
        fontSize:isArr?16:12, fontWeight:isArr?900:700,
        color:isArr?"#2563EB":"#1E293B", padding:"3px 2px", lineHeight:1}}>
        {cell.v}
      </div>
    );
  }
  const ok  = validated && filled === cell.v;
  const ko  = validated && filled !== cell.v;
  const isArr = cell.kind === "arrow";
  return (
    <div onClick={onActivate} style={{
      display:"flex",alignItems:"center",justifyContent:"center",
      border:`1.5px ${active&&!validated?"solid":"dashed"} ${ok?"#10B981":ko?"#EF4444":active?"#2563EB":"#94A3B8"}`,
      borderRadius:6, cursor:validated?"default":"pointer",
      background:ok?"#ECFDF5":ko?"#FEF2F2":active?"#EFF6FF":"#F8FAFC",
      color:ok?"#065F46":ko?"#EF4444":active?"#1D4ED8":"#94A3B8",
      fontSize:isArr?15:12, fontWeight:800,
      minWidth:isArr?26:22, minHeight:24, padding:"3px 4px",
      transition:"all .12s"
    }}>
      {validated ? cell.v : (filled || "?")}
    </div>
  );
}

// Arrow picker: ↗ / ↘
function ArrowPicker({ onPick }) {
  return (
    <div style={{display:"flex",gap:10,flexShrink:0}}>
      {["↗","↘"].map(a=>(
        <button key={a} onClick={()=>onPick(a)} style={{
          flex:1, height:58, fontSize:28, fontWeight:900,
          background:"#EFF6FF", border:"2.5px solid #3B82F6",
          borderRadius:14, cursor:"pointer", color:"#1D4ED8",
          boxShadow:"0 4px 14px rgba(59,130,246,.2)"
        }}>{a}</button>
      ))}
    </div>
  );
}

// Sign picker: + / −
function SignPicker({ onPick }) {
  const opts=[{v:"+",bg:"#ECFDF5",bd:"#10B981",tc:"#065F46"},
              {v:"-",bg:"#FEF2F2",bd:"#EF4444",tc:"#991B1B"}];
  return (
    <div style={{display:"flex",gap:10,flexShrink:0}}>
      {opts.map(o=>(
        <button key={o.v} onClick={()=>onPick(o.v)} style={{
          flex:1, height:58, fontSize:26, fontWeight:900,
          background:o.bg, border:`2.5px solid ${o.bd}`,
          borderRadius:14, cursor:"pointer", color:o.tc,
          boxShadow:`0 4px 14px ${o.bd}44`
        }}>{o.v}</button>
      ))}
    </div>
  );
}

// Numpad for tableau (with ± for negatives)
function TNumPad({ value, onChange, onValidate }) {
  const keys = ["7","8","9","4","5","6","1","2","3","±","0","⌫"];
  const press = k => {
    if(k==="⌫") { onChange(v=>v.length>0?v.slice(0,-1):""); return; }
    if(k==="±") { onChange(v=>v.startsWith("-")?v.slice(1):v?"-"+v:""); return; }
    if(value.replace("-","").length>=2) return;
    onChange(v=>v+k);
  };
  const canOK = value.length>0 && value!=="-";
  return (
    <div style={{display:"flex",flexDirection:"column",gap:7,flexShrink:0}}>
      <div style={{background:"#F8FAFC",border:"2px solid #CBD5E1",borderRadius:12,
        padding:"7px 12px",textAlign:"center",minHeight:42,
        display:"flex",alignItems:"center",justifyContent:"center"}}>
        <span style={{fontFamily:"'Nunito',sans-serif",fontSize:22,fontWeight:900,
          color:"#1E293B",letterSpacing:2}}>{value||"—"}</span>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6}}>
        {keys.map(k=>(
          <button key={k} onClick={()=>press(k)} style={{
            height:44, borderRadius:10, border:"none",
            fontSize:k==="±"||k==="⌫"?15:19, fontWeight:800,
            fontFamily:"'Nunito',sans-serif", cursor:"pointer",
            background:k==="⌫"?"#FEF2F2":k==="±"?"#F1F5F9":"#fff",
            color:k==="⌫"?"#EF4444":k==="±"?"#475569":"#1E293B",
            boxShadow:"0 2px 6px rgba(0,0,0,.07)"
          }}>{k}</button>
        ))}
      </div>
      <button onClick={()=>canOK&&onValidate(value)} style={{
        padding:"12px", border:"none", borderRadius:12,
        background:canOK?"linear-gradient(135deg,#10B981,#059669)":"#E2E8F0",
        color:canOK?"#fff":"#94A3B8", fontFamily:"'Nunito',sans-serif",
        fontSize:14, fontWeight:800, cursor:canOK?"pointer":"not-allowed"
      }}>Confirmer ✓</button>
    </div>
  );
}

// Grid renderer — Tableau de Variations
function TableauVarGrid({ spec, activeFill, fills, validated, onCellClick }) {
  const { xVals, cells } = spec;
  const n = xVals.length;
  // Grid: label col + (2n-1) data cols (alternating value/arrow)
  const gridCols = `24px ${Array(2*n-1).fill("1fr").join(" ")}`;
  return (
    <div style={{border:"1.5px solid #CBD5E1",borderRadius:8,overflow:"hidden",
      background:"#fff",marginBottom:8}}>
      {/* x row */}
      <div style={{display:"grid",gridTemplateColumns:gridCols,
        borderBottom:"1.5px solid #CBD5E1",background:"#F8FAFC",minHeight:26}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"center",
          fontWeight:700,fontSize:10,color:"#64748B",
          borderRight:"1.5px solid #CBD5E1"}}>x</div>
        {cells.map((_,i)=>(
          <div key={`xr${i}`} style={{
            display:"flex",alignItems:"center",justifyContent:"center",
            borderLeft:i%2===0?"1px solid #CBD5E1":"none",
            padding:"3px 1px",fontWeight:700,fontSize:11,color:"#1E293B"
          }}>
            {i%2===0 ? xVals[i/2] : ""}
          </div>
        ))}
      </div>
      {/* f(x) row */}
      <div style={{display:"grid",gridTemplateColumns:gridCols,minHeight:32}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"center",
          fontWeight:700,fontSize:9,color:"#64748B",
          borderRight:"1.5px solid #CBD5E1",flexDirection:"column",lineHeight:1.2,padding:"2px"}}>
          <span>f</span><span style={{fontSize:8}}>(x)</span>
        </div>
        {cells.map((cell,i)=>(
          <div key={`fr${i}`} style={{
            display:"flex",alignItems:"center",justifyContent:"center",
            borderLeft:i%2===0?"1px solid #CBD5E1":"none",
            padding:"3px 1px"
          }}>
            <TCell cell={cell} filled={fills[i]} active={activeFill===i}
              validated={validated}
              onActivate={()=>cell.hole&&!validated&&onCellClick(i)}/>
          </div>
        ))}
      </div>
    </div>
  );
}

// Grid renderer — Tableau de Signes
function TableauSignGrid({ spec, activeFill, fills, validated, onCellClick }) {
  const { xVals, cells, rows } = spec;
  // cells = [sign, 0, sign, 0, ..., sign] pour la ligne f(x) finale
  // rows (optionnel) = [{label, cells:[...]}, ...] pour les lignes intermédiaires (facteurs)
  // Indexation globale : row 0 = [0..cells.length-1], row 1 = [cells.length..2n-1], ..., ligne f = dernière
  const hasRows = Array.isArray(rows) && rows.length > 0;
  const allRows = hasRows ? [...rows, { label: "f(x)", cells, isFinal: true }] : [{ label: "f(x)", cells, isFinal: true }];
  // Offsets des lignes : row i commence à offset[i]
  const offsets = [];
  let off = 0;
  for (const r of allRows) { offsets.push(off); off += r.cells.length; }

  const colDefs = cells.map((_,i)=>i%2===0?"1fr":"26px").join(" ");
  const gridCols = `44px ${colDefs}`;
  return (
    <div style={{border:"1.5px solid #CBD5E1",borderRadius:8,overflow:"hidden",
      background:"#fff",marginBottom:8}}>
      {/* x row */}
      <div style={{display:"grid",gridTemplateColumns:gridCols,
        borderBottom:"1.5px solid #CBD5E1",background:"#F8FAFC",minHeight:24}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"center",
          fontWeight:700,fontSize:10,color:"#64748B",borderRight:"1.5px solid #CBD5E1"}}>x</div>
        {cells.map((_,i)=>{
          const isRoot=i%2===1;
          return (
            <div key={`xr${i}`} style={{
              display:"flex",alignItems:"center",
              justifyContent:i===0?"flex-start":i===cells.length-1?"flex-end":"center",
              borderLeft:isRoot?"1.5px solid #CBD5E1":"1px solid #E2E8F0",
              background:isRoot?"#F1F5F9":"transparent",
              padding:"3px 4px",fontWeight:700,fontSize:11,color:"#1E293B"
            }}>
              {isRoot ? xVals[(i-1)/2+1] : (i===0?"-∞":i===cells.length-1?"+∞":"")}
            </div>
          );
        })}
      </div>
      {/* Toutes les lignes : d'abord facteurs (si rows), puis f(x) final */}
      {allRows.map((row, rowIdx) => {
        const rowOffset = offsets[rowIdx];
        const isFinalRow = row.isFinal;
        return (
          <div key={`row${rowIdx}`} style={{display:"grid",gridTemplateColumns:gridCols,minHeight:30,
            borderTop: rowIdx>0?"1.5px solid #CBD5E1":"none",
            background: isFinalRow && hasRows ? "#FFFBEB" : "transparent"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"center",
              fontWeight:700,fontSize:10,color:"#64748B",
              borderRight:"1.5px solid #CBD5E1",padding:"2px 4px",
              fontFamily:"'DM Sans',serif"}}>
              <M tex={row.label}/>
            </div>
            {row.cells.map((cell,i)=>{
              const isRoot=i%2===1;
              const globalIdx = rowOffset + i;
              return (
                <div key={`rc${rowIdx}-${i}`} style={{
                  display:"flex",alignItems:"center",justifyContent:"center",
                  borderLeft:isRoot?"1.5px solid #CBD5E1":"1px solid #E2E8F0",
                  background:isRoot?"#F1F5F9":"transparent",
                  padding:"3px 2px"
                }}>
                  <TCell cell={cell} filled={fills[globalIdx]} active={activeFill===globalIdx}
                    validated={validated}
                    onActivate={()=>cell.hole&&!validated&&onCellClick(globalIdx)}/>
                </div>
              );
            })}
          </div>
        );
      })}
    </div>
  );
}

