//  PROBABILITY VISUALS
// ═══════════════════════════════════════════════════════════════════════════════

// Fraction rendered as SVG (num over den with bar)
function SvgFrac({ num, den, cx, cy, col = "#475569", sz = 8.5 }) {
  const w = Math.max(String(num).length, String(den).length) * sz * 0.65 + 5;
  return (
    <g>
      <text x={cx} y={cy} textAnchor="middle" fontSize={sz} fill={col} fontFamily="DM Sans">{num}</text>
      <line x1={cx - w / 2} y1={cy + 2.5} x2={cx + w / 2} y2={cy + 2.5} stroke={col} strokeWidth={0.9} />
      <text x={cx} y={cy + sz + 3} textAnchor="middle" fontSize={sz} fill={col} fontFamily="DM Sans">{den}</text>
    </g>
  );
}

// Probability tree SVG component
// spec: { pA:[n,d], pCA:[n,d], pDA:[n,d], pCBarA:[n,d], pDBarA:[n,d], labelC, labelD }
function ProbaTree({ spec }) {
  const { pA, pCA, pDA, pCBarA, pDBarA, labelC = "C", labelD = "D" } = spec;
  const pBarA = [pA[1] - pA[0], pA[1]];
  const W = 252, H = 164;
  // Coordinates
  const R   = [12,  82];   // root
  const A   = [68,  30];   // first level A
  const BA  = [68, 134];   // first level Ā
  const AC  = [210,  8];   // leaves
  const AD  = [210, 52];
  const BC  = [210, 112];
  const BD  = [210, 156];
  const lx  = 216;         // leaf label x
  const lc  = "#64748B";   // line color

  // Branch midpoints
  const mRA  = [(R[0]+A[0])/2,   (R[1]+A[1])/2];
  const mRBA = [(R[0]+BA[0])/2,  (R[1]+BA[1])/2];
  const mAC  = [(A[0]+AC[0])/2,  (A[1]+AC[1])/2];
  const mAD  = [(A[0]+AD[0])/2,  (A[1]+AD[1])/2];
  const mBAC = [(BA[0]+BC[0])/2, (BA[1]+BC[1])/2];
  const mBAD = [(BA[0]+BD[0])/2, (BA[1]+BD[1])/2];

  return (
    <svg viewBox={`0 0 ${W} ${H}`}
      style={{ width: "100%", maxHeight: 164, display: "block", background: "#FAFCFF", borderRadius: 8, border: "1px solid #E2E8F0" }}>
      {/* Branch lines */}
      <line x1={R[0]} y1={R[1]} x2={A[0]}  y2={A[1]}  stroke={lc} strokeWidth={1.5} />
      <line x1={R[0]} y1={R[1]} x2={BA[0]} y2={BA[1]} stroke={lc} strokeWidth={1.5} />
      <line x1={A[0]}  y1={A[1]}  x2={AC[0]} y2={AC[1]} stroke={lc} strokeWidth={1.5} />
      <line x1={A[0]}  y1={A[1]}  x2={AD[0]} y2={AD[1]} stroke={lc} strokeWidth={1.5} />
      <line x1={BA[0]} y1={BA[1]} x2={BC[0]} y2={BC[1]} stroke={lc} strokeWidth={1.5} />
      <line x1={BA[0]} y1={BA[1]} x2={BD[0]} y2={BD[1]} stroke={lc} strokeWidth={1.5} />

      {/* Node label A */}
      <text x={A[0]-4}  y={A[1]-6}   textAnchor="end" fontSize={12} fill="#2563EB" fontWeight="bold" fontFamily="DM Sans">A</text>
      {/* Node label Ā (A with overline bar) */}
      <text x={BA[0]-4} y={BA[1]+14} textAnchor="end" fontSize={12} fill="#7C3AED" fontWeight="bold" fontFamily="DM Sans">A</text>
      <line x1={BA[0]-14} y1={BA[1]+2} x2={BA[0]-4} y2={BA[1]+2} stroke="#7C3AED" strokeWidth={1.2} />

      {/* Leaf labels */}
      <text x={lx} y={AC[1]+4}  fontSize={12} fill="#2563EB" fontWeight="bold" fontFamily="DM Sans">{labelC}</text>
      <text x={lx} y={AD[1]+4}  fontSize={12} fill="#2563EB" fontWeight="bold" fontFamily="DM Sans">{labelD}</text>
      <text x={lx} y={BC[1]+4}  fontSize={12} fill="#7C3AED" fontWeight="bold" fontFamily="DM Sans">{labelC}</text>
      <text x={lx} y={BD[1]+4}  fontSize={12} fill="#7C3AED" fontWeight="bold" fontFamily="DM Sans">{labelD}</text>

      {/* Branch probability fractions */}
      <SvgFrac num={pA[0]}     den={pA[1]}     cx={mRA[0]-4}  cy={mRA[1]-14} />
      <SvgFrac num={pBarA[0]}  den={pBarA[1]}  cx={mRBA[0]-4} cy={mRBA[1]+6} />
      <SvgFrac num={pCA[0]}    den={pCA[1]}    cx={mAC[0]+4}  cy={mAC[1]-13} />
      <SvgFrac num={pDA[0]}    den={pDA[1]}    cx={mAD[0]+4}  cy={mAD[1]+5} />
      <SvgFrac num={pCBarA[0]} den={pCBarA[1]} cx={mBAC[0]+4} cy={mBAC[1]-13} />
      <SvgFrac num={pDBarA[0]} den={pDBarA[1]} cx={mBAD[0]+4} cy={mBAD[1]+5} />
    </svg>
  );
}

// Probability double-entry table (HTML)
// spec: { rows, cols, data:[[]], hi:[{r,c}] }
function ProbaTable({ spec }) {
  const { rows, cols, data, hi = [] } = spec;
  const isHi = (r, c) => hi.some(h => h.r === r && h.c === c);
  const isTotal = (r, c) => r === rows.length - 1 || c === cols.length - 1;

  const cs = (r, c, head) => ({
    border: "1px solid #CBD5E1",
    padding: "5px 7px",
    fontSize: 11,
    textAlign: "center",
    background: isHi(r, c) ? "#FEF3C7" : head ? "#F1F5F9" : isTotal(r, c) ? "#F8FAFC" : "#fff",
    fontWeight: isHi(r, c) || head || isTotal(r, c) ? 700 : 500,
    color: isHi(r, c) ? "#92400E" : "#1E293B",
    whiteSpace: "nowrap",
  });

  return (
    <div style={{ overflowX: "auto", margin: "6px 0 2px" }}>
      <table style={{ borderCollapse: "collapse", width: "100%", tableLayout: "auto" }}>
        <thead>
          <tr>
            <td style={{ ...cs(-1,-1,true), background:"#E2E8F0" }}></td>
            {cols.map((c, i) => <td key={i} style={cs(-1, i, true)}>{c}</td>)}
          </tr>
        </thead>
        <tbody>
          {rows.map((row, r) => (
            <tr key={r}>
              <td style={cs(r, -1, true)}>{row}</td>
              {data[r].map((val, c) => <td key={c} style={cs(r, c, false)}>{val}</td>)}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ── Question database ─────────────────────────────────────────────────────────
const r = String.raw;

// Probability table specs
const T_LUNETTES  = { rows:["Fille","Garçon","Total"], cols:["Lunettes","Sans lun.","Total"], data:[[3,7,10],[5,5,10],[8,12,20]] };
const T_LUNETTES2 = { rows:["Fille","Garçon","Total"], cols:["Lunettes","Sans lun.","Total"], data:[[6,4,10],[2,8,10],[8,12,20]] };
const T_CINEMA    = { rows:["Cinéma","Pas cinéma","Total"], cols:["Lit","Pas lit","Total"], data:[[4,6,10],[6,4,10],[10,10,20]] };
const T_CONTROLE  = { rows:["Révisé","Non révisé","Total"], cols:["Réussi","Échoué","Total"], data:[[8,4,12],[2,6,8],[10,10,20]] };
const T_TRANSPORT = { rows:["À vélo","Pas à vélo","Total"], cols:["À l'heure","En retard","Total"], data:[[6,4,10],[4,6,10],[10,10,20]] };

// Probability tree specs (pA=[num,den], pCA=P(C|A), etc.)
const TREE_A = { pA:[1,2], pCA:[2,3], pDA:[1,3], pCBarA:[1,3], pDBarA:[2,3] };
const TREE_B = { pA:[2,5], pCA:[1,2], pDA:[1,2], pCBarA:[1,3], pDBarA:[2,3] };
const TREE_E = { pA:[1,2], pCA:[3,4], pDA:[1,4], pCBarA:[1,4], pDBarA:[3,4] };
// Arbres avec probabilités décimales (branches faciles sans calculatrice)
// Représentation décimale: pX = [numérateur×10, 10] → 0.3 = [3,10]
