// ── NumPad — for multiplication tables ────────────────────────────────────────
function NumPad({ value, onChange, onValidate, state, correctAnswer }) {
  // state: "idle" | "correct" | "wrong"
  // Layout: 7 8 9 / 4 5 6 / 1 2 3 / ± 0 ⌫ / OK (full width)

  const press = (k) => {
    if (state !== "idle") return;
    if (k === "⌫") { onChange(v => v.slice(0,-1)); return; }
    if (k === "OK") { if(value.length>0) onValidate(value); return; }
    if (k === "±") {
      onChange(v => {
        if (!v || v === "-") return v;
        return v.startsWith("-") ? v.slice(1) : "-" + v;
      });
      return;
    }
    // max 3 chars excluding leading minus
    if (value.replace("-","").length >= 3) return;
    onChange(v => v + k);
  };

  const dispBg = state==="correct" ? "#ECFDF5" : state==="wrong" ? "#FEF2F2" : "#F8FAFC";
  const dispBd = state==="correct" ? "#10B981" : state==="wrong" ? "#EF4444" : "#CBD5E1";
  const dispTx = state==="correct" ? "#065F46" : state==="wrong" ? "#991B1B" : "#1E293B";

  const digitKeys = ["7","8","9","4","5","6","1","2","3","±","0","⌫"];
  const disabled = state !== "idle";

  return (
    <div style={{display:"flex",flexDirection:"column",gap:8,flexShrink:0}}>
      {/* Display */}
      <div style={{background:dispBg,border:`2.5px solid ${dispBd}`,borderRadius:14,
        padding:"10px 16px",textAlign:"center",minHeight:52,display:"flex",
        alignItems:"center",justifyContent:"center",gap:10}}>
        {state==="correct" && <span style={{fontSize:18}}>✅</span>}
        {state==="wrong"   && <span style={{fontSize:18}}>❌</span>}
        <span style={{fontFamily:"'Nunito',sans-serif",fontSize:28,fontWeight:900,
          color:dispTx,letterSpacing:2}}>
          {state==="wrong" ? correctAnswer : (value || "—")}
        </span>
      </div>

      {/* Keys grid 3×4 */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:7}}>
        {digitKeys.map(k => {
          const isDel = k==="⌫";
          const isSign = k==="±";
          return (
            <button key={k} onClick={()=>press(k)} disabled={disabled}
              style={{
                height:50, borderRadius:12, border:"none",
                fontSize: isDel ? 18 : isSign ? 20 : 22,
                fontWeight: 800,
                fontFamily: "'Nunito',sans-serif",
                cursor: disabled ? "default" : "pointer",
                background: isDel ? "#FEF2F2" : isSign ? "#F1F5F9" : "#fff",
                color: isDel ? "#EF4444" : isSign ? "#475569" : "#1E293B",
                boxShadow: disabled ? "none" : "0 2px 8px rgba(0,0,0,.08)",
                transition:"all .12s ease",
                opacity: disabled ? 0.45 : 1,
              }}>
              {k}
            </button>
          );
        })}
      </div>

      {/* OK full width */}
      <button onClick={()=>press("OK")} disabled={disabled}
        style={{
          height:50, borderRadius:12, border:"none",
          fontSize:14, fontWeight:800,
          fontFamily:"'DM Sans',sans-serif",
          cursor: disabled ? "default" : "pointer",
          background: disabled ? "#E2E8F0" : "linear-gradient(135deg,#10B981,#059669)",
          color: disabled ? "#94A3B8" : "#fff",
          boxShadow: disabled ? "none" : "0 4px 14px rgba(16,185,129,.35)",
          transition:"all .12s ease",
        }}>
        OK ✓
      </button>
    </div>
  );
}

// ── EqPad — student builds full S={...} notation ─────────────────────────────
function EqPad({ value, onChange, onValidate, state, correctAnswer }) {
  const MAX = 14; // enough for {-1;0;1}
  const press = (k) => {
    if (state !== "idle") return;
    if (k === "⌫") { onChange(v => v.slice(0,-1)); return; }
    if (k === "OK") { if(value.length>0) onValidate(value); return; }
    if (value.length >= MAX) return;
    if (k === "±") {
      // toggle sign of last number segment after last { or ;
      onChange(v => {
        const sep = Math.max(v.lastIndexOf("{"), v.lastIndexOf(";"));
        const before = sep >= 0 ? v.slice(0, sep + 1) : "";
        const after  = sep >= 0 ? v.slice(sep + 1)    : v;
        if (!after.match(/\d/)) return v;
        const toggled = after.startsWith("-") ? after.slice(1) : "-" + after;
        return before + toggled;
      });
      return;
    }
    onChange(v => v + k);
  };

  const dispBg = state==="correct"?"#ECFDF5":state==="wrong"?"#FEF2F2":"#F8FAFC";
  const dispBd = state==="correct"?"#10B981":state==="wrong"?"#EF4444":"#CBD5E1";
  const dispTx = state==="correct"?"#065F46":state==="wrong"?"#991B1B":"#1E293B";
  const displayVal = state==="wrong" ? `S = ${correctAnswer}` : value ? `S = ${value}` : "S = ?";

  // Rows: special symbols first, then digits
  const rows = [
    [{k:"{",bg:"#EFF6FF",tc:"#1D4ED8"}, {k:";",bg:"#F1F5F9",tc:"#475569"}, {k:"}",bg:"#EFF6FF",tc:"#1D4ED8"}],
    [{k:"7"},{k:"8"},{k:"9"}],
    [{k:"4"},{k:"5"},{k:"6"}],
    [{k:"1"},{k:"2"},{k:"3"}],
    [{k:"±",bg:"#F1F5F9",tc:"#475569"},{k:"0"},{k:"⌫",bg:"#FEF2F2",tc:"#EF4444"}],
  ];

  return (
    <div style={{display:"flex",flexDirection:"column",gap:6,flexShrink:0}}>
      {/* Display */}
      <div style={{background:dispBg,border:`2.5px solid ${dispBd}`,borderRadius:12,
        padding:"8px 12px",minHeight:44,display:"flex",
        alignItems:"center",justifyContent:"center",gap:8,overflow:"hidden"}}>
        {state==="correct"&&<span style={{fontSize:15,flexShrink:0}}>✅</span>}
        {state==="wrong"  &&<span style={{fontSize:15,flexShrink:0}}>❌</span>}
        <span style={{fontFamily:"'Nunito',sans-serif",
          fontSize: value.length > 10 ? 14 : 20,
          fontWeight:900, color:dispTx, letterSpacing:.5,
          wordBreak:"break-all", textAlign:"center"}}>
          {displayVal}
        </span>
      </div>
      {/* Keys */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:5}}>
        {rows.flat().map((btn,i)=>(
          <button key={i} onClick={()=>press(btn.k)} disabled={state!=="idle"}
            style={{
              height:40, borderRadius:10, border:"none",
              fontSize: btn.k==="±"||btn.k==="⌫"?15:btn.k===";"?17:btn.k==="{"||btn.k==="}"?20:19,
              fontWeight:800, fontFamily:"'Nunito',sans-serif",
              cursor:state!=="idle"?"default":"pointer",
              background:btn.bg||(state!=="idle"?"#F1F5F9":"#fff"),
              color:btn.tc||"#1E293B",
              boxShadow:state!=="idle"?"none":"0 2px 6px rgba(0,0,0,.07)",
              opacity:state!=="idle"?0.45:1, transition:"all .1s",
            }}>{btn.k}</button>
        ))}
      </div>
      <button onClick={()=>state==="idle"&&value.length>0&&onValidate(value)}
        disabled={state!=="idle"}
        style={{padding:"11px",border:"none",borderRadius:11,
          background:state!=="idle"?"#E2E8F0":"linear-gradient(135deg,#10B981,#059669)",
          color:state!=="idle"?"#94A3B8":"#fff",fontFamily:"'Nunito',sans-serif",
          fontSize:14,fontWeight:800,cursor:state!=="idle"?"default":"pointer",
          boxShadow:state!=="idle"?"none":"0 4px 12px rgba(16,185,129,.35)"}}>
        OK ✓
      </button>
    </div>
  );
}
// Builds strings like ]3;+∞[  [-3;+∞[  ]-∞;-2]  ]-∞;-1[∪]1;+∞[
function SolPad({ value, onChange, onValidate, state, correctAnswer }) {
  const MAX = 24;
  const press = (k) => {
    if (state !== "idle") return;
    if (k === "⌫") { onChange(v => v.slice(0, -1)); return; }
    if (k === "OK") { if (value.length > 0) onValidate(value); return; }
    if (value.length >= MAX) return;
    const insert = k === "-∞" ? "−∞" : k === "±" ? "-" : k;
    onChange(v => v + insert);
  };

  const dispBg = state==="correct"?"#ECFDF5":state==="wrong"?"#FEF2F2":"#F8FAFC";
  const dispBd = state==="correct"?"#10B981":state==="wrong"?"#EF4444":"#CBD5E1";
  const dispTx = state==="correct"?"#065F46":state==="wrong"?"#991B1B":"#1E293B";

  // Grid 3 cols — 7 rows + OK
  const rows = [
    [{k:"]",bg:"#EFF6FF",tc:"#1D4ED8"}, {k:"[",bg:"#EFF6FF",tc:"#1D4ED8"}, {k:";",bg:"#F1F5F9",tc:"#475569"}],
    [{k:"-∞",bg:"#FEF3C7",tc:"#92400E"}, {k:"+∞",bg:"#FEF3C7",tc:"#92400E"}, {k:"∪",bg:"#F3E8FF",tc:"#7C3AED"}],
    [{k:"7"},{k:"8"},{k:"9"}],
    [{k:"4"},{k:"5"},{k:"6"}],
    [{k:"1"},{k:"2"},{k:"3"}],
    [{k:"±",bg:"#F1F5F9",tc:"#475569"},{k:"0"},{k:"⌫",bg:"#FEF2F2",tc:"#EF4444"}],
  ];

  const disabled = state !== "idle";

  return (
    <div style={{display:"flex",flexDirection:"column",gap:6,flexShrink:0}}>
      {/* Display — scrollable for long union sets */}
      <div style={{background:dispBg,border:`2.5px solid ${dispBd}`,borderRadius:12,
        padding:"7px 10px",minHeight:42,display:"flex",
        alignItems:"center",justifyContent:"center",gap:8,overflow:"hidden"}}>
        {state==="correct"&&<span style={{fontSize:15,flexShrink:0}}>✅</span>}
        {state==="wrong"  &&<span style={{fontSize:15,flexShrink:0}}>❌</span>}
        <span style={{fontFamily:"'Nunito',sans-serif",
          fontSize: value.length > 14 ? 13 : 17,
          fontWeight:900,color:dispTx,letterSpacing:.5,
          wordBreak:"break-all",textAlign:"center"}}>
          {state==="wrong"? correctAnswer : (value||"—")}
        </span>
      </div>

      {/* Keys */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:5}}>
        {rows.flat().map((btn,i) => (
          <button key={i} onClick={()=>press(btn.k)} disabled={disabled}
            style={{
              height:40, borderRadius:10, border:"none",
              fontSize: ["-∞","+∞"].includes(btn.k)?11:btn.k==="⌫"?15:btn.k===";"||btn.k==="∪"?16:17,
              fontWeight:800, fontFamily:"'Nunito',sans-serif",
              cursor:disabled?"default":"pointer",
              background:btn.bg||(disabled?"#F1F5F9":"#fff"),
              color:btn.tc||"#1E293B",
              boxShadow:disabled?"none":"0 2px 6px rgba(0,0,0,.07)",
              opacity:disabled?0.45:1, transition:"all .1s",
            }}>
            {btn.k}
          </button>
        ))}
      </div>
      {/* OK full width */}
      <button onClick={()=>!disabled&&value.length>0&&onValidate(value)} disabled={disabled}
        style={{padding:"11px",border:"none",borderRadius:11,
          background:disabled?"#E2E8F0":"linear-gradient(135deg,#10B981,#059669)",
          color:disabled?"#94A3B8":"#fff",fontFamily:"'Nunito',sans-serif",
          fontSize:14,fontWeight:800,cursor:disabled?"default":"pointer",
          boxShadow:disabled?"none":"0 4px 12px rgba(16,185,129,.35)"}}>
        OK ✓
      </button>
    </div>
  );
}

// ── EXPRPAD — expression algébrique (x², x, chiffres, +, −) ───────────────────
function ExprPad({ correct, altAnswers, partialAnswers, extraBtn, extraBtns, onValidate, state }) {
  const [val, setVal] = React.useState('');
  const disabled = state === 'correct' || state === 'wrong'; // partial permet de continuer

  const toLatex = s => s
    .replace(/x²/g,'x^2')
    .replace(/²/g,'^2')
    .replace(/√7/g,'\\sqrt{7}')
    .replace(/√6/g,'\\sqrt{6}')
    .replace(/√5/g,'\\sqrt{5}')
    .replace(/√3/g,'\\sqrt{3}')
    .replace(/√2/g,'\\sqrt{2}');

  const ins = t => { if(!disabled) setVal(v => v + t); };
  const del = () => { if(!disabled) setVal(v => [...v].slice(0,-1).join('')); };

  // Normalise une expression factorisée : retire les espaces,
  // puis trie les facteurs parenthésés pour accepter (A)(B) = (B)(A)
  const normFactor = s => {
    const clean = s.replace(/\s/g,'').toLowerCase();
    // Découpe en facteurs parenthésés ex: "(x+2)(x+3)" → ["x+2","x+3"]
    const parts = [];
    let depth=0, cur='', hasParens=false;
    for(let ch of clean){
      if(ch==='('){depth++;if(depth===1){hasParens=true;continue;}}
      else if(ch===')'){depth--;if(depth===0){parts.push(cur);cur='';continue;}}
      if(depth>0) cur+=ch; else if(ch!=='(') cur+=ch; // prefixes like "3" or "-"
    }
    if(!hasParens) return clean; // pas de parenthèses → comparaison simple
    return [...parts].sort().join('|');
  };

  const submit = () => {
    if(!val || disabled) return;
    const normalized = normFactor(val);
    
    // Check if it's a partial answer first (for "C'est bon mais tu peux encore simplifier" feedback)
    if(partialAnswers && partialAnswers.length > 0) {
      const isPartial = partialAnswers.some(ans => normFactor(ans) === normalized);
      if(isPartial) {
        onValidate('partial', val);
        return;
      }
    }
    
    // Check main correct answer
    const isMainCorrect = normFactor(correct) === normalized;
    if(isMainCorrect) {
      onValidate('correct', val);
      return;
    }
    
    // Check alternative answers
    if(altAnswers && altAnswers.length > 0) {
      const isAltCorrect = altAnswers.some(ans => normFactor(ans) === normalized);
      if(isAltCorrect) {
        onValidate('correct', val);
        return;
      }
    }
    
    onValidate('wrong', val);
  };

  const dispBg = state==='correct'?'#ECFDF5':state==='wrong'?'#FEF2F2':state==='partial'?'#FEF9C3':'#F8FAFC';
  const dispBd = state==='correct'?'#10B981':state==='wrong'?'#EF4444':state==='partial'?'#F59E0B':'#CBD5E1';
  const dispClr = state==='correct'?'#065F46':state==='wrong'?'#991B1B':state==='partial'?'#92400E':'#1E293B';

  // Reset val when entering partial state to allow re-typing
  React.useEffect(() => {
    if(state === 'partial') {
      setVal('');
    }
  }, [state]);

  const B = ({label, tex, bg, color, flex=1, onP}) => (
    <button onClick={onP||(() => ins(label))} disabled={disabled}
      style={{flex,padding:"11px 4px",borderRadius:10,border:"none",
        background:bg||"#F1F5F9",color:color||"#1E293B",
        fontSize:15,fontWeight:700,cursor:disabled?"default":"pointer",
        opacity:disabled?.55:1,fontFamily:"'Nunito',sans-serif",minWidth:0}}>
      {tex ? <M tex={tex}/> : label}
    </button>
  );

  // Combine extraBtn (legacy) and extraBtns (array)
  const allExtra = [...(extraBtns||[]), ...(extraBtn?[extraBtn]:[])];
  // Determine which algebraic buttons to show (avoid duplicates)
  const hasX2inExtra = allExtra.includes("x²");
  const hasXinExtra  = allExtra.includes("x");

  return (
    <div style={{display:"flex",flexDirection:"column",gap:7,flexShrink:0}}>
      <div style={{background:dispBg,border:`2.5px solid ${dispBd}`,borderRadius:14,
        padding:"10px 16px",textAlign:"center",minHeight:52,display:"flex",
        alignItems:"center",justifyContent:"center"}}>
        <span style={{fontFamily:"'Nunito',sans-serif",fontSize:20,fontWeight:900,color:dispClr}}>
          {val ? <M tex={toLatex(val)}/> : <span style={{color:"#CBD5E1",fontSize:24}}>—</span>}
        </span>
      </div>

      <div style={{display:"flex",flexDirection:"column",gap:5}}>
        {/* Row 1 — algebraic special keys */}
        <div style={{display:"flex",gap:5}}>
          {/* x² — violet, sauf si déjà dans extraBtns */}
          {!hasX2inExtra && <B label="x²" tex="x^2" bg="#7C3AED" color="#fff"/>}
          {/* x — violet */}
          {!hasXinExtra  && <B label="x"  tex="x"   bg="#7C3AED" color="#fff"/>}
          {/* Extra buttons (radicaux, etc.) — teal */}
          {allExtra.filter(b=>b!=="x²"&&b!=="x").map((btn,i) => (
            <B key={i} label={btn} tex={toLatex(btn)} bg="#0F766E" color="#fff"/>
          ))}
          {/* x² / x in extra — violet */}
          {hasX2inExtra && <B label="x²" tex="x^2" bg="#7C3AED" color="#fff"/>}
          {hasXinExtra  && <B label="x"  tex="x"   bg="#7C3AED" color="#fff"/>}
          {/* ² exposant seul */}
          <B label="²" tex="^2" bg="#5B21B6" color="#fff" onP={()=>ins('²')}/>
          {/* Parenthèses */}
          <B label="(" tex="(" bg="#475569" color="#fff" onP={()=>ins('(')}/>
          <B label=")" tex=")" bg="#475569" color="#fff" onP={()=>ins(')')}/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="7"/><B label="8"/><B label="9"/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="4"/><B label="5"/><B label="6"/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="1"/><B label="2"/><B label="3"/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="+" bg="#EDE9FE" color="#5B21B6"/>
          <B label="0"/>
          <B label="−" bg="#EDE9FE" color="#5B21B6" onP={()=>ins('-')}/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="⌫" bg="#FEE2E2" color="#EF4444" onP={del}/>
          <button onClick={submit} disabled={disabled||!val}
            style={{flex:2,padding:"13px",borderRadius:10,border:"none",
              background:"#10B981",color:"#fff",fontSize:15,fontWeight:800,
              cursor:(disabled||!val)?"default":"pointer",
              opacity:(disabled||!val)?.5:1,
              boxShadow:(disabled||!val)?"none":"0 4px 12px rgba(16,185,129,.35)"}}>
            OK ✓
          </button>
        </div>
      </div>
    </div>
  );
}

// ── FractionPad — Pour saisir des fractions (numérateur/dénominateur) ─────────
function FractionPad({ correct, altAnswers, partialAnswers, onValidate, state }) {
  const [num, setNum] = React.useState('');   // numérateur
  const [denom, setDenom] = React.useState(''); // dénominateur
  const [focus, setFocus] = React.useState('num'); // 'num' ou 'denom'
  const disabled = state === 'correct' || state === 'wrong';

  const toLatex = s => s
    .replace(/x²/g,'x^2')
    .replace(/²/g,'^2');

  const ins = t => {
    if(disabled) return;
    if(focus === 'num') setNum(v => v + t);
    else setDenom(v => v + t);
  };
  
  const del = () => {
    if(disabled) return;
    if(focus === 'num') setNum(v => [...v].slice(0,-1).join(''));
    else setDenom(v => [...v].slice(0,-1).join(''));
  };

  // Normalisation pour comparaison
  const normFactor = s => {
    const clean = s.replace(/\s/g,'').toLowerCase();
    const parts = [];
    let depth=0, cur='', hasParens=false;
    for(let ch of clean){
      if(ch==='('){depth++;if(depth===1){hasParens=true;continue;}}
      else if(ch===')'){depth--;if(depth===0){parts.push(cur);cur='';continue;}}
      if(depth>0) cur+=ch; else if(ch!=='(') cur+=ch;
    }
    if(!hasParens) return clean;
    return [...parts].sort().join('|');
  };

  const submit = () => {
    if(!num || !denom || disabled) return;
    const userAnswer = `(${num})/(${denom})`;
    const normalized = normFactor(userAnswer);
    
    // Check partial answers first
    if(partialAnswers && partialAnswers.length > 0) {
      const isPartial = partialAnswers.some(ans => normFactor(ans) === normalized);
      if(isPartial) {
        onValidate('partial', userAnswer);
        return;
      }
    }
    
    // Check main answer
    const isMainCorrect = normFactor(correct) === normalized;
    if(isMainCorrect) {
      onValidate('correct', userAnswer);
      return;
    }
    
    // Check alt answers
    if(altAnswers && altAnswers.length > 0) {
      const isAltCorrect = altAnswers.some(ans => normFactor(ans) === normalized);
      if(isAltCorrect) {
        onValidate('correct', userAnswer);
        return;
      }
    }
    
    onValidate('wrong', userAnswer);
  };

  const dispBg = state==='correct'?'#ECFDF5':state==='wrong'?'#FEF2F2':state==='partial'?'#FEF9C3':'#F8FAFC';
  const dispBd = state==='correct'?'#10B981':state==='wrong'?'#EF4444':state==='partial'?'#F59E0B':'#CBD5E1';
  const dispClr = state==='correct'?'#065F46':state==='wrong'?'#991B1B':state==='partial'?'#92400E':'#1E293B';

  // Reset on partial
  React.useEffect(() => {
    if(state === 'partial') {
      setNum('');
      setDenom('');
    }
  }, [state]);

  const B = ({label, tex, bg, color, flex=1, onP}) => (
    <button onClick={onP||(() => ins(label))} disabled={disabled}
      style={{flex,padding:"11px 4px",borderRadius:10,border:"none",
        background:bg||"#F1F5F9",color:color||"#1E293B",
        fontSize:15,fontWeight:700,cursor:disabled?"default":"pointer",
        opacity:disabled?.55:1,fontFamily:"'Nunito',sans-serif",minWidth:0}}>
      {tex ? <M tex={tex}/> : label}
    </button>
  );

  return (
    <div style={{display:"flex",flexDirection:"column",gap:7,flexShrink:0}}>
      {/* Fraction display */}
      <div style={{background:dispBg,border:`2.5px solid ${dispBd}`,borderRadius:14,
        padding:"12px 16px",display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
        {/* Numérateur */}
        <div onClick={()=>!disabled&&setFocus('num')} style={{
          width:"100%",textAlign:"center",padding:"6px",borderRadius:8,
          background:focus==='num'&&state==='idle'?'rgba(124,58,237,0.1)':'transparent',
          border:`2px ${focus==='num'&&state==='idle'?'solid':'dashed'} ${focus==='num'&&state==='idle'?'#7C3AED':'#CBD5E1'}`,
          cursor:disabled?"default":"pointer",minHeight:40,display:"flex",alignItems:"center",justifyContent:"center"
        }}>
          <span style={{fontFamily:"'Nunito',sans-serif",fontSize:18,fontWeight:900,color:dispClr}}>
            {num ? <M tex={toLatex(num)}/> : <span style={{color:"#CBD5E1",fontSize:14}}>Numérateur</span>}
          </span>
        </div>
        
        {/* Barre de fraction */}
        <div style={{width:"100%",height:3,background:dispBd,borderRadius:2}}/>
        
        {/* Dénominateur */}
        <div onClick={()=>!disabled&&setFocus('denom')} style={{
          width:"100%",textAlign:"center",padding:"6px",borderRadius:8,
          background:focus==='denom'&&state==='idle'?'rgba(124,58,237,0.1)':'transparent',
          border:`2px ${focus==='denom'&&state==='idle'?'solid':'dashed'} ${focus==='denom'&&state==='idle'?'#7C3AED':'#CBD5E1'}`,
          cursor:disabled?"default":"pointer",minHeight:40,display:"flex",alignItems:"center",justifyContent:"center"
        }}>
          <span style={{fontFamily:"'Nunito',sans-serif",fontSize:18,fontWeight:900,color:dispClr}}>
            {denom ? <M tex={toLatex(denom)}/> : <span style={{color:"#CBD5E1",fontSize:14}}>Dénominateur</span>}
          </span>
        </div>
      </div>

      <div style={{display:"flex",flexDirection:"column",gap:5}}>
        {/* Row 1 — algebraic keys */}
        <div style={{display:"flex",gap:5}}>
          <B label="x²" tex="x^2" bg="#7C3AED" color="#fff"/>
          <B label="x" tex="x" bg="#7C3AED" color="#fff"/>
          <B label="²" tex="^2" bg="#5B21B6" color="#fff" onP={()=>ins('²')}/>
          <B label="(" tex="(" bg="#475569" color="#fff" onP={()=>ins('(')}/>
          <B label=")" tex=")" bg="#475569" color="#fff" onP={()=>ins(')')}/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="7"/><B label="8"/><B label="9"/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="4"/><B label="5"/><B label="6"/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="1"/><B label="2"/><B label="3"/>
        </div>
        <div style={{display:"flex",gap:5}}>
          <B label="+" bg="#EDE9FE" color="#5B21B6"/>
          <B label="0"/>
          <B label="−" bg="#EDE9FE" color="#5B21B6" onP={()=>ins('-')}/>
        </div>
        
        {/* Navigation entre zones + validate */}
        <div style={{display:"flex",gap:5}}>
          <button onClick={()=>!disabled&&setFocus(f=>f==='num'?'denom':'num')}
            disabled={disabled}
            style={{flex:1,padding:"11px",borderRadius:10,border:"2px solid #7C3AED",
              background:"#fff",color:"#7C3AED",fontSize:13,fontWeight:700,
              cursor:disabled?"default":"pointer",opacity:disabled?.5:1}}>
            {focus==='num'?'↓ Dénominateur':'↑ Numérateur'}
          </button>
          <B label="⌫" bg="#FEE2E2" color="#EF4444" onP={del}/>
        </div>
        
        <button onClick={submit} disabled={disabled||!num||!denom}
          style={{width:"100%",padding:"13px",borderRadius:10,border:"none",
            background:"#10B981",color:"#fff",fontSize:15,fontWeight:800,
            cursor:(disabled||!num||!denom)?"default":"pointer",
            opacity:(disabled||!num||!denom)?.5:1,
            boxShadow:(disabled||!num||!denom)?"none":"0 4px 12px rgba(16,185,129,.35)"}}>
          OK ✓
        </button>
      </div>
    </div>
  );
}
