// ── Spaced Repetition System ──────────────────────────────────────────────────
// Each question tracked by index: {lastSeen, interval, ease}
// interval in days: 1 → 3 → 7 → 14 → 30
const SRS_INTERVALS = [1, 3, 7, 14, 30];
function nextInterval(currentInterval, correct) {
  if(!correct) return 1; // Failed → reset to 1 day
  const idx = SRS_INTERVALS.indexOf(currentInterval);
  return SRS_INTERVALS[Math.min(idx+1, SRS_INTERVALS.length-1)];
}
function isDue(entry) {
  if(!entry || !entry.lastSeen) return true;
  const daysSince = (Date.now() - entry.lastSeen) / 86400000;
  return daysSince >= (entry.interval||1);
}

// ── Build SRS queue for a subcat: returns question indices due for review ─────
function getSRSQueue(allQ, srsData) {
  const due = [];
  const fresh = [];
  allQ.forEach((q, i) => {
    const entry = srsData[i];
    if(!entry) fresh.push(i);
    else if(isDue(entry)) due.push(i);
  });
  // Due first, then fresh, max 10
  return [...due, ...fresh].slice(0, 10);
}

// ── Generate adaptive weekly program ─────────────────────────────────────────
async function generateWeeklyProgram(profile, allProg, diagResults) {
  const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
  const today = new Date().getDay(); // 0=Sun, 1=Mon...
  const weekdays = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];

  // ── Score chaque sous-thème ────────────────────────────────────────────────
  // Priorité : allProg (quiz faits dans l'app) > diagResults (diagnostic initial)
  // Score sur 0-100 : 0=non testé, bas=faible, haut=maîtrisé, 999=3 étoiles
  const subScores = [];
  Object.entries(curr.cats).forEach(([catId, subs]) => {
    // Score catégorie-wide du diagnostic (fallback si allProg vide)
    const diag = diagResults?.[catId];
    const diagPct = diag && diag.total > 0 ? Math.round(diag.correct / diag.total * 100) : null;

    subs.forEach(subId => {
      const p = allProg[`${catId}:${subId}`] || {pc:0,pt:0,stars:0};
      const rate = p.pt > 0 ? Math.round(p.pc / p.pt * 100) : null;
      let score;
      let source;
      if (p.stars >= 3) {
        score = 999;
        source = "mastered";
      } else if (rate !== null) {
        // L'élève a déjà fait des quiz sur ce sous-thème : on utilise cette donnée
        score = rate;
        source = "practice";
      } else if (diagPct !== null) {
        // Pas de pratique mais diagnostic disponible : on utilise le score catégorie
        // Attention : tous les sous-thèmes de la catégorie auront le même score.
        // Pour différencier, on ajoute un tout petit bruit basé sur le subId (ordre stable).
        score = diagPct;
        source = "diagnostic";
      } else {
        // Rien du tout : score 0 = "non testé, priorité de découverte"
        score = 0;
        source = "unknown";
      }
      subScores.push({ catId, subId, score, stars: p.stars||0, rate, source });
    });
  });

  // Tri : non testés en premier, puis scores les plus faibles
  // Les "mastered" (999) sont exclus du travail prioritaire.
  const needsWork = subScores
    .filter(s => s.score < 999)
    .sort((a,b) => {
      // Priorité 1 : score (plus bas = plus urgent)
      // Priorité 2 : "unknown" avant "diagnostic" avant "practice" à score égal
      if (a.score !== b.score) return a.score - b.score;
      const rank = { unknown: 0, diagnostic: 1, practice: 2, mastered: 3 };
      return rank[a.source] - rank[b.source];
    });
  const consolidated = subScores
    .filter(s => s.score >= 40 && s.score < 80 && s.source !== "unknown")
    .sort((a,b) => a.score - b.score);

  const days = [];
  const dayNames = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];

  // Plan de 5 jours : alternance renforcement (thèmes faibles) / consolidation (thèmes moyens)
  for (let d = 0; d < 5; d++) {
    const isReinforcement = d % 2 === 0; // Lun, Mer, Ven → renforcement
    let pick;
    if (isReinforcement) {
      pick = needsWork[Math.floor(d/2) % Math.max(needsWork.length, 1)];
    } else {
      pick = consolidated[Math.floor(d/2) % Math.max(consolidated.length, 1)] || needsWork[0];
    }
    if (!pick) continue;
    days.push({
      day: d,
      dayLabel: dayNames[d],
      catId: pick.catId,
      subId: pick.subId,
      type: isReinforcement ? 'renforcement' : 'consolidation',
      source: pick.source, // pour debug et éventuel affichage "basé sur ton diagnostic"
      done: false,
    });
  }

  const program = {
    days,
    weekStart: new Date().toDateString(),
    generated: Date.now(),
  };
  await saveProgram(program);
  return program;
}

// ── Error pattern analysis ────────────────────────────────────────────────────
function getErrorPatterns(allProg, curr) {
  const weak = [];
  Object.entries(curr.cats).forEach(([catId, subs]) => {
    subs.forEach(subId => {
      const p = allProg[`${catId}:${subId}`] || {pc:0,pt:0};
      if(p.pt >= 3) {
        const r = Math.round(p.pc/p.pt*100);
        if(r < 60) weak.push({ catId, subId, rate: r, errors: p.pt - p.pc });
      }
    });
  });
  return weak.sort((a,b)=>a.rate-b.rate).slice(0,3);
}

// ── DiagnosticScreen ──────────────────────────────────────────────────────────
function DiagnosticScreen({profile, onComplete}) {
  const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
  // Build diagnostic: 2 questions per category
  const diagQ = React.useMemo(() => {
    const qs = [];
    Object.entries(curr.cats).forEach(([catId, subs]) => {
      const sub = subs[0];
      const pool = (DB[catId] && DB[catId][sub]) ? DB[catId][sub] : [];
      const mcqPool = pool.filter(q => q.choices && !q.exprpad && !q.numpad && !q.gspec && !q.tspec && !q.trespec && !q.dgspec && !q.tvSpec && !q.tsSpec);
      if(mcqPool.length >= 2) {
        qs.push({...mcqPool[0], _catId:catId, _subId:sub});
        qs.push({...mcqPool[Math.floor(mcqPool.length/2)], _catId:catId, _subId:sub});
      } else if(mcqPool.length === 1) {
        qs.push({...mcqPool[0], _catId:catId, _subId:sub});
      }
    });
    return shuffle(qs).slice(0, 12);
  }, [profile.level]);

  const [idx, setIdx] = useState(0);
  const [selected, setSelected] = useState(null);
  const [shown, setShown] = useState(false);
  const [results, setResults] = useState({}); // catId → {correct, total}

  const q = diagQ[idx];
  const pct = Math.round((idx / diagQ.length) * 100);

  const pick = choice => {
    if(shown) return;
    setSelected(choice);
    setShown(true);
    const correct = choice === q.a;
    setResults(r => {
      const prev = r[q._catId] || {correct:0,total:0};
      return {...r, [q._catId]: {correct: prev.correct+(correct?1:0), total: prev.total+1}};
    });
  };

  const next = async () => {
    if(idx + 1 >= diagQ.length) {
      // Save diagnostic results
      const diagData = {date: Date.now(), results, level: profile.level};
      await saveDiag(diagData);
      onComplete(results);
    } else {
      setIdx(i=>i+1);
      setSelected(null);
      setShown(false);
    }
  };

  const getState = c => {
    if(!shown) return selected===c ? 'selected' : 'default';
    if(c === q?.a) return 'correct';
    if(c === selected) return 'wrong';
    return 'default';
  };

  const COLORS = {
    default:  {bg:'#fff',       border:'#E2E8F0', text:'#334155'},
    selected: {bg:'#EFF6FF',    border:'#3B82F6', text:'#1E3A8A'},
    correct:  {bg:'#ECFDF5',    border:'#10B981', text:'#065F46'},
    wrong:    {bg:'#FEF2F2',    border:'#EF4444', text:'#991B1B'},
  };

  if(!q) return null;

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      {/* Header */}
      <div style={{background:'linear-gradient(135deg,#7C3AED,#5B21B6)',
        padding:'16px 18px 20px',flexShrink:0}}>
        <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:12}}>
          <img src={SIGMA_IMG} alt="Sigma" style={{width:36,height:36,objectFit:'contain'}}/>
          <div>
            <div style={{color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:15}}>
              Diagnostic rapide
            </div>
            <div style={{color:'rgba(255,255,255,0.6)',fontSize:10}}>
              Sigma évalue ton niveau pour t'aider
            </div>
          </div>
        </div>
        {/* Progress */}
        <div style={{height:6,background:'rgba(255,255,255,0.15)',borderRadius:99}}>
          <div style={{height:'100%',width:`${pct}%`,background:'#fff',
            borderRadius:99,transition:'width .4s ease'}}/>
        </div>
        <div style={{display:'flex',justifyContent:'space-between',marginTop:4}}>
          <span style={{color:'rgba(255,255,255,0.5)',fontSize:9}}>Question {idx+1}/{diagQ.length}</span>
          <span style={{color:'rgba(255,255,255,0.5)',fontSize:9}}>{pct}%</span>
        </div>
      </div>

      {/* Body */}
      <div style={{flex:1,display:'flex',flexDirection:'column',padding:'16px',gap:10}}>
        {/* Category badge */}
        <div style={{display:'flex',alignItems:'center',gap:6}}>
          <span style={{fontSize:12}}>{getCatInfo(q._catId)?.emoji||'📚'}</span>
          <span style={{fontSize:10,color:'#64748B',fontWeight:600}}>
            {getCatInfo(q._catId)?.label||q._catId}
          </span>
        </div>

        {/* Question card */}
        <div style={{background:'#fff',borderRadius:16,padding:'16px',
          textAlign:'center',boxShadow:'0 2px 10px rgba(0,0,0,.06)'}}>
          <div style={{fontSize:16,fontWeight:700,color:'#1E293B'}}>
            <M tex={q.q}/>
          </div>
        </div>

        {/* Choices */}
        <div style={{display:'flex',flexDirection:'column',gap:8,flex:1}}>
          {q.choices && q.choices.map((c,i) => {
            const st = getState(c);
            const col = COLORS[st];
            return (
              <button key={i} onClick={()=>pick(c)}
                style={{padding:'12px 16px',borderRadius:13,
                  border:`2px solid ${col.border}`,background:col.bg,
                  color:col.text,cursor:shown?'default':'pointer',
                  fontSize:13,fontWeight:600,textAlign:'left',
                  transition:'all .15s'}}>
                <M tex={c}/>
              </button>
            );
          })}
        </div>

        {/* Next button */}
        {shown && (
          <button onClick={next} className="pop-in"
            style={{padding:'13px',borderRadius:14,border:'none',
              background:'linear-gradient(135deg,#7C3AED,#5B21B6)',
              color:'#fff',fontFamily:"'Nunito',sans-serif",
              fontSize:14,fontWeight:800,cursor:'pointer',
              boxShadow:'0 5px 16px rgba(124,58,237,.35)'}}>
            {idx+1 >= diagQ.length ? 'Voir mon bilan → 🎯' : 'Suivante →'}
          </button>
        )}
      </div>
    </div>
  );
}

// ── DiagnosticResultScreen ───────────────────────────────────────────────────
function DiagnosticResultScreen({profile, diagResults, onStart}) {
  const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
  const cats = CATS.filter(c => Object.keys(curr.cats).includes(c.id));
  const total = Object.values(diagResults).reduce((a,v)=>a+v.total,0);
  const correct = Object.values(diagResults).reduce((a,v)=>a+v.correct,0);
  const globalPct = total>0 ? Math.round(correct/total*100) : 0;

  const emotion = globalPct>=80?"love":globalPct>=60?"cool":globalPct>=40?"happy":"sad";
  const msg = globalPct>=80?"Excellent ! Sigma a tout noté 💪":
              globalPct>=60?"Bon niveau ! On va affiner ça 📊":
              globalPct>=40?"Quelques lacunes, Sigma va t'aider 🧡":
              "Pas de panique ! Sigma construit ton plan 🚀";

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',
      padding:'20px',background:'var(--am-bg-light)',gap:12}}>
      <div style={{display:'flex',flexDirection:'column',alignItems:'center',gap:4}}>
        <div className="sigma-float"><Sigma emotion={emotion} size={120}/></div>
        <div className="sigma-shadow" style={{width:'40%',marginTop:-2}}/>
      </div>
      <div style={{textAlign:'center'}}>
        <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:32,
          color:globalPct>=60?"#10B981":"#F59E0B"}}>{globalPct}%</div>
        <div style={{color:'#64748B',fontSize:12,marginTop:4}}>{msg}</div>
      </div>

      {/* Heatmap */}
      <div style={{background:'#fff',borderRadius:16,padding:'14px',
        boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
        <div style={{fontWeight:800,fontSize:12,color:'#1E293B',marginBottom:10}}>
          📊 Ta carte de compétences
        </div>
        <div style={{display:'flex',flexDirection:'column',gap:7}}>
          {cats.map(cat=>{
            const r = diagResults[cat.id];
            const pct = r ? Math.round(r.correct/r.total*100) : null;
            const color = pct===null?"#CBD5E1":pct>=80?"#10B981":pct>=60?"#F59E0B":"#EF4444";
            const label = pct===null?"Non testé":pct>=80?"✅ Maîtrisé":pct>=60?"⚡ À consolider":"🔴 À travailler";
            return (
              <div key={cat.id} style={{display:'flex',alignItems:'center',gap:8}}>
                <span style={{fontSize:14,width:22}}>{cat.emoji}</span>
                <div style={{flex:1}}>
                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}>
                    <span style={{fontSize:10,fontWeight:700,color:'#334155'}}>{cat.label}</span>
                    <span style={{fontSize:9,color,fontWeight:700}}>{label}</span>
                  </div>
                  <div style={{height:5,background:'#F1F5F9',borderRadius:99,overflow:'hidden'}}>
                    <div style={{height:'100%',width:`${pct||5}%`,background:color,
                      borderRadius:99,transition:'width 1s ease'}}/>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Message de personnalisation : visible si on a identifié des faiblesses */}
      {(() => {
        const weak = cats
          .filter(c => {
            const r = diagResults[c.id];
            if (!r || r.total === 0) return false;
            return Math.round(r.correct / r.total * 100) < 60;
          })
          .map(c => c.label);
        if (weak.length === 0) return null;
        return (
          <div style={{background:'#FEF3C7', borderRadius:12, padding:'10px 14px',
            border:'1px solid #FDE68A'}}>
            <div style={{fontSize:11, color:'#92400E', fontWeight:700, lineHeight:1.4}}>
              🎯 Sigma te proposera en priorité :{" "}
              <span style={{fontWeight:900}}>
                {weak.slice(0, 2).join(" et ")}
              </span>
            </div>
          </div>
        );
      })()}

      <button onClick={onStart}
        style={{padding:'14px',borderRadius:16,border:'none',
          background:'linear-gradient(135deg,#10B981,#047857)',
          color:'#fff',fontFamily:"'Nunito',sans-serif",
          fontSize:15,fontWeight:900,cursor:'pointer',
          boxShadow:'0 6px 20px rgba(16,185,129,.3)'}}>
        Voir mon programme 📅 →
      </button>
    </div>
  );
}

// ── WeeklyProgramScreen ────────────────────────────────────────────────────
function WeeklyProgramScreen({profile, program, allProg, onStartSession, onSkip}) {
  const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
  const dayLabels = ['Lun','Mar','Mer','Jeu','Ven'];
  const todayDay = new Date().getDay(); // 0=Sun...
  // Map: Mon=0,Tue=1...
  const todayIdx = todayDay === 0 ? 6 : todayDay - 1; // 0=Mon, 6=Sun

  const weakPats = getErrorPatterns(allProg, curr);

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      {/* Header */}
      <div style={{background:'linear-gradient(135deg,var(--am-bg-dark-1),var(--am-bg-dark-2))',
        padding:'16px 16px 18px',flexShrink:0}}>
        <div style={{display:'flex',alignItems:'center',gap:10}}>
          <img src={SIGMA_IMG} alt="" style={{width:36,height:36,objectFit:'contain'}}/>
          <div>
            <div style={{color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:16}}>
              Mon Programme
            </div>
            <div style={{color:'#64748B',fontSize:10}}>Semaine du {new Date().toLocaleDateString('fr-FR',{day:'numeric',month:'long'})}</div>
          </div>
        </div>
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'12px 12px 20px',display:'flex',flexDirection:'column',gap:10}}>

        {/* Today's session highlighted */}
        {program.days[todayIdx] && (
          <div>
            <div style={{fontSize:9,fontWeight:700,color:'#94A3B8',textTransform:'uppercase',letterSpacing:1,marginBottom:6}}>
              🌟 Aujourd'hui
            </div>
            <div style={{background:'linear-gradient(135deg,#7C3AED,#5B21B6)',
              borderRadius:16,padding:'14px',
              boxShadow:'0 6px 20px rgba(124,58,237,.25)'}}>
              <div style={{display:'flex',alignItems:'center',gap:10}}>
                <span style={{fontSize:24}}>{getCatInfo(program.days[todayIdx].catId)?.emoji||'📚'}</span>
                <div style={{flex:1}}>
                  <div style={{color:'rgba(255,255,255,0.6)',fontSize:9,fontWeight:700,textTransform:'uppercase'}}>
                    {program.days[todayIdx].type==='renforcement'?'🔧 Renforcement':'⚡ Consolidation'}
                  </div>
                  <div style={{color:'#fff',fontWeight:800,fontSize:13,fontFamily:"'Nunito',sans-serif"}}>
                    {getSubInfo(program.days[todayIdx].catId, program.days[todayIdx].subId)?.label||program.days[todayIdx].subId}
                  </div>
                  <div style={{color:'rgba(255,255,255,0.5)',fontSize:9,marginTop:1}}>
                    {getCatInfo(program.days[todayIdx].catId)?.label}
                  </div>
                </div>
                <button onClick={()=>onStartSession(program.days[todayIdx])}
                  style={{background:'rgba(255,255,255,0.2)',border:'none',borderRadius:10,
                    padding:'9px 14px',color:'#fff',fontWeight:800,fontSize:12,cursor:'pointer'}}>
                  C'est parti 🚀
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Full week plan */}
        <div>
          <div style={{fontSize:9,fontWeight:700,color:'#94A3B8',textTransform:'uppercase',letterSpacing:1,marginBottom:7}}>
            📅 La semaine
          </div>
          <div style={{background:'#fff',borderRadius:16,overflow:'hidden',
            boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
            {program.days.map((day,i)=>{
              const isToday = i === todayIdx;
              const cat = getCatInfo(day.catId);
              const isDone = day.done;
              const p = allProg[`${day.catId}:${day.subId}`] || {pc:0,pt:0};
              const r = p.pt>0 ? Math.round(p.pc/p.pt*100) : null;
              return (
                <div key={i} style={{display:'flex',alignItems:'center',gap:10,
                  padding:'11px 14px',
                  background:isToday?'#F5F3FF':'#fff',
                  borderBottom:i<program.days.length-1?'1px solid #F8FAFC':'none',
                  opacity:isDone?0.6:1}}>
                  <div style={{width:32,textAlign:'center'}}>
                    <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:11,
                      color:isToday?'#7C3AED':'#94A3B8'}}>{dayLabels[i]}</div>
                    {isToday&&<div style={{width:6,height:6,borderRadius:'50%',
                      background:'#7C3AED',margin:'2px auto'}}/>}
                  </div>
                  <span style={{fontSize:16}}>{isDone?'✅':cat?.emoji||'📚'}</span>
                  <div style={{flex:1}}>
                    <div style={{fontSize:11,fontWeight:700,color:'#334155'}}>
                      {getSubInfo(day.catId,day.subId)?.label||day.subId}
                    </div>
                    <div style={{fontSize:9,color:'#94A3B8'}}>
                      {day.type==='renforcement'?'🔧 Renforcement':'⚡ Consolidation'}
                      {r!==null&&` · ${r}% de réussite`}
                    </div>
                  </div>
                  {!isDone&&isToday&&<span style={{fontSize:10,color:'#7C3AED',fontWeight:700}}>Maintenant</span>}
                </div>
              );
            })}
          </div>
        </div>

        {/* Error patterns */}
        {weakPats.length>0&&(
          <div>
            <div style={{fontSize:9,fontWeight:700,color:'#94A3B8',textTransform:'uppercase',letterSpacing:1,marginBottom:7}}>
              ⚠️ Sigma a repéré tes pièges
            </div>
            <div style={{background:'#FEF9C3',borderRadius:14,padding:'12px 14px',
              border:'1.5px solid #FDE68A'}}>
              {weakPats.map((w,i)=>(
                <div key={i} style={{display:'flex',alignItems:'center',gap:8,
                  marginBottom:i<weakPats.length-1?8:0}}>
                  <span style={{fontSize:12}}>🎯</span>
                  <div style={{flex:1}}>
                    <div style={{fontSize:11,fontWeight:700,color:'#92400E'}}>
                      {getSubInfo(w.catId,w.subId)?.label||w.subId}
                    </div>
                    <div style={{fontSize:9,color:'#B45309'}}>
                      Taux de réussite : {w.rate}% · {w.errors} erreur{w.errors>1?'s':''} au total
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        <button onClick={onSkip}
          style={{padding:'10px',borderRadius:12,border:'1.5px solid #E2E8F0',
            background:'transparent',color:'#64748B',fontSize:11,fontWeight:600,cursor:'pointer'}}>
          Voir mon tableau de bord →
        </button>
      </div>
    </div>
  );
}


