// ── QR Code generator (pure JS, no lib needed) ───────────────────────────────
// Uses qrcode-generator pattern (matrix-based, supports up to ~200 chars)
// For larger payloads we show a compact stats summary only

function compactStats(profile, allProg, xp, badges) {
  const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
  const catStats = {};
  Object.entries(curr.cats).forEach(([catId, subs]) => {
    let stars = 0, pt = 0, pc = 0;
    subs.forEach(s => {
      const p = allProg[`${catId}:${s}`] || {pc:0,pt:0,stars:0};
      stars += p.stars||0;
      pt += p.pt||0;
      pc += p.pc||0;
    });
    catStats[catId] = { stars, rate: pt>0?Math.round(pc/pt*100):null };
  });
  return {
    n: profile.name,
    l: profile.level,
    s: profile.streak||0,
    x: xp,
    b: badges.length,
    c: catStats,
    t: new Date().toLocaleDateString('fr-FR'),
  };
}

// ── Teacher Snapshot (lien pour dashboard prof) ──────────────────────────────
// URL du dashboard prof. À ajuster si tu changes d'hébergement.
const DASHBOARD_URL = 'https://automaths-prof.vercel.app/';

async function teacherSnapshot(profile, allProg, xp) {
  const activeDays = await loadActiveDays();
  const recentDays = activeDays.slice(-14);

  const lastSeen = recentDays.length > 0
    ? recentDays[recentDays.length - 1] + 'T12:00:00Z'
    : new Date().toISOString();

  const progress = {};
  for (const [key, p] of Object.entries(allProg || {})) {
    if (p && p.pt > 0) {
      progress[key] = { pc: p.pc || 0, pt: p.pt || 0, stars: p.stars || 0 };
    }
  }

  return {
    v: 1,
    exportedAt: new Date().toISOString(),
    student: {
      name: profile.name || 'Anonyme',
      level: profile.level || 'seconde',
      lastSeen,
      streak: profile.streak || 0,
      totalXp: xp || 0,
    },
    progress,
    activeDays: recentDays,
  };
}

function buildTeacherLink(snapshot) {
  const json = JSON.stringify(snapshot);
  const b64 = btoa(unescape(encodeURIComponent(json)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
  return DASHBOARD_URL + '?d=' + b64;
}

// ── QR Display Screen ─────────────────────────────────────────────────────────
function QRExportScreen({profile, allProg, xp, badges, onBack}) {
  const data = compactStats(profile, allProg, xp, badges);
  const json = JSON.stringify(data);

  // Build visual QR via api.qrserver.com (gratuit, sans clé, stable).
  // Note : Google Charts QR API a été dépréciée en 2024, on utilise un fallback.
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=280x280&data=${encodeURIComponent(json)}&ecc=L&margin=10`;

  const CATS_MAP = {
    fonctions:'📈 Fonctions',pourcentages:'💹 %',numerique:'🔢 Numérique',
    litteral:'📐 Littéral',probabilites:'🎲 Probas',derivation:'∂ Dérivation',bac:'🏆 Bac'
  };
  const lvlInfo = getXpLevel(xp);

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      {/* Header */}
      <div style={{background:'linear-gradient(135deg,var(--am-bg-dark-1),var(--am-bg-dark-2))',
        padding:'14px 16px',flexShrink:0,display:'flex',alignItems:'center',gap:10}}>
        <button onClick={onBack} style={{background:'rgba(255,255,255,0.1)',border:'none',
          borderRadius:9,padding:'6px 11px',color:'#94A3B8',cursor:'pointer',fontSize:12,fontWeight:700}}>
          ← Retour
        </button>
        <div style={{flex:1,color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:16,textAlign:'center'}}>
          Mon code élève 📤
        </div>
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'16px',display:'flex',flexDirection:'column',gap:12}}>

        {/* QR Code */}
        <div style={{background:'#fff',borderRadius:18,padding:'20px',textAlign:'center',
          boxShadow:'0 4px 16px rgba(0,0,0,.08)'}}>
          <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:16,
            color:'#1E293B',marginBottom:4}}>{profile.name}</div>
          <div style={{color:'#64748B',fontSize:11,marginBottom:14}}>
            {lvlInfo.emoji} {lvlInfo.label} · ⚡ {xp} XP · 🔥 {profile.streak||0} jours
          </div>
          <img src={qrUrl} alt="QR Code"
            style={{width:220,height:220,borderRadius:12,border:'2px solid #F1F5F9'}}
            onError={e=>{
              // Si l'API tombe, on remplace l'image par un message lisible
              const parent = e.target.parentNode;
              const fallback = document.createElement('div');
              fallback.style.cssText = 'width:220px;height:220px;border-radius:12px;border:2px dashed #CBD5E1;background:#F8FAFC;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:16px;margin:0 auto;';
              fallback.innerHTML = '<div style="font-size:36px;margin-bottom:8px;">📱</div><div style="font-size:11px;color:#64748B;text-align:center;line-height:1.5;">QR temporairement indisponible.<br/>Ton code de sauvegarde est<br/>accessible via <strong>Sauvegarde 💾</strong></div>';
              e.target.style.display='none';
              parent.appendChild(fallback);
            }}/>
          <div style={{marginTop:12,fontSize:10,color:'#94A3B8',lineHeight:1.5}}>
            Montre ce QR code à ton professeur<br/>ou télécharge le fichier JSON ci-dessous
          </div>
        </div>

        {/* Quick stats */}
        <div style={{background:'#fff',borderRadius:16,padding:'14px',
          boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
          <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,fontSize:13,
            color:'#1E293B',marginBottom:10}}>📊 Mes stats résumées</div>
          {Object.entries(data.c).map(([catId, stat]) => (
            <div key={catId} style={{display:'flex',alignItems:'center',gap:8,
              padding:'6px 0',borderBottom:'1px solid #F8FAFC'}}>
              <span style={{fontSize:14,width:20}}>{CATS_MAP[catId]?.split(' ')[0]||'📚'}</span>
              <div style={{flex:1,fontSize:11,fontWeight:600,color:'#334155'}}>
                {CATS_MAP[catId]?.split(' ').slice(1).join(' ')||catId}
              </div>
              {stat.rate!==null && (
                <span style={{fontSize:10,fontWeight:700,
                  color:stat.rate>=80?'#10B981':stat.rate>=60?'#F59E0B':'#EF4444'}}>
                  {stat.rate}%
                </span>
              )}
              <span style={{fontSize:10,color:'#94A3B8'}}>
                {'⭐'.repeat(stat.stars>3?3:stat.stars)||'○'}
              </span>
            </div>
          ))}
        </div>

        <div style={{background:'#EFF6FF',borderRadius:12,padding:'10px 14px',
          fontSize:11,color:'#1D4ED8',lineHeight:1.5,fontWeight:600}}>
          💡 Ton professeur scanne ce QR code avec son tableau de bord AutoMaths
          pour voir tes progrès en temps réel.
        </div>
      </div>
    </div>
  );
}

// ── Send to Teacher Screen (lien partagé) ────────────────────────────────────
function SendToTeacherScreen({profile, onBack}) {
  const [link, setLink] = React.useState('');
  const [status, setStatus] = React.useState('');
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    // BUGFIX : on charge les données fraîches depuis le storage à chaque ouverture
    // de l'écran. Avant, on utilisait `allProgCache` (state global) qui n'était
    // jamais alimenté → snapshots avec progress: {} et totalXp: 0.
    (async () => {
      try {
        // 1. Reconstruire allProg depuis le storage par catégorie/sous-catégorie
        const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
        const entries = [];
        Object.entries(curr.cats).forEach(([c, subs]) => subs.forEach(s => entries.push([c, s])));
        const allProg = {};
        await Promise.all(entries.map(async ([c, s]) => {
          try {
            const r = await _storage.get(PK(c, s));
            if (r?.value) allProg[`${c}:${s}`] = JSON.parse(r.value);
          } catch {}
        }));

        // 2. Charger l'XP cumulé
        const xp = await loadXP().catch(() => 0);

        // 3. Générer le snapshot et le lien
        const snap = await teacherSnapshot(profile, allProg, xp);
        setLink(buildTeacherLink(snap));
        setLoading(false);
      } catch (e) {
        setStatus('error');
        setLoading(false);
      }
    })();
  }, [profile]);

  const handleShare = async () => {
    if (!link) return;
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Mon suivi AutoMaths',
          text: `Suivi de ${profile.name} pour le prof`,
          url: link,
        });
        setStatus('shared');
      } catch (e) {
        // L'utilisateur a annulé le partage, on ne fait rien
      }
    } else {
      handleCopy();
    }
  };

  const handleCopy = async () => {
    if (!link) return;
    try {
      await navigator.clipboard.writeText(link);
      setStatus('copied');
      setTimeout(() => setStatus(''), 2500);
    } catch {
      const ta = document.getElementById('teacher-link-area');
      if (ta) { ta.select(); document.execCommand('copy'); setStatus('copied'); }
    }
  };

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      <div style={{background:'linear-gradient(135deg,var(--am-bg-dark-1),var(--am-bg-dark-2))',
        padding:'14px 16px',flexShrink:0,display:'flex',alignItems:'center',gap:10}}>
        <button onClick={onBack} style={{background:'rgba(255,255,255,0.1)',border:'none',
          borderRadius:9,padding:'6px 11px',color:'#94A3B8',cursor:'pointer',fontSize:12,fontWeight:700}}>
          ← Retour
        </button>
        <div style={{flex:1,color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:16,textAlign:'center'}}>
          Envoyer à mon prof 📨
        </div>
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'20px',display:'flex',flexDirection:'column',gap:14}}>
        {loading ? (
          <div style={{textAlign:'center',padding:40,color:'#64748B'}}>Préparation du lien…</div>
        ) : (
          <React.Fragment>
            <div style={{background:'#fff',borderRadius:18,padding:'20px',
              boxShadow:'0 4px 16px rgba(0,0,0,.08)'}}>
              <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:15,
                color:'#1E293B',marginBottom:8}}>
                Comment ça marche
              </div>
              <ol style={{paddingLeft:20,fontSize:13,color:'#475569',lineHeight:1.7,margin:0}}>
                <li>Appuie sur <strong>Partager</strong> ci-dessous</li>
                <li>Choisis Pronote, Mail, ou n'importe quel moyen</li>
                <li>Envoie le lien à ton prof — il l'ouvrira et tes progrès apparaîtront chez lui</li>
              </ol>
              <div style={{marginTop:12,padding:'10px 12px',background:'#FEF3C7',borderRadius:8,
                fontSize:11,color:'#92400E',lineHeight:1.5}}>
                💡 Le lien contient un résumé de ton travail. Pas ton mot de passe, pas tes badges :
                juste ce que ton prof a besoin de voir.
              </div>
            </div>

            <button onClick={handleShare} style={{
              padding:'16px 20px',background:'linear-gradient(135deg,#4338CA,#6366F1)',
              color:'#fff',border:'none',borderRadius:14,fontSize:16,fontWeight:800,
              cursor:'pointer',fontFamily:"'Nunito',sans-serif",
              boxShadow:'0 4px 12px rgba(99,102,241,0.3)'}}>
              📤 Partager le lien
            </button>

            <button onClick={handleCopy} style={{
              padding:'12px 20px',background:'#fff',color:'#1E293B',
              border:'2px solid #E2E8F0',borderRadius:12,fontSize:14,fontWeight:700,
              cursor:'pointer',fontFamily:"'Nunito',sans-serif"}}>
              {status === 'copied' ? '✓ Lien copié' : '📋 Copier le lien'}
            </button>

            <details style={{background:'#fff',borderRadius:12,padding:12,fontSize:12}}>
              <summary style={{cursor:'pointer',color:'#64748B',fontWeight:700}}>
                Voir le lien (avancé)
              </summary>
              <textarea id="teacher-link-area" value={link} readOnly
                style={{width:'100%',minHeight:80,marginTop:10,padding:8,
                  fontSize:10,fontFamily:'monospace',border:'1px solid #E2E8F0',
                  borderRadius:6,resize:'vertical',color:'#475569'}}/>
            </details>

            {status === 'shared' && (
              <div style={{padding:'10px 14px',background:'#D1FAE5',borderRadius:10,
                fontSize:12,color:'#065F46',fontWeight:600}}>
                ✓ Lien partagé. Ton prof devrait le recevoir.
              </div>
            )}
            {status === 'error' && (
              <div style={{padding:'10px 14px',background:'#FEE2E2',borderRadius:10,
                fontSize:12,color:'#991B1B',fontWeight:600}}>
                Erreur de génération du lien. Réessaie.
              </div>
            )}
          </React.Fragment>
        )}
      </div>
    </div>
  );
}

// ── Reminder / Notification system ────────────────────────────────────────────
const REMINDER_K = 'user:reminder';

async function loadReminder()  { try{const r=await _storage.get(REMINDER_K);return r?.value?JSON.parse(r.value):null;}catch{return null;} }
async function saveReminder(d) { try{await _storage.set(REMINDER_K,JSON.stringify(d));}catch{} }

function ReminderScreen({onBack}) {
  const [notifPerm, setNotifPerm] = React.useState(typeof Notification!=='undefined'?Notification.permission:'denied');
  const [hour, setHour] = React.useState(18);
  const [saved, setSaved] = React.useState(false);

  const requestPerm = async () => {
    if(typeof Notification === 'undefined') return;
    const perm = await Notification.requestPermission();
    setNotifPerm(perm);
    if(perm === 'granted') {
      new Notification("l'AutoMaths 🤖", {
        body:"Sigma te rappellera chaque jour à l'heure choisie !",
        icon:SIGMA_IMG
      });
    }
  };

  const save = async () => {
    await saveReminder({ hour, enabled: notifPerm==='granted' });
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const HOURS = Array.from({length:16},(_,i)=>i+7); // 7h → 22h
  const permColor = notifPerm==='granted'?'#10B981':notifPerm==='denied'?'#EF4444':'#F59E0B';
  const permLabel = notifPerm==='granted'?'✅ Autorisées':'⚠️ '+notifPerm;

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      <div style={{background:'linear-gradient(135deg,var(--am-bg-dark-1),var(--am-bg-dark-2))',
        padding:'14px 16px',flexShrink:0,display:'flex',alignItems:'center',gap:10}}>
        <button onClick={onBack} style={{background:'rgba(255,255,255,0.1)',border:'none',
          borderRadius:9,padding:'6px 11px',color:'#94A3B8',cursor:'pointer',fontSize:12,fontWeight:700}}>
          ← Retour
        </button>
        <div style={{flex:1,color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,
          fontSize:16,textAlign:'center'}}>Rappels quotidiens 🔔</div>
      </div>

      <div style={{flex:1,padding:'20px',display:'flex',flexDirection:'column',gap:14}}>

        {/* Sigma */}
        <div style={{textAlign:'center',padding:'10px 0'}}>
          <div className="sigma-float"><Sigma emotion="love" size={100}/></div>
          <div className="sigma-shadow" style={{width:'35%',margin:'-2px auto 0'}}/>
          <div style={{marginTop:10,fontFamily:"'Nunito',sans-serif",fontWeight:800,
            fontSize:15,color:'#1E293B'}}>
            Je peux te rappeler chaque jour !
          </div>
          <div style={{color:'#64748B',fontSize:12,marginTop:4}}>
            Une notification à l'heure de ton choix
          </div>
        </div>

        {/* Permission */}
        <div style={{background:'#fff',borderRadius:16,padding:'16px',
          boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
          <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:12}}>
            <span style={{fontSize:20}}>🔔</span>
            <div style={{flex:1}}>
              <div style={{fontWeight:800,fontSize:13,color:'#1E293B'}}>Notifications</div>
              <div style={{fontSize:10,color:permColor,fontWeight:700}}>{permLabel}</div>
            </div>
            {notifPerm!=='granted'&&(
              <button onClick={requestPerm}
                style={{padding:'8px 14px',borderRadius:10,border:'none',
                  background:'linear-gradient(135deg,#7C3AED,#5B21B6)',
                  color:'#fff',fontFamily:"'Nunito',sans-serif",
                  fontSize:12,fontWeight:800,cursor:'pointer'}}>
                Autoriser
              </button>
            )}
          </div>

          {notifPerm==='denied'&&(
            <div style={{background:'#FEF2F2',borderRadius:10,padding:'10px 12px',
              fontSize:11,color:'#991B1B',lineHeight:1.5}}>
              ⚠️ Notifications bloquées dans ce navigateur.<br/>
              Va dans Paramètres → Notifications → AutoMaths → Autoriser
            </div>
          )}
        </div>

        {/* Hour picker */}
        {notifPerm==='granted'&&(
          <div style={{background:'#fff',borderRadius:16,padding:'16px',
            boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
            <div style={{fontWeight:800,fontSize:13,color:'#1E293B',marginBottom:12}}>
              🕐 Heure du rappel
            </div>
            <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
              {HOURS.map(h=>(
                <button key={h} onClick={()=>setHour(h)}
                  style={{padding:'8px 12px',borderRadius:10,border:'none',
                    background:hour===h?'#7C3AED':'#F1F5F9',
                    color:hour===h?'#fff':'#64748B',
                    fontFamily:"'Nunito',sans-serif",fontWeight:700,
                    fontSize:12,cursor:'pointer'}}>
                  {h}h
                </button>
              ))}
            </div>
            <div style={{marginTop:12,padding:'10px',background:'#F5F3FF',borderRadius:10,
              fontSize:12,color:'#5B21B6',fontWeight:600,textAlign:'center'}}>
              🤖 Sigma te rappellera chaque jour à {hour}h00
            </div>
          </div>
        )}

        {notifPerm==='granted'&&(
          <button onClick={save}
            style={{padding:'14px',borderRadius:14,border:'none',
              background:saved?'#10B981':'linear-gradient(135deg,#F59E0B,#B45309)',
              color:'#fff',fontFamily:"'Nunito',sans-serif",
              fontSize:15,fontWeight:900,cursor:'pointer',
              boxShadow:'0 5px 16px rgba(245,158,11,.3)',transition:'background .3s'}}>
            {saved?'✅ Rappel enregistré !':'Enregistrer mon rappel 🔔'}
          </button>
        )}

        <div style={{background:'#FEF9C3',borderRadius:12,padding:'10px 14px',
          fontSize:11,color:'#92400E',lineHeight:1.5}}>
          💡 <strong>Sans serveur :</strong> Le rappel fonctionne quand l'app est installée
          sur ton téléphone (PWA). Pour des notifs en arrière-plan depuis n'importe où, 
          il faut l'héberger sur un serveur (voir README).
        </div>
      </div>
    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// BackupScreen — Sauvegarder / Restaurer ses données
// ─────────────────────────────────────────────────────────────────────────────
// Mode "expertise" : l'élève copie son code et le stocke lui-même (mail, notes).
// Pas de serveur, pas de compte, zéro friction. S'il perd ses données (clear
// cache, changement d'appareil), il colle son code et retrouve tout.
function BackupScreen({onBack, onImportDone, onSendTeacher, hasProfile}) {
  const [tab, setTab] = useState('export'); // 'export' | 'import'
  const [code, setCode] = useState('');
  const [importCode, setImportCode] = useState('');
  const [status, setStatus] = useState(null); // {type:'ok'|'err', msg}
  const [copied, setCopied] = useState(false);
  const [loading, setLoading] = useState(false);

  // Génère le code dès l'arrivée sur l'onglet export
  useEffect(() => {
    if (tab === 'export' && !code) {
      setLoading(true);
      exportBackup().then(c => { setCode(c); setLoading(false); })
        .catch(() => { setStatus({type:'err', msg:"Erreur lors de l'export"}); setLoading(false); });
    }
  }, [tab]);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(code);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback : select the textarea
      try {
        const ta = document.getElementById('backup-code-area');
        if (ta) { ta.select(); document.execCommand('copy'); setCopied(true); setTimeout(()=>setCopied(false), 2000); }
      } catch {}
    }
  };

  const handleImport = async () => {
    if (!importCode.trim()) {
      setStatus({type:'err', msg:'Colle ton code avant de restaurer'});
      return;
    }
    if (!confirm('Restaurer cette sauvegarde écrasera tes données actuelles sur cet appareil. Continuer ?')) return;
    setLoading(true);
    const res = await importBackup(importCode.trim());
    setLoading(false);
    if (res.ok) {
      setStatus({type:'ok', msg:`✅ ${res.msg} (${res.count} éléments)`});
      setTimeout(() => { if (onImportDone) onImportDone(); }, 1500);
    } else {
      setStatus({type:'err', msg:`❌ ${res.msg}`});
    }
  };

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      {/* Header */}
      <div style={{background:'linear-gradient(135deg,var(--am-bg-dark-1),var(--am-bg-dark-2))',
        padding:'14px 16px',flexShrink:0,display:'flex',alignItems:'center',gap:10}}>
        <button onClick={onBack} style={{background:'rgba(255,255,255,0.1)',border:'none',
          borderRadius:9,padding:'6px 11px',color:'#94A3B8',cursor:'pointer',fontSize:12,fontWeight:700}}>
          ← Retour
        </button>
        <div style={{flex:1,color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:16,textAlign:'center'}}>
          Sauvegarder 💾
        </div>
      </div>

      {/* Tabs */}
      <div style={{display:'flex',background:'#fff',borderBottom:'1px solid #E2E8F0',flexShrink:0}}>
        {[{id:'export',label:'📤 Sauvegarder'},{id:'import',label:'📥 Restaurer'}].map(t=>(
          <button key={t.id} onClick={()=>{setTab(t.id);setStatus(null);}}
            style={{flex:1,padding:'12px 8px',border:'none',cursor:'pointer',
              background: tab===t.id?'#EFF6FF':'#fff',
              color: tab===t.id?'#1D4ED8':'#64748B',
              fontFamily:"'Nunito',sans-serif",fontSize:12,fontWeight:800,
              borderBottom: tab===t.id?'3px solid #1D4ED8':'3px solid transparent'}}>
            {t.label}
          </button>
        ))}
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'16px',display:'flex',flexDirection:'column',gap:14}}>
        {hasProfile && onSendTeacher && (
          <button onClick={onSendTeacher}
            style={{padding:'14px 16px',background:'linear-gradient(135deg,#4338CA,#6366F1)',
              color:'#fff',border:'none',borderRadius:14,fontSize:14,fontWeight:800,
              cursor:'pointer',fontFamily:"'Nunito',sans-serif",
              display:'flex',alignItems:'center',justifyContent:'center',gap:10,
              boxShadow:'0 4px 12px rgba(99,102,241,0.25)'}}>
            <span style={{fontSize:18}}>📨</span>
            <span>Envoyer mes progrès à mon prof</span>
          </button>
        )}

        {tab === 'export' && (
          <>
            <div style={{background:'#EFF6FF',borderRadius:12,padding:'12px 14px',
              borderLeft:'4px solid #1D4ED8',fontSize:12,color:'#1E3A8A',lineHeight:1.5}}>
              <strong>💡 À quoi sert ce code ?</strong><br/>
              Copie-le dans un endroit sûr (mail, notes). Si tu changes d'appareil ou si tu es
              déconnecté, tu pourras retrouver tout ton parcours en collant ce code.
            </div>

            {loading ? (
              <div style={{textAlign:'center',padding:20,color:'#64748B',fontSize:12}}>
                Génération de la sauvegarde…
              </div>
            ) : (
              <>
                <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,fontSize:13,color:'#1E293B'}}>
                  🔐 Ton code de sauvegarde
                </div>
                <textarea id="backup-code-area" value={code} readOnly
                  style={{width:'100%',minHeight:160,padding:'10px',fontSize:10,
                    fontFamily:'monospace',background:'#F8FAFC',border:'1.5px solid #CBD5E1',
                    borderRadius:10,resize:'vertical',lineHeight:1.4,wordBreak:'break-all'}}/>

                <button onClick={handleCopy}
                  style={{padding:'12px',borderRadius:12,border:'none',cursor:'pointer',
                    background: copied?'#10B981':'linear-gradient(135deg,#1D4ED8,#1E40AF)',
                    color:'#fff',fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:900,
                    boxShadow:'0 4px 12px rgba(29,78,216,.25)'}}>
                  {copied ? '✅ Copié !' : '📋 Copier le code'}
                </button>

                <div style={{background:'#FEF9C3',borderRadius:10,padding:'10px 12px',
                  fontSize:11,color:'#92400E',lineHeight:1.5}}>
                  ⚠️ <strong>Garde ce code en sécurité.</strong> Il contient toute ta progression :
                  étoiles, cartes, streak, XP, badges, diagnostic, programme…
                </div>
              </>
            )}
          </>
        )}

        {tab === 'import' && (
          <>
            <div style={{background:'#FEF9C3',borderRadius:12,padding:'12px 14px',
              borderLeft:'4px solid #F59E0B',fontSize:12,color:'#92400E',lineHeight:1.5}}>
              <strong>⚠️ Attention :</strong> Restaurer une sauvegarde remplacera toutes tes données
              actuelles sur cet appareil. Cette action est irréversible.
            </div>

            <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,fontSize:13,color:'#1E293B'}}>
              📥 Colle ton code de sauvegarde
            </div>
            <textarea value={importCode} onChange={e=>{setImportCode(e.target.value);setStatus(null);}}
              placeholder="Colle ici ton code de sauvegarde…"
              style={{width:'100%',minHeight:140,padding:'10px',fontSize:10,
                fontFamily:'monospace',background:'#fff',border:'1.5px solid #CBD5E1',
                borderRadius:10,resize:'vertical',lineHeight:1.4,wordBreak:'break-all'}}/>

            {status && (
              <div style={{padding:'10px 12px',borderRadius:10,fontSize:12,fontWeight:700,
                background: status.type==='ok'?'#D1FAE5':'#FEE2E2',
                color: status.type==='ok'?'#065F46':'#991B1B'}}>
                {status.msg}
              </div>
            )}

            <button onClick={handleImport} disabled={loading || !importCode.trim()}
              style={{padding:'12px',borderRadius:12,border:'none',
                cursor: (loading || !importCode.trim())?'not-allowed':'pointer',
                background: (loading || !importCode.trim())?'#CBD5E1':'linear-gradient(135deg,#059669,#047857)',
                color:'#fff',fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:900,
                boxShadow:'0 4px 12px rgba(5,150,105,.25)',opacity: (loading || !importCode.trim())?0.6:1}}>
              {loading ? '⏳ Restauration…' : '♻️ Restaurer ma sauvegarde'}
            </button>
          </>
        )}
      </div>
    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// PreferencesScreen — Taille de texte + Thème
// ─────────────────────────────────────────────────────────────────────────────
function PreferencesScreen({profile, onSave, onBack}) {
  const currentPrefs = getPrefs(profile);
  const [fontScale, setFontScale] = useState(currentPrefs.fontScale);
  const [theme, setTheme] = useState(currentPrefs.theme);

  // Aperçu en direct de la taille de texte
  useEffect(() => {
    applyFontScale(fontScale);
  }, [fontScale]);

  const thObj = THEMES[theme] || THEMES.ocean;

  const handleSave = () => {
    const updatedProfile = { ...profile, prefs: { fontScale, theme } };
    saveProfA(updatedProfile);
    onSave(updatedProfile);
  };

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',background:'var(--am-bg-light)'}}>
      {/* Header */}
      <div style={{background:'linear-gradient(135deg,var(--am-bg-dark-1),var(--am-bg-dark-2))',
        padding:'14px 16px',flexShrink:0,display:'flex',alignItems:'center',gap:10}}>
        <button onClick={onBack} style={{background:'rgba(255,255,255,0.1)',border:'none',
          borderRadius:9,padding:'6px 11px',color:'#94A3B8',cursor:'pointer',fontSize:12,fontWeight:700}}>
          ← Retour
        </button>
        <div style={{flex:1,color:'#fff',fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:16,textAlign:'center'}}>
          Préférences 🎨
        </div>
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'16px',display:'flex',flexDirection:'column',gap:16}}>

        {/* ─── Taille de texte ─── */}
        <div style={{background:'#fff',borderRadius:16,padding:'16px',
          boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
          <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,fontSize:14,
            color:'#1E293B',marginBottom:4}}>🔤 Taille du texte</div>
          <div style={{fontSize:11,color:'#64748B',marginBottom:12}}>
            Pour un meilleur confort de lecture
          </div>
          <div style={{display:'flex',flexDirection:'column',gap:8}}>
            {Object.entries(FONT_SCALES).map(([key, {label, factor}]) => {
              const active = fontScale === key;
              return (
                <button key={key} onClick={() => setFontScale(key)}
                  style={{background: active?'#EFF6FF':'#F8FAFC',
                    border: active?'2px solid #1D4ED8':'2px solid transparent',
                    borderRadius:12,padding:'12px 14px',cursor:'pointer',
                    display:'flex',alignItems:'center',justifyContent:'space-between',
                    transition:'all .15s'}}>
                  <span style={{fontFamily:"'Nunito',sans-serif",fontWeight:700,
                    fontSize: 14 * factor, color:'#1E293B'}}>{label}</span>
                  <span style={{fontSize: 11 * factor, color:'#64748B'}}>Exemple de texte</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* ─── Thème de couleurs ─── */}
        <div style={{background:'#fff',borderRadius:16,padding:'16px',
          boxShadow:'0 2px 8px rgba(0,0,0,.05)'}}>
          <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,fontSize:14,
            color:'#1E293B',marginBottom:4}}>🎨 Thème de couleurs</div>
          <div style={{fontSize:11,color:'#64748B',marginBottom:12}}>
            Change l'ambiance des écrans principaux
          </div>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10}}>
            {Object.entries(THEMES).map(([key, th]) => {
              const active = theme === key;
              return (
                <button key={key} onClick={() => setTheme(key)}
                  style={{background:'transparent',border:'none',padding:0,cursor:'pointer'}}>
                  <div style={{background: th.bgMain, borderRadius:12,padding:'20px 10px',
                    border: active?'3px solid #F59E0B':'3px solid transparent',
                    boxShadow: active?'0 4px 14px rgba(245,158,11,.3)':'0 2px 6px rgba(0,0,0,.08)',
                    textAlign:'center',position:'relative'}}>
                    <div style={{fontSize:28,marginBottom:4}}>{th.emoji}</div>
                    <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,
                      fontSize:12,color: th.dark?'#fff':'#1E293B'}}>
                      {th.label}
                    </div>
                    {active && (
                      <div style={{position:'absolute',top:4,right:6,fontSize:14}}>✓</div>
                    )}
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* ─── Aperçu ─── */}
        <div style={{background: thObj.bgMain, borderRadius:16,padding:'20px',
          boxShadow:'0 2px 8px rgba(0,0,0,.1)'}}>
          <div style={{color: thObj.dark?'#fff':'#1E293B',
            fontFamily:"'Nunito',sans-serif",fontWeight:800,
            fontSize: 14 * (FONT_SCALES[fontScale]?.factor||1),
            textAlign:'center',marginBottom:8}}>
            Aperçu du thème
          </div>
          <div style={{color: thObj.dark?'#94A3B8':'#475569',
            fontSize: 11 * (FONT_SCALES[fontScale]?.factor||1),
            textAlign:'center'}}>
            Voici comment sera affiché l'écran d'accueil
          </div>
        </div>

        {/* ─── Bouton Enregistrer ─── */}
        <button onClick={handleSave}
          style={{background:'linear-gradient(135deg,#10B981,#059669)',border:'none',
            borderRadius:14,padding:'14px',cursor:'pointer',color:'#fff',
            fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:15,
            boxShadow:'0 6px 16px rgba(16,185,129,.3)'}}>
          ✓ Enregistrer
        </button>
      </div>
    </div>
  );
}


function ProfileSetupScreen({onComplete, onBack, onRestore}) {
  const [name, setName] = useState('');
  const [level, setLevel] = useState('');
  const [step, setStep] = useState(0);
  const LEVELS = [
    {id:'seconde',       emoji:'🌱', label:'Seconde',             desc:'Je commence le lycée'},
    {id:'premiere_tronc',emoji:'📘', label:'1ère Tronc commun',   desc:'Sans spécialité maths'},
    {id:'premiere_stmg', emoji:'📊', label:'1ère STMG',           desc:'Sciences de gestion'},
    {id:'premiere_spe',  emoji:'🔬', label:'1ère Spé Maths',      desc:'Avec spécialité maths'},
    {id:'terminale_spe', emoji:'🏆', label:'Terminale Spé',        desc:'Bac à portée !'},
  ];
  const finish = async () => {
    const prof={name:name.trim(),level,joinedAt:Date.now(),streak:0,lastActive:Date.now()};
    // Rétroactivement : si le compteur streak_progress a déjà franchi le seuil
    // aujourd'hui (l'élève a joué avant de créer son compte), on crédite la série.
    try {
      const sp = await loadStreakProgress();
      if (sp && sp.completed) {
        prof.streak = 1; // premier jour validé
      }
    } catch {}
    saveProfA(prof); onComplete(prof);
  };
  return (
    <div style={{height:"100%",display:"flex",flexDirection:"column",alignItems:"center",
      justifyContent:"center",padding:"24px",background:"linear-gradient(170deg,var(--am-bg-dark-1),var(--am-bg-dark-2))",
      position:"relative"}}>
      {/* Bouton retour */}
      <button onClick={step===1?()=>setStep(0):onBack}
        style={{position:"absolute",top:16,left:16,background:"rgba(255,255,255,0.08)",
          border:"none",borderRadius:9,padding:"6px 12px",color:"#94A3B8",
          cursor:"pointer",fontSize:12,fontWeight:700}}>
        ← Retour
      </button>
      <div style={{display:"flex",flexDirection:"column",alignItems:"center",width:"100%"}}>
        <div className="sigma-float">
          <Sigma emotion={step===0?"thinking":"love"} size={180}/>
        </div>
        <div className="sigma-shadow" style={{marginTop:-4}}/>
      </div>
      {step===0?(
        <div className="slide-up" style={{width:"100%",maxWidth:320,marginTop:20}}>
          <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:22,color:"#fff",textAlign:"center",marginBottom:6}}>Bienvenue ! Je suis Sigma 🤖</div>
          <div style={{color:"#64748B",textAlign:"center",fontSize:13,marginBottom:22}}>Ton assistante maths personnelle.<br/>Comment tu t'appelles ?</div>
          <input autoFocus placeholder="Ton prénom..." value={name}
            onChange={e=>setName(e.target.value)}
            onKeyDown={e=>e.key==='Enter'&&name.trim()&&setStep(1)}
            style={{width:"100%",padding:"14px 16px",borderRadius:14,border:"2px solid #334155",
              background:"#1E293B",color:"#fff",fontSize:16,fontFamily:"'DM Sans',sans-serif",
              boxSizing:"border-box",outline:"none"}}/>
          <button onClick={()=>setStep(1)} disabled={!name.trim()}
            style={{width:"100%",marginTop:12,padding:"14px",borderRadius:14,border:"none",
              background:name.trim()?"linear-gradient(135deg,#F59E0B,#B45309)":"#1E293B",
              color:name.trim()?"#fff":"#475569",fontFamily:"'Nunito',sans-serif",
              fontSize:15,fontWeight:800,cursor:name.trim()?"pointer":"default"}}>
            Continuer →
          </button>
          {/* Lien : si l'élève a déjà un compte, il peut restaurer sa sauvegarde
              au lieu de refaire tout le diagnostic */}
          {onRestore && (
            <div style={{marginTop:14,paddingTop:14,borderTop:"1px solid rgba(148,163,184,0.15)",
              textAlign:"center"}}>
              <div style={{fontSize:11,color:"#64748B",marginBottom:6}}>
                Tu as déjà utilisé AutoMaths ?
              </div>
              <button onClick={onRestore}
                style={{background:"transparent",border:"1.5px solid rgba(59,130,246,0.4)",
                  borderRadius:10,padding:"8px 14px",cursor:"pointer",
                  color:"#93C5FD",fontFamily:"'Nunito',sans-serif",
                  fontSize:11,fontWeight:800,display:"inline-flex",alignItems:"center",gap:6}}>
                💾 Restaurer ma sauvegarde
              </button>
            </div>
          )}
        </div>
      ):(
        <div className="slide-up" style={{width:"100%",maxWidth:320,marginTop:16}}>
          <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:20,color:"#fff",textAlign:"center",marginBottom:4}}>Super, {name.trim()} ! 👋</div>
          <div style={{color:"#64748B",textAlign:"center",fontSize:13,marginBottom:18}}>Quel est ton niveau ?</div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {LEVELS.map(l=>(
              <button key={l.id} onClick={()=>setLevel(l.id)}
                style={{padding:"13px 16px",borderRadius:14,border:`2px solid ${level===l.id?"#F59E0B":"#334155"}`,
                  background:level===l.id?"rgba(245,158,11,0.15)":"#1E293B",
                  color:"#fff",cursor:"pointer",display:"flex",alignItems:"center",gap:10,textAlign:"left"}}>
                <span style={{fontSize:22}}>{l.emoji}</span>
                <div style={{flex:1}}>
                  <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:800,fontSize:13}}>{l.label}</div>
                  <div style={{color:"#475569",fontSize:10}}>{l.desc}</div>
                </div>
                {level===l.id&&<span style={{color:"#F59E0B",fontSize:18}}>✓</span>}
              </button>
            ))}
          </div>
          <button onClick={finish} disabled={!level}
            style={{width:"100%",marginTop:14,padding:"14px",borderRadius:14,border:"none",
              background:level?"linear-gradient(135deg,#10B981,#047857)":"#1E293B",
              color:level?"#fff":"#475569",fontFamily:"'Nunito',sans-serif",
              fontSize:15,fontWeight:800,cursor:level?"pointer":"default"}}>
            C'est parti ! 🚀
          </button>
        </div>
      )}
    </div>
  );
}

