// ── Défi du Jour ─────────────────────────────────────────────────────────────
function getDailyChallenge(profile, allProg, diagResults) {
  const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
  const allCats = Object.keys(curr.cats);

  // Seed basé sur la date (change chaque jour)
  const seed = new Date().toDateString();
  let hash = 0;
  for (let c of seed) hash = (hash*31 + c.charCodeAt(0)) & 0xFFFFFF;

  // ── Choix ciblé : privilégier les thèmes faibles ───────────────────────────
  // Priorité au signal le plus récent : allProg > diagResults > aléatoire
  let targetCat = null;
  let targetSub = null;

  // Phase 1 : chercher une sous-catégorie faible dans allProg (<60% de réussite, >=3 tentatives)
  if (allProg) {
    const weak = [];
    for (const catId of allCats) {
      const subs = curr.cats[catId] || [];
      for (const subId of subs) {
        const p = allProg[`${catId}:${subId}`];
        if (p && p.pt >= 3) {
          const rate = Math.round(p.pc / p.pt * 100);
          if (rate < 60 && (p.stars || 0) < 3) weak.push({ catId, subId, rate });
        }
      }
    }
    if (weak.length > 0) {
      // Choisir dans les faibles, avec un peu de variation par le hash du jour
      weak.sort((a, b) => a.rate - b.rate);
      // 70% du temps : le plus faible ; 30% du temps : un autre parmi les 3 premiers
      const pick = (hash % 10 < 7) ? weak[0] : weak[hash % Math.min(3, weak.length)];
      targetCat = pick.catId;
      targetSub = pick.subId;
    }
  }

  // Phase 2 : fallback sur diagResults (catégorie la plus faible au diagnostic)
  if (!targetCat && diagResults) {
    const catRates = [];
    for (const catId of allCats) {
      const d = diagResults[catId];
      if (d && d.total > 0) {
        const rate = Math.round(d.correct / d.total * 100);
        if (rate < 60) catRates.push({ catId, rate });
      }
    }
    if (catRates.length > 0) {
      catRates.sort((a, b) => a.rate - b.rate);
      const pick = (hash % 10 < 7) ? catRates[0] : catRates[hash % Math.min(3, catRates.length)];
      targetCat = pick.catId;
      // Sous-thème : le premier de la catégorie (ordre pédagogique)
      const subs = curr.cats[targetCat] || [];
      targetSub = subs[hash % Math.max(subs.length, 1)];
    }
  }

  // Phase 3 : fallback aléatoire (comportement original)
  if (!targetCat) {
    const catIdx = hash % allCats.length;
    targetCat = allCats[catIdx];
    const subs = curr.cats[targetCat];
    const subIdx = (hash >> 8) % subs.length;
    targetSub = subs[subIdx];
  }

  const qs = (DB[targetCat] && DB[targetCat][targetSub]) ? DB[targetCat][targetSub] : [];
  const picked = [];
  for (let i = 0; i < 5 && qs.length > 0; i++) {
    picked.push(qs[(hash + i*7) % qs.length]);
  }
  return { catId: targetCat, subId: targetSub, questions: picked, date: new Date().toDateString() };
}

