// Helper : compte les questions en "mastered"
function countMastered(qState) {
  if (!qState || typeof qState !== 'object') return 0;
  let n = 0;
  for (const k in qState) if (qState[k]?.status === "mastered") n++;
  return n;
}

// Helper : vérifie s'il existe un sous-thème dont toutes les questions sont "mastered"
function hasFullyMasteredSubtheme(qState) {
  if (!qState) return false;
  // Regrouper par catId:subId
  const bySub = {};
  for (const k in qState) {
    const parts = k.split(":");
    if (parts.length < 3) continue;
    const subKey = parts[0] + ":" + parts[1];
    bySub[subKey] = bySub[subKey] || { total: 0, mastered: 0 };
    bySub[subKey].total++;
    if (qState[k]?.status === "mastered") bySub[subKey].mastered++;
  }
  // Chercher un sous-thème où total >= 3 (éviter les micro-subs) et tous mastered
  for (const sk in bySub) {
    const { total, mastered } = bySub[sk];
    if (total >= 3 && total === mastered) {
      // Vérifier aussi qu'on a au moins autant de questions dans DB pour ce sub
      const [catId, subId] = sk.split(":");
      const subQs = DB?.[catId]?.[subId];
      if (Array.isArray(subQs) && subQs.length === total) return true;
    }
  }
  return false;
}

