// Fonction centrale : évalue tous les objectifs et renvoie la liste des cartes débloquées
// ET non encore enregistrées dans CARDS_UNLOCKED_K. Appelée après chaque événement pertinent.
async function checkNewUnlocks(ctx) {
  const unlocked = await loadCardsUnlocked();
  const newOnes = [];
  for (const card of CARDS) {
    if (unlocked.includes(card.id)) continue;
    const obj = CARDS_OBJECTIVES[card.id];
    if (!obj) continue;
    try {
      if (obj.check(ctx)) newOnes.push(card);
    } catch(e) { /* ignore */ }
  }
  if (newOnes.length > 0) {
    const updated = [...unlocked, ...newOnes.map(c => c.id)];
    await saveCardsUnlocked(updated);
  }
  return newOnes;
}

// Enregistrer un weekend-day joué (pour Venice)
async function recordWeekendActivity() {
  const d = new Date();
  const day = d.getDay(); // 0=Sun, 6=Sat
  if (day !== 0 && day !== 6) return;
  const year = d.getFullYear();
  // Numéro de semaine ISO
  const jan1 = new Date(year, 0, 1);
  const week = Math.ceil(((d - jan1) / 86400000 + jan1.getDay() + 1) / 7);
  const key = `${year}-W${week}`;
  const w = await loadWeekendDays();
  const existing = w[key] || [];
  const lbl = day === 6 ? "Sat" : "Sun";
  if (!existing.includes(lbl)) {
    existing.push(lbl);
    w[key] = existing;
    // Nettoyer les anciennes semaines (garder 8 semaines max)
    const keys = Object.keys(w).sort();
    while (keys.length > 8) { delete w[keys.shift()]; }
    await saveWeekendDays(w);
  }
}

