// ── Streak progress (bonnes réponses cumulées du jour) ───────────────────────
// Retourne { date, count, completed }. Si la date stockée n'est pas aujourd'hui, reset.
async function loadStreakProgress() {
  try {
    const r = await _storage.get(STREAK_PROGRESS_K);
    const today = new Date().toDateString();
    if (r?.value) {
      const data = JSON.parse(r.value);
      if (data.date === today) return data;
    }
    return { date: today, count: 0, completed: false };
  } catch { return { date: new Date().toDateString(), count: 0, completed: false }; }
}
async function saveStreakProgress(p) {
  try { await _storage.set(STREAK_PROGRESS_K, JSON.stringify(p)); } catch {}
}

// ── Compteur lifetime (total bonnes réponses jamais remis à zéro) ─────────
async function loadLifetimeCorrect() {
  try { const r = await _storage.get(LIFETIME_CORRECT_K); return r?.value ? parseInt(r.value) : 0; }
  catch { return 0; }
}
async function saveLifetimeCorrect(n) {
  try { await _storage.set(LIFETIME_CORRECT_K, String(n)); } catch {}
}
async function loadPromptDismissedAt() {
  try { const r = await _storage.get(PROMPT_DISMISSED_AT_K); return r?.value ? parseInt(r.value) : -1; }
  catch { return -1; }
}
async function savePromptDismissedAt(n) {
  try { await _storage.set(PROMPT_DISMISSED_AT_K, String(n)); } catch {}
}
// Règle de déclenchement : on propose le compte quand lifetime >= 50 (ou 100, 150, ...)
// ET qu'on ne l'a pas déjà proposé à cette valeur ou au-dessus
function shouldShowAccountPrompt(lifetime, dismissedAt) {
  if (lifetime < ACCOUNT_PROMPT_FIRST) return false;
  // Seuil à franchir : le prochain multiple de 50 strictement supérieur à dismissedAt
  // Si jamais refusé (dismissedAt = -1), le seuil est 50
  const nextThreshold = dismissedAt < ACCOUNT_PROMPT_FIRST
    ? ACCOUNT_PROMPT_FIRST
    : Math.ceil((dismissedAt + 1) / ACCOUNT_PROMPT_STEP) * ACCOUNT_PROMPT_STEP;
  return lifetime >= nextThreshold;
}

// ── QState : suivi par question individuelle ────────────────────────────────
// Permet de savoir si l'élève maîtrise une question précise ou non.
// Clé par question : `${catId}:${subId}:${idxInSub}`
// Valeur : { status: "unknown"|"learning"|"mastered", streak, lastSeen, attempts, successes }
async function loadQState() {
  try { const r = await _storage.get(QSTATE_K); return r?.value ? JSON.parse(r.value) : {}; }
  catch { return {}; }
}
async function saveQState(state) {
  try { await _storage.set(QSTATE_K, JSON.stringify(state)); } catch {}
}
// Récupère le statut d'une question avec gestion du "refresh" après MASTERY_REFRESH_DAYS
function getQStatus(state, key) {
  const entry = state[key];
  if (!entry) return { status: "unknown", streak: 0, lastSeen: 0, attempts: 0, successes: 0 };
  // Si une question mastered est vue il y a longtemps, on la repasse en learning
  if (entry.status === "mastered" && entry.lastSeen &&
      (Date.now() - entry.lastSeen) > MASTERY_REFRESH_DAYS * 86400000) {
    return { ...entry, status: "learning", streak: 0 };
  }
  return entry;
}
// Met à jour le state pour une question après une tentative
function updateQStatus(state, key, correct) {
  const prev = getQStatus(state, key);
  const newAttempts = prev.attempts + 1;
  const newSuccesses = prev.successes + (correct ? 1 : 0);
  let newStreak, newStatus;
  if (correct) {
    newStreak = (prev.streak || 0) + 1;
    if (newStreak >= MASTERY_STREAK) newStatus = "mastered";
    else newStatus = "learning";
  } else {
    newStreak = 0;
    newStatus = "learning"; // on ne revient jamais à "unknown" une fois tenté
  }
  return {
    ...state,
    [key]: {
      status: newStatus,
      streak: newStreak,
      lastSeen: Date.now(),
      attempts: newAttempts,
      successes: newSuccesses,
    }
  };
}
// Génère la clé d'une question : on a besoin de l'index dans le tableau DB
function getQKey(catId, subId, question) {
  const arr = DB[catId]?.[subId] || [];
  const idx = arr.indexOf(question);
  if (idx < 0) return null;
  return `${catId}:${subId}:${idx}`;
}

// Trouve la clé d'une question en cherchant dans toute la DB (plus lent mais universel)
function findQKey(question) {
  for (const cId of Object.keys(DB)) {
    for (const sId of Object.keys(DB[cId])) {
      const arr = DB[cId][sId];
      if (!Array.isArray(arr)) continue;
      const idx = arr.indexOf(question);
      if (idx >= 0) return `${cId}:${sId}:${idx}`;
    }
  }
  return null;
}

// Sélection intelligente de n questions dans un pool, en fonction du qState.
// Priorités (dans l'ordre) :
//   1. learning (questions en cours d'apprentissage, échecs récents en priorité)
//   2. unknown (jamais vues)
//   3. mastered anciennes (>30 jours) — pour maintien
//   4. mastered récentes (évitées par défaut)
// Si n > pool disponible, on complète avec du shuffle.
function selectQuestionsSmart(pool, n, qStateSnapshot, avoidKeys = null) {
  if (!Array.isArray(pool) || pool.length === 0) return [];
  const learning = [];
  const unknown = [];
  const masteredOld = [];
  const masteredRecent = [];
  // IMPORTANT : on conserve l'index d'origine dans pool pour reconstruire une
  // progression douce (facile → difficile) dans l'ordre final de présentation.
  // On marque aussi chaque question comme "recent" (vue dans les N dernières)
  // pour la déprioriser au sein de sa catégorie.
  pool.forEach((q, origIdx) => {
    const key = findQKey(q);
    const isRecent = avoidKeys && key && avoidKeys.has(key);
    const entry = key ? getQStatus(qStateSnapshot || {}, key) : null;
    if (!entry || entry.status === "unknown") unknown.push({ q, origIdx, isRecent });
    else if (entry.status === "learning") learning.push({ q, origIdx, streak: entry.streak || 0, isRecent });
    else {
      const age = entry.lastSeen ? (Date.now() - entry.lastSeen) : Infinity;
      if (age > MASTERY_REFRESH_DAYS * 86400000) masteredOld.push({ q, origIdx, isRecent });
      else masteredRecent.push({ q, origIdx, isRecent });
    }
  });
  // Dans learning : prioriser les streak faibles (pas encore proches de la maîtrise)
  learning.sort((a, b) => a.streak - b.streak);
  // Helper : pour chaque groupe, on met les "non-recent" avant les "recent"
  // Ça permet de choisir d'abord des questions pas vues récemment, tout en
  // ne les excluant pas si on en a besoin pour atteindre n.
  const dedup = arr => {
    const nonRecent = shuffle(arr.filter(x => !x.isRecent));
    const recent = shuffle(arr.filter(x => x.isRecent));
    return [...nonRecent, ...recent];
  };
  const priority = [
    ...dedup(learning),
    ...dedup(unknown),
    ...dedup(masteredOld),
  ];
  let selected = priority.slice(0, n);
  if (selected.length < n) {
    const remaining = dedup(masteredRecent).slice(0, n - selected.length);
    selected = [...selected, ...remaining];
  }
  // ─── Progression douce : on trie par origIdx (croissant = facile → dur)
  // puis on introduit un léger désordre interne par zones pour éviter que
  // ce soit toujours strictement la même série. On découpe en 3 tiers,
  // chaque tiers est shuffle indépendamment, puis on concatène tier 1 + 2 + 3.
  // Résultat : les questions plus faciles restent au début, mais pas dans
  // le même ordre qu'une session précédente.
  selected.sort((a, b) => a.origIdx - b.origIdx);
  const third = Math.ceil(selected.length / 3);
  const t1 = shuffle(selected.slice(0, third));
  const t2 = shuffle(selected.slice(third, 2 * third));
  const t3 = shuffle(selected.slice(2 * third));
  return [...t1, ...t2, ...t3].map(x => x.q);
}

// ── Moteur de détection d'erreurs (feedback personnalisé) ───────────────────
// Analyse (bonneRéponse, réponseÉlève) et renvoie un message de feedback ciblé.
// Renvoie null si aucun pattern ne matche (on retombe alors sur le tip générique).

// Helper : parse un nombre simple (entier, décimal, signé) depuis un string
function tryParseNumber(s) {
  if (typeof s !== 'string') return null;
  const cleaned = s.trim().replace(',', '.').replace(/\s/g, '');
  // Rejet si ça contient autre chose qu'un nombre signé
  if (!/^-?\d+(\.\d+)?$/.test(cleaned)) return null;
  return parseFloat(cleaned);
}

// Helper : extraction d'une fraction a/b depuis un string type "3/4" ou "-3/4"
function tryParseFraction(s) {
  if (typeof s !== 'string') return null;
  const m = s.trim().match(/^(-?\d+)\s*\/\s*(-?\d+)$/);
  if (!m) return null;
  const num = parseInt(m[1]);
  const den = parseInt(m[2]);
  if (den === 0) return null;
  return { num, den, value: num / den };
}

// Helper : compare deux polynômes simples en comptant les occurrences de motifs clés
function polyInfo(tex) {
  if (typeof tex !== 'string') return null;
  // Détecte x^2, 2ab (terme du milieu), constante
  return {
    hasSquare: /x\^?\{?2\}?/.test(tex) || /x²/.test(tex),
    hasLinearX: /(^|[^\^])\d*x(?![\^\d])/.test(tex.replace(/x\^?\{?2\}?/g, '').replace(/x²/g, '')),
    raw: tex,
  };
}

// Liste des patterns — ordre d'importance (le 1er qui matche gagne)
const ERROR_PATTERNS = [
  // 1. Signe inversé (très fréquent)
  {
    name: 'sign_flip',
    detect: (correct, given) => {
      const a = tryParseNumber(correct), b = tryParseNumber(given);
      if (a === null || b === null) return false;
      if (a === 0 || b === 0) return false;
      return Math.abs(a + b) < 1e-9; // a = -b
    },
    message: "⚠️ Attention au signe. Le résultat est juste en valeur absolue, mais le signe est inversé.",
  },

  // 2. Double / moitié (erreur fréquente : confondre ab et 2ab)
  {
    name: 'double_value',
    detect: (correct, given) => {
      const a = tryParseNumber(correct), b = tryParseNumber(given);
      if (a === null || b === null || a === 0) return false;
      return Math.abs(b - 2 * a) < 1e-9;
    },
    message: "Tu as obtenu le double du résultat. Vérifie si tu n'as pas compté un terme deux fois.",
  },
  {
    name: 'half_value',
    detect: (correct, given) => {
      const a = tryParseNumber(correct), b = tryParseNumber(given);
      if (a === null || b === null || a === 0) return false;
      return Math.abs(b - a / 2) < 1e-9;
    },
    message: "Tu as la moitié du résultat. As-tu oublié un facteur 2 quelque part ?",
  },

  // 3. Fraction inversée
  {
    name: 'fraction_inverted',
    detect: (correct, given) => {
      const fa = tryParseFraction(correct), fb = tryParseFraction(given);
      if (!fa || !fb) return false;
      return fa.num === fb.den && fa.den === fb.num;
    },
    message: "Tu as inversé la fraction. Le numérateur et le dénominateur sont à permuter.",
  },

  // 4. Oubli du double produit dans (a+b)²
  //    Pattern : correct = x²+2kx+k², given = x²+k² (manque le terme en x)
  {
    name: 'missing_double_product',
    detect: (correct, given, q) => {
      if (typeof correct !== 'string' || typeof given !== 'string') return false;
      if (!q || !q.q || !/\(.+\)\^?\{?2\}?|\(.+\)²/.test(q.q)) return false; // question du type (…)²
      const pc = polyInfo(correct), pg = polyInfo(given);
      if (!pc || !pg) return false;
      // correct a un terme linéaire en x, given n'en a pas
      return pc.hasSquare && pc.hasLinearX && pg.hasSquare && !pg.hasLinearX;
    },
    message: "Tu as oublié le double produit. Rappel : (a+b)² = a² + 2ab + b² — pas seulement a² + b².",
  },

  // 5. Erreur de distributivité (oubli du signe négatif devant parenthèse)
  //    Détection heuristique : la bonne réponse et la donnée diffèrent par le signe d'un des termes
  //    Approximation simple : pour les questions contenant "−(" ou "-(", détection par différence numérique double
  {
    name: 'distributivity_sign',
    detect: (correct, given, q) => {
      if (!q || typeof q.q !== 'string') return false;
      if (!/-\s*\(/.test(q.q) && !/−\s*\(/.test(q.q)) return false;
      const a = tryParseNumber(correct), b = tryParseNumber(given);
      if (a === null || b === null) return false;
      // Si l'élève a "oublié" de distribuer le signe, la différence est souvent une valeur
      // correspondant à deux fois un terme ; heuristique faible
      return Math.abs(a - b) > 1e-9 && Math.abs(a) + Math.abs(b) > 0;
    },
    message: "Attention à la distribution du signe « − » devant la parenthèse. Chaque terme à l'intérieur change de signe.",
  },

  // 6. Racine vs carré (détecte si l'élève a élevé au carré au lieu de racine, ou l'inverse)
  {
    name: 'root_vs_square',
    detect: (correct, given, q) => {
      if (!q || typeof q.q !== 'string') return false;
      if (!/\\sqrt|√/.test(q.q)) return false;
      const a = tryParseNumber(correct), b = tryParseNumber(given);
      if (a === null || b === null || a <= 0) return false;
      return Math.abs(b - a * a) < 1e-9;
    },
    message: "Tu as élevé au carré au lieu de prendre la racine. √a, c'est le nombre dont le carré vaut a.",
  },

  // 7. Confusion multiplication / addition pour petites valeurs (tables)
  {
    name: 'mul_vs_add',
    detect: (correct, given, q) => {
      if (!q || typeof q.q !== 'string') return false;
      if (!/\\times|×/.test(q.q)) return false;
      // Extraire les deux facteurs de la question
      const m = q.q.match(/(\d+)\s*(?:\\times|×)\s*(\d+)/);
      if (!m) return false;
      const a = parseInt(m[1]), b = parseInt(m[2]);
      const g = tryParseNumber(given);
      if (g === null) return false;
      return g === a + b;
    },
    message: "Tu as additionné au lieu de multiplier. Ici c'est une multiplication.",
  },

  // 8. Puissance : a^n interprété comme a*n (erreur très classique)
  {
    name: 'power_vs_mult',
    detect: (correct, given, q) => {
      if (!q || typeof q.q !== 'string') return false;
      const m = q.q.match(/(\d+)\s*\^\s*\{?(\d+)\}?/);
      if (!m) return false;
      const a = parseInt(m[1]), n = parseInt(m[2]);
      const g = tryParseNumber(given);
      if (g === null) return false;
      return g === a * n;
    },
    message: "Attention : aⁿ ce n'est pas a × n, mais a multiplié par lui-même n fois. Par ex. 2³ = 2×2×2 = 8, pas 2×3 = 6.",
  },

  // 9. Unité / conversion oubliée (seulement pour les questions de conversion)
  {
    name: 'unit_shift',
    detect: (correct, given, q) => {
      if (!q || typeof q.q !== 'string') return false;
      // Restriction : uniquement pour les vraies questions de conversion d'unités
      // (présence d'unités classiques, pas de puissances)
      if (/\^/.test(q.q)) return false; // pas de puissance
      if (!/\b(km|hm|dam|cm|mm|dm|kg|hg|dag|dg|cg|mg|hl|dal|dl|cl|ml|°C|litre|gramme|mètre|convertis|conversion|heure|minute|seconde|\d+\s*[a-z])/.test(q.q)) return false;
      const a = tryParseNumber(correct), b = tryParseNumber(given);
      if (a === null || b === null || a === 0) return false;
      const ratios = [10, 100, 1000, 0.1, 0.01, 0.001];
      for (const r of ratios) {
        if (Math.abs(b - a * r) < 1e-9) return true;
      }
      return false;
    },
    message: "Le résultat est correct mais d'un facteur 10, 100 ou 1000 à côté. Vérifie la conversion d'unités ou le décalage de la virgule.",
  },
];

function detectErrorPattern(correct, given, question) {
  if (correct === given) return null;
  for (const p of ERROR_PATTERNS) {
    try {
      if (p.detect(correct, given, question)) return p.message;
    } catch { /* un pattern qui plante ne doit pas casser le quiz */ }
  }
  return null;
}

// ── Badge unlock helper ───────────────────────────────────────────────────────
async function checkAndUnlockBadge(badgeId, setBadgesState) {
  const current = await loadBadges();
  if(current.includes(badgeId)) return false;
  const updated = [...current, badgeId];
  await saveBadges(updated);
  if(setBadgesState) setBadgesState(updated);
  return true;
}

// ── Sigma messages contextuels ────────────────────────────────────────────────
function getSigmaMessage(profile, xp, badges, dailyDone) {
  const hour = new Date().getHours();
  const streak = profile.streak||0;
  const lvl = getXpLevel(xp);
  if(dailyDone) return ["🎯 Défi du jour complété ! Tu es au top aujourd'hui.","☀️ Défi du jour fait ! Sigma est fière de toi !"][Math.floor(Date.now()/86400000)%2];
  if(hour < 7)  return "🌙 Si tôt le matin ? Sigma admire ton courage !";
  if(hour >= 22) return "🦉 Tu travailles tard... Sigma veille sur toi !";
  if(streak >= 7) return `🔥 ${streak} jours d'affilée ! Tu es une machine !`;
  if(streak >= 3) return `🔥 ${streak} jours de suite ! Continue comme ça !`;
  if(xp === 0)  return "👋 Commence ton premier exercice, Sigma t'attend !";
  if(lvl.lvl >= 5) return `${lvl.emoji} Niveau ${lvl.label} ! Tu écrases tout !`;
  const msgs = [
    "💪 Chaque exercice te rapproche du bac !",
    "🧠 La régularité, c'est la clé du succès.",
    "⚡ 5 minutes par jour, et les maths deviennent tes amies.",
    `🌟 Encore ${(getNextLevel(xp) ? getNextLevel(xp).xpNeeded - xp : 0)} XP pour le niveau suivant !`,
    "🎯 Le défi du jour t'attend ci-dessous !",
  ];
  return msgs[Math.floor(Date.now()/3600000)%msgs.length];
}



