function QuizScreen({questions,catId,subId,quizMode,onFinish,onBack}) {
  const [idx,setIdx]           = useState(0);
  const [selected,setSelected] = useState(null);
  const [shown,setShown]       = useState(false);
  const [score,setScore]       = useState(0);
  const [streak,setStreak]     = useState(0);
  const [shake,setShake]       = useState(false);
  const [pad,setPad]           = useState("");
  const [padState,setPadState] = useState("idle");
  // Confirmation d'abandon (modale)
  const [showAbandon, setShowAbandon] = useState(false);
  // Rappel de cours (affiché uniquement en pratique/daily, si un rappel existe)
  const [showReminder, setShowReminder] = useState(false);
  const reminderAvailable = (quizMode === "practice" || quizMode === "daily") && !!getCourseReminder(catId, subId);
  // Track failed question indices for spaced repetition
  const failedIdx = React.useRef([]);
  // ── Tableau fill mode ──
  const [activeFill,setActiveFill] = useState(-1);
  const [fills,setFills]           = useState({});
  const [tabValidated,setTabValidated] = useState(false);
  const [dragDone,setDragDone]         = useState(false);
  const [dragCorrect,setDragCorrect]   = useState(false);

  const cat     = getCat(catId) || { id:catId, label:"En route pour le Bac", emoji:"🏆", color:"#F59E0B", grad:"linear-gradient(135deg,#F59E0B,#B45309)", light:"#FFFBEB", border:"#FDE68A", subs:[] };
  const q       = questions[idx];
  const isNum   = !!q.numpad;
  const isSol   = !!q.solpad;
  const isEq    = !!q.eqpad;
  const isExpr  = !!q.exprpad;
  const isFrac  = !!q.fractionpad;
  const isDrag  = !!q.dgspec;
  const spec    = q.tvSpec || q.tsSpec;
  const specType= q.tvSpec?"tv":q.tsSpec?"ts":null;
  const isTab   = !!spec;
  const hasVis  = !!(q.gspec || q.tspec || q.trespec);
  const choices = useCallback(()=>q.choices?shuffle(q.choices):[],[q])();

  // holes & correctness for tableau mode
  // On aplatit spec (rows + cells finaux) en un tableau global indexé linéairement.
  const flatCells = isTab ? (() => {
    if (specType === "ts" && Array.isArray(spec.rows) && spec.rows.length > 0) {
      const out = [];
      for (const r of spec.rows) out.push(...r.cells);
      out.push(...spec.cells);
      return out;
    }
    return spec.cells;
  })() : [];
  const holes      = isTab ? flatCells.reduce((a,c,i)=>c.hole?[...a,i]:a,[]) : [];
  const allFilled  = holes.every(i=>fills[i]!==undefined);
  const allCorrect = holes.every(i=>fills[i]===flatCells[i]?.v);

  // active cell kind
  const activeKind = activeFill>=0&&isTab ? flatCells[activeFill]?.kind : null;

  // Reset all state when question changes
  useEffect(()=>{
    setPad(""); setPadState("idle");
    setFills({}); setTabValidated(false); setDragDone(false); setDragCorrect(false);
    setSelected(null); setShown(false);
    if(q.tvSpec||q.tsSpec){
      const s=q.tvSpec||q.tsSpec;
      let flat = s.cells;
      if (q.tsSpec && Array.isArray(s.rows) && s.rows.length > 0) {
        flat = [];
        for (const r of s.rows) flat.push(...r.cells);
        flat.push(...s.cells);
      }
      const first=flat.findIndex(c=>c.hole);
      setActiveFill(first>=0?first:-1);
    } else { setActiveFill(-1); }
  },[idx]);

  // Fill a hole and auto-advance for arrow/sign pickers
  const fillHole=(i,val)=>{
    const nf={...fills,[i]:val};
    setFills(nf);
    if(flatCells[i]?.kind!=="num"){
      const next=flatCells.findIndex((c,j)=>j>i&&c.hole&&!nf[j]);
      setActiveFill(next>=0?next:-1);
    } else { setPad(""); }
  };

  // Validate tableau
  const validateTab=()=>{
    if(!allFilled||tabValidated) return;
    setTabValidated(true);
    if(allCorrect){setScore(s=>s+1);setStreak(s=>s+1);}
    else{setStreak(0);setShake(true);setTimeout(()=>setShake(false),420);}
  };

  // MCQ pick
  const pick=(c)=>{
    if(shown) return;
    setSelected(c);setShown(true);
    const ok=c===q.a;
    if(ok){setScore(s=>s+1);setStreak(s=>s+1);}
    else{setStreak(0);setShake(true);setTimeout(()=>setShake(false),420);}
  };

  // Numpad validate
  // Normalisation commutative des facteurs parenthésés
  const normFactor = s => {
    const clean = s.replace(/\s/g,'').toLowerCase();
    const parts=[]; let depth=0,cur='',hasP=false;
    for(let ch of clean){
      if(ch==='('){depth++;if(depth===1){hasP=true;continue;}}
      else if(ch===')'){depth--;if(depth===0){parts.push(cur);cur='';continue;}}
      if(depth>0) cur+=ch;
    }
    return hasP ? [...parts].sort().join('|') : clean;
  };

  const validatePad=(val)=>{
    if(padState!=="idle") return;
    const ok = normFactor(val) === normFactor(q.a);
    setPadState(ok?"correct":"wrong");
    if(ok){setScore(s=>s+1);setStreak(s=>s+1);}
    else{setStreak(0);setShake(true);setTimeout(()=>setShake(false),420);}
  };

  const nextQ=()=>{
    const isCorrectNow = isDrag?dragCorrect:(isNum||isSol||isEq||isExpr||isFrac)?padState==="correct":isTab?allCorrect:selected===q.a;
    if(!isCorrectNow) failedIdx.current = [...new Set([...failedIdx.current, idx])];
    // Le score a déjà été incrémenté par validateTab/pick/validatePad au moment de la
    // validation de la réponse. On ne le re-incrémente PAS ici, sinon la dernière
    // bonne réponse compterait double (bug du 110% : 11 sur 10 questions).
    if(idx+1>=questions.length){onFinish(score, failedIdx.current);return;}
    setIdx(i=>i+1);
  };

  const getState=c=>{
    if(!shown) return selected===c?"selected":"default";
    if(c===q.a) return "correct";
    if(c===selected) return "wrong";
    return "default";
  };

  const didAnswer  = isDrag?dragDone:(isNum||isSol||isEq||isExpr||isFrac)?padState!=="idle":isTab?tabValidated:shown;
  const wasCorrect = isDrag?dragCorrect:(isNum||isSol||isEq||isExpr||isFrac)?padState==="correct":isTab?allCorrect:selected===q.a;
  // Feedback personnalisé Tier 1 : détection automatique du type d'erreur
  // Actif uniquement pour les QCM (où on sait ce que l'élève a choisi)
  const personalizedFeedback = (!wasCorrect && !isDrag && !isNum && !isTab && !isSol && !isEq && !isExpr && !isFrac && shown && selected)
    ? detectErrorPattern(q.a, selected, q)
    : null;

  return (
    <div style={{display:"flex",flexDirection:"column",minHeight:"100%",padding:"16px 16px 14px",position:"relative"}}>
      {/* Modal rappel de cours */}
      {showReminder && reminderAvailable && (
        <CourseReminderModal catId={catId} subId={subId} onClose={()=>setShowReminder(false)}/>
      )}
      {/* Header */}
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14,flexShrink:0}}>
        <button onClick={() => {
          // Si l'élève a déjà validé au moins 1 réponse (score > 0) ou avancé d'une
          // question (idx > 0), on demande confirmation : les réponses partielles ne
          // sont pas sauvegardées, autant l'avertir de la perte.
          if (idx > 0 || score > 0) setShowAbandon(true);
          else onBack();
        }} style={{background:"none",border:"none",cursor:"pointer",color:"#94A3B8",fontSize:18,padding:0,flexShrink:0}}>✕</button>
        <div style={{flex:1,background:"#E2E8F0",borderRadius:99,height:9,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${(idx/questions.length)*100}%`,background:cat.color,borderRadius:99,transition:"width .4s ease"}}/>
        </div>
        {reminderAvailable && (
          <button onClick={()=>setShowReminder(true)}
            title="Voir le rappel de cours"
            style={{background:"#EFF6FF",border:"1.5px solid #BFDBFE",borderRadius:99,
              padding:"3px 10px",fontSize:13,cursor:"pointer",color:"#1D4ED8",
              fontWeight:700,display:"flex",alignItems:"center",gap:3,flexShrink:0}}>
            📘
          </button>
        )}
        <div style={{background:"#FEF3C7",color:"#92400E",borderRadius:99,padding:"3px 9px",fontSize:11,fontWeight:700}}>🔥{streak}</div>
        <div style={{background:cat.light,color:cat.color,borderRadius:99,padding:"3px 9px",fontSize:11,fontWeight:700,border:`1px solid ${cat.border}`}}>{idx+1}/{questions.length}</div>
      </div>

      {/* Tag */}
      <div style={{display:"inline-flex",alignItems:"center",gap:5,background:cat.light,color:cat.color,borderRadius:99,padding:"4px 12px",fontSize:11,fontWeight:700,marginBottom:14,alignSelf:"flex-start",border:`1.5px solid ${cat.border}`,flexShrink:0}}>
        {cat.emoji} {cat.label}
      </div>

      {/* ── DragGraph exercise (full replacement) ── */}
      {isDrag && (
        <DragGraph spec={q.dgspec} onConclude={(ok)=>{
          setDragDone(true); setDragCorrect(ok);
          if(ok){setScore(s=>s+1);setStreak(s=>s+1);}
          else{setStreak(0);setShake(true);setTimeout(()=>setShake(false),420);}
        }}/>
      )}

      {/* Question card (all non-drag questions) */}
      {!isDrag && <div className={shake?"shake":""} style={{
        background:(isNum||isSol||isExpr||isFrac)?"linear-gradient(135deg,#7C3AED,#5B21B6)":"var(--am-bg-light)",
        borderRadius:18,
        padding: isNum && !q.gspec ? "18px" : hasVis||isTab||isSol||isFrac ? "12px" : "16px",
        marginBottom:isTab?10:14, boxShadow:"0 3px 12px rgba(0,0,0,.08)",
        border:"none", flexShrink:0,
        width:"100%", boxSizing:"border-box",
      }}>
        {q.gspec   && <div style={{marginBottom:8}}><Graph spec={q.gspec}/></div>}
        {q.trespec && <div style={{marginBottom:10}}><ProbaTree spec={q.trespec}/></div>}
        {q.tspec   && <ProbaTable spec={q.tspec}/>}
        <div style={{
          fontSize: isNum && !q.gspec
            ? (q.q.length > 60 ? 14 : q.q.length > 40 ? 16 : q.q.length > 20 ? 21 : 38)
            : (isNum||isSol) && q.gspec ? 16
            : isSol ? 19
            : hasVis||isTab ? 14
            : q.q.length > 80 ? 14
            : q.q.length > 50 ? 16
            : q.q.length > 25 ? 17
            : 19,
          fontWeight:700, lineHeight:1.5, textAlign:"center",
          color:(isNum||isSol||isExpr||isFrac)?"#fff":"#1E293B",
          fontFamily:(isNum||isSol||isExpr||isFrac)?"'Nunito',sans-serif":"'DM Sans',sans-serif",
          padding: isNum && q.gspec ? "4px 0 2px" : 0,
          maxWidth:"100%", overflow:"hidden",
        }}>
          <M tex={q.q}/>
        </div>
        {isNum&&<div style={{textAlign:"center",marginTop:4,opacity:.7,fontSize:11,color:"#E0D9FF"}}>Tape ta réponse ↓</div>}
        {isSol&&<div style={{textAlign:"center",marginTop:4,opacity:.7,fontSize:11,color:"#E0D9FF"}}>Tape l'ensemble solution ↓</div>}
        {isEq &&<div style={{textAlign:"center",marginTop:4,opacity:.7,fontSize:11,color:"#E0D9FF"}}>Tape S={"{...}"} ↓</div>}
      </div>}

      {/* ── TABLEAU GRIDS ── */}
      {isTab && specType==="tv" && (
        <TableauVarGrid spec={spec} activeFill={activeFill} fills={fills}
          validated={tabValidated} onCellClick={i=>!tabValidated&&setActiveFill(i)}/>
      )}
      {isTab && specType==="ts" && (
        <TableauSignGrid spec={spec} activeFill={activeFill} fills={fills}
          validated={tabValidated} onCellClick={i=>!tabValidated&&setActiveFill(i)}/>
      )}

      {/* ── TABLEAU INPUT HINT ── */}
      {isTab && !tabValidated && activeFill>=0 && (
        <div style={{background:"#EFF6FF",borderRadius:10,padding:"5px 12px",
          fontSize:11,color:"#1D4ED8",fontWeight:700,marginBottom:8,flexShrink:0}}>
          {activeKind==="arrow"?"↗↘ Choisis le sens de variation :"
          :activeKind==="sign" ?"+ − Signe de f dans cet intervalle :"
          :"🔢 Tape la valeur :"}
        </div>
      )}

      {/* ── ARROW PICKER ── */}
      {isTab && !tabValidated && activeKind==="arrow" && (
        <ArrowPicker onPick={v=>fillHole(activeFill,v)}/>
      )}

      {/* ── SIGN PICKER ── */}
      {isTab && !tabValidated && activeKind==="sign" && (
        <SignPicker onPick={v=>fillHole(activeFill,v)}/>
      )}

      {/* ── TABLEAU NUMPAD ── */}
      {isTab && !tabValidated && activeKind==="num" && (
        <TNumPad value={pad} onChange={setPad}
          onValidate={v=>{ fillHole(activeFill,v); setPad(""); }}/>
      )}

      {/* ── VALIDATE BUTTON (tableau, all holes filled) ── */}
      {isTab && !tabValidated && allFilled && activeKind!=="num" && (
        <button onClick={validateTab} className="pop-in" style={{
          marginTop:4,border:"none",borderRadius:12,padding:"13px",
          background:"linear-gradient(135deg,#F59E0B,#D97706)",
          color:"#fff",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:800,
          cursor:"pointer",boxShadow:"0 5px 15px rgba(245,158,11,.35)",flexShrink:0
        }}>Vérifier le tableau ✓</button>
      )}

      {/* ── MCQ choices ── */}
      {!isDrag && !isNum && !isTab && !isSol && !isEq && !isExpr && !isFrac && (
        <div style={{display:"flex",flexDirection:"column",gap:10,flexShrink:0}}>
          {choices.map((c,i)=><Btn key={i} tex={c} state={getState(c)} onClick={shown?undefined:()=>pick(c)}/>)}
        </div>
      )}

      {/* ── Numpad ── */}
      {isNum && (
        <NumPad value={pad} onChange={setPad} onValidate={validatePad}
          state={padState} correctAnswer={q.a}/>
      )}

      {/* ── EqPad ── */}
      {isEq && (
        <EqPad value={pad} onChange={setPad} onValidate={validatePad}
          state={padState} correctAnswer={q.a}/>
      )}

      {/* ── SolPad ── */}
      {isSol && (
        <SolPad value={pad} onChange={setPad} onValidate={validatePad}
          state={padState} correctAnswer={q.a}/>
      )}

      {/* ── ExprPad (développement identités remarquables) ── */}
      {isExpr && (
        <ExprPad key={idx} correct={q.a} 
          altAnswers={q.altAnswers||[]} 
          partialAnswers={q.partialAnswers||[]}
          extraBtn={q.extraBtn||null} extraBtns={q.extraBtns||[]}
          state={padState}
          onValidate={(result)=>{
            setPadState(result);
            if(result==="correct"){setScore(s=>s+1);setStreak(s=>s+1);}
            else if(result==="wrong"){setStreak(0);setShake(true);setTimeout(()=>setShake(false),420);}
            else if(result==="partial"){
              // After showing the partial feedback for 2s, reset to idle to allow retry
              setTimeout(()=>setPadState("idle"), 2000);
            }
          }}/>
      )}

      {/* ── FractionPad (mise au même dénominateur) ── */}
      {isFrac && (
        <FractionPad key={idx} correct={q.a}
          altAnswers={q.altAnswers||[]}
          partialAnswers={q.partialAnswers||[]}
          state={padState}
          onValidate={(result)=>{
            setPadState(result);
            if(result==="correct"){setScore(s=>s+1);setStreak(s=>s+1);}
            else if(result==="wrong"){setStreak(0);setShake(true);setTimeout(()=>setShake(false),420);}
            else if(result==="partial"){
              setTimeout(()=>setPadState("idle"), 2000);
            }
          }}/>
      )}

      {/* ── FEEDBACK MCQ ── */}
      {!isDrag && !isNum && !isTab && !isSol && !isEq && !isExpr && !isFrac && shown && (
        <div className="fade-in" style={{marginTop:14,
          background:wasCorrect?"#ECFDF5":"#FEF2F2",
          border:`2.5px solid ${wasCorrect?"#10B981":"#EF4444"}`,
          borderRadius:16,padding:"13px 15px",flexShrink:0}}>
          <div style={{fontWeight:800,fontSize:13,marginBottom:wasCorrect&&!q.tip?0:6,
            color:wasCorrect?"#065F46":"#991B1B",
            display:"flex",alignItems:"center",gap:6}}>
            {wasCorrect ? "✅ Exact !" : (
              <span style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                ❌ La bonne réponse : <M tex={q.a}/>
              </span>
            )}
          </div>
          {/* Feedback personnalisé Tier 1 — message contextuel sur l'erreur type */}
          {personalizedFeedback && (
            <div style={{
              background:"#FEF3C7", borderRadius:10, padding:"9px 12px",
              borderLeft:"3px solid #F59E0B", marginBottom: q.tip ? 7 : 0
            }}>
              <div style={{fontSize:9, fontWeight:700, color:"#92400E",
                textTransform:"uppercase", letterSpacing:0.8, marginBottom:4}}>
                Sigma a repéré
              </div>
              <div style={{fontSize:12, color:"#78350F", lineHeight:1.5}}>
                {personalizedFeedback}
              </div>
            </div>
          )}
          {q.tip && (
            <div style={{
              background:wasCorrect?"rgba(16,185,129,0.08)":"rgba(239,68,68,0.06)",
              borderRadius:10,padding:"8px 11px",
              borderLeft:`3px solid ${wasCorrect?"#10B981":"#EF4444"}`}}>
              <div style={{fontSize:9,fontWeight:700,color:"#94A3B8",
                textTransform:"uppercase",letterSpacing:0.8,marginBottom:5}}>
                {wasCorrect?"Méthode":"Rappel — pourquoi ?"}
              </div>
              <div style={{fontSize:12,color:"#475569"}}>
                <M tex={q.tip}/>
              </div>
              {!wasCorrect && parseTrigoAngle(q.q)!==null && <MiniTrigoFeedback qTex={q.q}/>}
            </div>
          )}
        </div>
      )}

      {/* ── FEEDBACK numpad / solpad ── */}
      {(isNum||isSol) && padState!=="idle" && (
        <div className="fade-in" style={{marginTop:14,background:wasCorrect?"#ECFDF5":"#FEF2F2",
          border:`2.5px solid ${wasCorrect?"#10B981":"#EF4444"}`,borderRadius:16,
          padding:"13px 15px",flexShrink:0}}>
          <div style={{fontWeight:800,fontSize:13,
            color:wasCorrect?"#065F46":"#991B1B",marginBottom:q.tip?7:0}}>
            {wasCorrect ? `✅ Exact ! Réponse : ${q.a}` : `❌ La bonne réponse est ${q.a}`}
          </div>
          {q.tip && (
            <div style={{
              background:wasCorrect?"rgba(16,185,129,0.08)":"rgba(239,68,68,0.06)",
              borderRadius:10,padding:"8px 11px",
              borderLeft:`3px solid ${wasCorrect?"#10B981":"#EF4444"}`}}>
              <div style={{fontSize:9,fontWeight:700,color:"#94A3B8",
                textTransform:"uppercase",letterSpacing:0.8,marginBottom:5}}>
                {wasCorrect?"Méthode":"Rappel — pourquoi ?"}
              </div>
              <div style={{fontSize:12,color:"#475569"}}>
                <M tex={q.tip}/>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── FEEDBACK eqpad ── */}
      {isEq && padState!=="idle" && (
        <div className="fade-in" style={{marginTop:14,background:wasCorrect?"#ECFDF5":"#FEF2F2",border:`2.5px solid ${wasCorrect?"#10B981":"#EF4444"}`,borderRadius:14,padding:"12px 14px",flexShrink:0}}>
          <div style={{fontWeight:700,fontSize:13,color:wasCorrect?"#065F46":"#991B1B"}}>
            {wasCorrect ? `✅ Bravo ! S=${q.a}` : `❌ La réponse était S=${q.a}`}
          </div>
          <div style={{color:"#475569",fontSize:11,marginTop:4}}>💡 <M tex={q.tip}/></div>
        </div>
      )}

      {/* ── FEEDBACK exprpad ── */}
      {isExpr && padState!=="idle" && (
        <div className="fade-in" style={{marginTop:14,
          background:wasCorrect?"#ECFDF5":padState==="partial"?"#FEF9C3":"#FEF2F2",
          border:`2.5px solid ${wasCorrect?"#10B981":padState==="partial"?"#F59E0B":"#EF4444"}`,
          borderRadius:16,padding:"13px 15px",flexShrink:0}}>
          {wasCorrect ? (
            <div style={{fontWeight:800,fontSize:13,color:"#065F46"}}>✅ Bravo ! <M tex={q.tip||q.a}/></div>
          ) : padState==="partial" ? (
            <>
              <div style={{fontWeight:800,fontSize:12,color:"#92400E",marginBottom:5}}>
                ⚠️ C'est bon mais tu peux encore simplifier !
              </div>
              <div style={{background:"#fff",borderRadius:8,padding:"7px 10px",fontSize:11,color:"#475569"}}>
                💡 Continue à simplifier le numérateur
              </div>
            </>
          ) : (
            <>
              <div style={{fontWeight:800,fontSize:12,color:"#991B1B",marginBottom:5}}>
                ❌ La bonne réponse : <M tex={q.a}/>
              </div>
              <div style={{background:"#fff",borderRadius:8,padding:"7px 10px",fontSize:11,color:"#475569"}}>
                💡 <M tex={q.tip}/>
              </div>
            </>
          )}
        </div>
      )}

      {/* ── FEEDBACK fractionpad ── */}
      {isFrac && padState!=="idle" && (
        <div className="fade-in" style={{marginTop:14,
          background:wasCorrect?"#ECFDF5":padState==="partial"?"#FEF9C3":"#FEF2F2",
          border:`2.5px solid ${wasCorrect?"#10B981":padState==="partial"?"#F59E0B":"#EF4444"}`,
          borderRadius:16,padding:"13px 15px",flexShrink:0}}>
          {wasCorrect ? (
            <div style={{fontWeight:800,fontSize:13,color:"#065F46"}}>✅ Bravo ! <M tex={q.tip||q.a}/></div>
          ) : padState==="partial" ? (
            <>
              <div style={{fontWeight:800,fontSize:13,color:"#92400E",marginBottom:6}}>
                ⚠️ C'est bon mais tu peux encore simplifier !
              </div>
              <div style={{background:"#fff",borderRadius:10,padding:"8px 11px",fontSize:11,color:"#475569"}}>
                💡 Continue à simplifier le numérateur
              </div>
            </>
          ) : (
            <>
              <div style={{fontWeight:800,fontSize:13,color:"#991B1B",marginBottom:6}}>
                ❌ La bonne réponse : <M tex={q.a}/>
              </div>
              <div style={{background:"#fff",borderRadius:10,padding:"8px 11px",fontSize:11,color:"#475569"}}>
                💡 <M tex={q.tip}/>
              </div>
            </>
          )}
        </div>
      )}

      {/* ── FEEDBACK tableau ── */}
      {isTab && tabValidated && (
        <div className="fade-in" style={{marginTop:6,background:wasCorrect?"#ECFDF5":"#FEF2F2",border:`2px solid ${wasCorrect?"#10B981":"#EF4444"}`,borderRadius:12,padding:"10px 12px",flexShrink:0}}>
          <div style={{fontWeight:700,fontSize:12,marginBottom:3,color:wasCorrect?"#065F46":"#991B1B"}}>
            {wasCorrect?"✅ Tableau parfait !":"❌ Erreurs — les corrections s'affichent dans le tableau"}
          </div>
          <div style={{color:"#475569",fontSize:11}}>💡 <M tex={q.tip}/></div>
        </div>
      )}

      {/* ── NEXT BUTTON ── */}
      {didAnswer && (
        <button onClick={nextQ} className="pop-in" style={{marginTop:14,border:"none",borderRadius:14,padding:"15px",background:wasCorrect?"linear-gradient(135deg,#10B981,#059669)":"linear-gradient(135deg,#3B82F6,#1D4ED8)",color:"#fff",fontFamily:"'Nunito',sans-serif",fontSize:15,fontWeight:800,cursor:"pointer",boxShadow:wasCorrect?"0 5px 18px rgba(16,185,129,.4)":"0 5px 18px rgba(37,99,235,.4)",flexShrink:0}}>
          {idx+1>=questions.length?"Voir les résultats 🏆":"Suivante →"}
        </button>
      )}

      {/* ── ABANDON CONFIRMATION MODAL ── */}
      {showAbandon && (
        <div onClick={() => setShowAbandon(false)} style={{
          position:"fixed",inset:0,background:"rgba(15,23,42,0.55)",
          display:"flex",alignItems:"center",justifyContent:"center",
          zIndex:1000,padding:"20px"
        }}>
          <div onClick={(e) => e.stopPropagation()} className="pop-in" style={{
            background:"#fff",borderRadius:18,padding:"22px 22px 18px",
            maxWidth:340,width:"100%",boxShadow:"0 14px 40px rgba(0,0,0,0.25)",
            display:"flex",flexDirection:"column",gap:12
          }}>
            <div style={{fontFamily:"'Nunito',sans-serif",fontSize:18,fontWeight:900,color:"#1E293B"}}>
              Quitter le quiz ?
            </div>
            <div style={{color:"#475569",fontSize:13,lineHeight:1.5}}>
              Tu as déjà répondu à <strong>{idx + (score > 0 || padState !== "idle" || tabValidated ? 1 : 0)}</strong> question{idx >= 1 ? "s" : ""}.
              Si tu sors maintenant, <strong>tes réponses ne seront pas comptées</strong> :
              ni dans ton XP, ni dans ton suivi.
            </div>
            <div style={{display:"flex",gap:8,marginTop:6}}>
              <button onClick={() => setShowAbandon(false)} style={{
                flex:1,border:"1.5px solid #E2E8F0",background:"#fff",
                borderRadius:12,padding:"12px",fontFamily:"'Nunito',sans-serif",
                fontSize:13,fontWeight:800,color:"#475569",cursor:"pointer"
              }}>
                Continuer le quiz
              </button>
              <button onClick={() => { setShowAbandon(false); onBack(); }} style={{
                flex:1,border:"none",
                background:"linear-gradient(135deg,#EF4444,#DC2626)",
                borderRadius:12,padding:"12px",fontFamily:"'Nunito',sans-serif",
                fontSize:13,fontWeight:800,color:"#fff",cursor:"pointer",
                boxShadow:"0 4px 12px rgba(239,68,68,0.3)"
              }}>
                Quitter
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}


// ── Sigma SVG components ───────────────────────────────────────────────────────
// ── Sigma emotion component ───────────────────────────────────────────────────
const SIGMA_EMOTIONS = {
  happy:     SIGMA_IMG,
  cool:      SIGMA_COOL,
  love:      SIGMA_LOVE,
  sad:       SIGMA_SAD,
  error:     SIGMA_ERROR,
  thinking:  SIGMA_THINKING,
  sleepy:    SIGMA_SLEEPY,
  surprised: SIGMA_SURPRISED,
};
function Sigma({emotion="happy", size=80, float=false, className=""}) {
  const src = SIGMA_EMOTIONS[emotion] || SIGMA_IMG;
  return (
    <img src={src} alt={`Sigma ${emotion}`}
      className={float ? "sigma-float" + (className?" "+className:"") : className}
      style={{width:size,height:size,objectFit:"contain",display:"block",
        filter:"drop-shadow(0 4px 12px rgba(0,0,0,0.25))"}}/>
  );
}
function SigmaHappy({size=80}) { return <Sigma emotion="happy" size={size}/>; }
function SigmaSad({size=80})   { return <Sigma emotion="sad"   size={size}/>; }

// ── Sigma Légendaire — score parfait au bac ───────────────────────────────
function SigmaLegendaire({size=110}) {
  return (
    <img src={SIGMA_LEGENDAIRE} alt="Sigma Légendaire"
      className="sigma-gold"
      style={{width:size,height:size,objectFit:"contain",display:"block"}}/>
  );
}

function ResultScreen({score,total,catId,onReplay,onHome,streakJustCompleted=false,streakCount=0}) {
  const s=starsFor(score,total);
  const pct=Math.round((score/total)*100);
  const cat=getCat(catId)||{label:"",emoji:"🎯",color:"#3B82F6",grad:"linear-gradient(135deg,#3B82F6,#1D4ED8)",light:"#EFF6FF",border:"#BFDBFE"};

  const isBac = catId === "bac";
  const emotion = (pct===100 && isBac) ? "legendaire"
                : pct===100 ? "love"
                : pct>=80 ? "cool"
                : pct>=60 ? "happy"
                : pct>=40 ? "sad"
                : "error";
  const msgs = {
    legendaire:"🏆 LÉGENDAIRE ! Score parfait au bac ! Sigma est aux anges 👑",
    love:  "Score parfait ! Sigma est aux anges 💖",
    cool:  "Excellent travail ! Sigma est impressionnée 😎",
    happy: "Bien joué ! Sigma est fière de toi 🧡",
    sad:   "Pas mal, mais on peut faire mieux 💪",
    error: "Aïe... Sigma croit en toi, relance ! 💙",
  };
  const msgBg = {
    love:"#FFF0F6", cool:"#F0F9FF", happy:"#FEF3C7", sad:"#EFF6FF", error:"#FEF2F2"
  };
  const msgColor = {
    love:"#9D174D", cool:"#0369A1", happy:"#92400E", sad:"#1D4ED8", error:"#991B1B"
  };

  return (
    <div className="slide-up" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"22px 22px",height:"100%",gap:10}}>

      {/* Sigma mascot + ombre */}
      <div style={{display:"flex",flexDirection:"column",alignItems:"center"}}>
        <div className={emotion==="legendaire"?"":"sigma-float"}>
          {emotion==="legendaire"
            ? <SigmaLegendaire size={180}/>
            : <Sigma emotion={emotion} size={180} float={false}/>}
        </div>
        {emotion!=="legendaire" && <div className="sigma-shadow" style={{width:"55%",marginTop:-4}}/>}
      </div>

      {/* Stars */}
      <div style={{display:"flex",gap:8}}>
        {[1,2,3].map(n=><div key={n} className="pop-in" style={{fontSize:32,animationDelay:`${n*.1}s`,filter:n<=s?"none":"grayscale(1) opacity(.25)"}}>⭐</div>)}
      </div>

      {/* Score */}
      <div style={{textAlign:"center"}}>
        <div style={{fontFamily:"'Nunito',sans-serif",fontSize:48,fontWeight:900,color:cat.color,lineHeight:1}}>{score}/{total}</div>
        <div style={{color:"#64748B",fontSize:14,marginTop:3}}>{pct}% de réussite</div>
      </div>

      {/* Sigma message */}
      <div style={{background:msgBg[emotion],borderRadius:14,padding:"10px 16px",
        textAlign:"center",fontSize:13,fontWeight:700,
        color:msgColor[emotion],maxWidth:280}}>
        {msgs[emotion]}
      </div>

      {/* Badges */}
      <div style={{display:"flex",gap:7,flexWrap:"wrap",justifyContent:"center"}}>
        {score===total&&<span style={{background:"#FEF9C3",color:"#854D0E",borderRadius:99,padding:"4px 12px",fontSize:12,fontWeight:700}}>🎯 Score parfait !</span>}
        {score>=Math.ceil(total*.8)&&score<total&&<span style={{background:"#ECFDF5",color:"#065F46",borderRadius:99,padding:"4px 12px",fontSize:12,fontWeight:700}}>🔥 Excellent !</span>}
        {score<Math.ceil(total*.5)&&<span style={{background:"#FEF2F2",color:"#991B1B",borderRadius:99,padding:"4px 12px",fontSize:12,fontWeight:700}}>💪 À refaire !</span>}
      </div>

      {/* Streak validée — bandeau de célébration */}
      {streakJustCompleted && (
        <div className="pop-in" style={{
          background:"linear-gradient(135deg,#F59E0B,#EA580C)",
          borderRadius:14, padding:"12px 16px", maxWidth:320,
          display:"flex", alignItems:"center", gap:12,
          boxShadow:"0 4px 14px rgba(234,88,12,.35)"
        }}>
          <div style={{fontSize:32}}>🔥</div>
          <div style={{textAlign:"left"}}>
            <div style={{fontFamily:"'Nunito',sans-serif", fontWeight:900,
              fontSize:15, color:"#fff", lineHeight:1.2}}>
              {streakCount === 1 ? "Série démarrée !" : `Série à ${streakCount} jours !`}
            </div>
            <div style={{color:"rgba(255,255,255,.9)", fontSize:11,
              fontWeight:600, marginTop:2}}>
              Journée validée · Reviens demain pour continuer
            </div>
          </div>
        </div>
      )}

      {/* Buttons */}
      <div style={{display:"flex",flexDirection:"column",gap:9,width:"100%"}}>
        <button onClick={onReplay} style={{background:cat.grad,color:"#fff",border:"none",borderRadius:13,padding:"14px",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:800,cursor:"pointer",boxShadow:`0 5px 16px ${cat.color}44`}}>🔄 Rejouer</button>
        <button onClick={onHome}  style={{background:"#F1F5F9",color:"#475569",border:"none",borderRadius:13,padding:"14px",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:700,cursor:"pointer"}}>🏠 Menu principal</button>
      </div>
    </div>
  );
}

// ── Root ───────────────────────────────────────────────────────────────────────

// ════════════════════════════════════════════════════════════════════════════
// ── CERCLE TRIGONOMÉTRIQUE ── composant auto-contenu ────────────────────────
// ════════════════════════════════════════════════════════════════════════════
const PI_TRIGO = Math.PI;
const r_trigo = String.raw;

const TRIGO_POS = {
  p0:   { color:"#2563EB", cos:r_trigo`1`,                    sin:r_trigo`0`,                    cosS:"1",       sinS:"0"      },
  p16:  { color:"#DC2626", cos:r_trigo`\tfrac{\sqrt{3}}{2}`,  sin:r_trigo`\tfrac{1}{2}`,         cosS:"\u221a3/2",sinS:"1/2"   },
  p14:  { color:"#16A34A", cos:r_trigo`\tfrac{\sqrt{2}}{2}`,  sin:r_trigo`\tfrac{\sqrt{2}}{2}`,  cosS:"\u221a2/2",sinS:"\u221a2/2"},
  p13:  { color:"#DC2626", cos:r_trigo`\tfrac{1}{2}`,         sin:r_trigo`\tfrac{\sqrt{3}}{2}`,  cosS:"1/2",     sinS:"\u221a3/2"},
  p12:  { color:"#2563EB", cos:r_trigo`0`,                    sin:r_trigo`1`,                    cosS:"0",       sinS:"1"      },
  p23:  { color:"#DC2626", cos:r_trigo`-\tfrac{1}{2}`,        sin:r_trigo`\tfrac{\sqrt{3}}{2}`,  cosS:"-1/2",    sinS:"\u221a3/2"},
  p34:  { color:"#16A34A", cos:r_trigo`-\tfrac{\sqrt{2}}{2}`, sin:r_trigo`\tfrac{\sqrt{2}}{2}`,  cosS:"-\u221a2/2",sinS:"\u221a2/2"},
  p56:  { color:"#DC2626", cos:r_trigo`-\tfrac{\sqrt{3}}{2}`, sin:r_trigo`\tfrac{1}{2}`,         cosS:"-\u221a3/2",sinS:"1/2"  },
  p1:   { color:"#2563EB", cos:r_trigo`-1`,                   sin:r_trigo`0`,                    cosS:"-1",      sinS:"0"      },
  p76:  { color:"#DC2626", cos:r_trigo`-\tfrac{\sqrt{3}}{2}`, sin:r_trigo`-\tfrac{1}{2}`,        cosS:"-\u221a3/2",sinS:"-1/2" },
  p54:  { color:"#16A34A", cos:r_trigo`-\tfrac{\sqrt{2}}{2}`, sin:r_trigo`-\tfrac{\sqrt{2}}{2}`, cosS:"-\u221a2/2",sinS:"-\u221a2/2"},
  p43:  { color:"#DC2626", cos:r_trigo`-\tfrac{1}{2}`,        sin:r_trigo`-\tfrac{\sqrt{3}}{2}`, cosS:"-1/2",    sinS:"-\u221a3/2"},
  p32:  { color:"#2563EB", cos:r_trigo`0`,                    sin:r_trigo`-1`,                   cosS:"0",       sinS:"-1"     },
  p53:  { color:"#DC2626", cos:r_trigo`\tfrac{1}{2}`,         sin:r_trigo`-\tfrac{\sqrt{3}}{2}`, cosS:"1/2",     sinS:"-\u221a3/2"},
  p74:  { color:"#16A34A", cos:r_trigo`\tfrac{\sqrt{2}}{2}`,  sin:r_trigo`-\tfrac{\sqrt{2}}{2}`, cosS:"\u221a2/2",sinS:"-\u221a2/2"},
  p116: { color:"#DC2626", cos:r_trigo`\tfrac{\sqrt{3}}{2}`,  sin:r_trigo`-\tfrac{1}{2}`,        cosS:"\u221a3/2",sinS:"-1/2"  },
};

const mkt = (dtex, angle, pk, rtex) => ({ displayTex:dtex, angle, reductionTex:rtex||null, ...TRIGO_POS[pk] });

