const TRIGO_LEVELS = [
  { id:1, label:"Niveau 1", sub:"Angles de base du cercle trigonom\u00e9trique", color:"#2563EB", emoji:"\uD83D\uDD35", questions:TRIGO_L1 },
  { id:2, label:"Niveau 2", sub:"Angles positifs et n\u00e9gatifs",              color:"#DC2626", emoji:"\uD83D\uDD34", questions:TRIGO_L2 },
  { id:3, label:"Niveau 3", sub:"Grands angles",                                 color:"#7C3AED", emoji:"\uD83D\uDFE3", questions:TRIGO_L3 },
];

const TRIGO_TOL = 16 * Math.PI / 180;
const CX_T = 155, CY_T = 155, R_T = 128;
const pxT = a => CX_T + R_T * Math.cos(a);
const pyT = a => CY_T - R_T * Math.sin(a);

// Parse un angle en radians depuis le tex d'une question valeurs_trigo
function parseTrigoAngle(qTex) {
  if (!qTex) return null;
  // Match \dfrac{Npi}{D} ou \dfrac{pi}{D}
  const m = qTex.match(/frac\{(\d*)\\?pi\}\{(\d+)\}/);
  if (m) { const n = m[1] ? parseInt(m[1]) : 1; return (n * Math.PI) / parseInt(m[2]); }
  // Match pi seul
  if (/\(\\pi\)/.test(qTex) || /\\pi\)/.test(qTex)) return Math.PI;
  return null;
}

// Mini cercle trigo pour le feedback des questions valeurs_trigo
function MiniTrigoFeedback({ qTex }) {
  const angle = parseTrigoAngle(qTex);
  if (angle === null) return null;
  const cx=80, cy=80, r=60;
  const px = cx + r * Math.cos(angle);
  const py = cy - r * Math.sin(angle);
  const cosX = px, sinY = py;
  return (
    <svg viewBox="0 0 160 160" width="100%" style={{maxWidth:180,display:"block",margin:"8px auto 0"}}>
      <rect width="160" height="160" fill="#F8FAFC" rx="10"/>
      <line x1="10" y1={cy} x2="150" y2={cy} stroke="#CBD5E1" strokeWidth="1"/>
      <line x1={cx} y1="10" x2={cx} y2="150" stroke="#CBD5E1" strokeWidth="1"/>
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#EF4444" strokeWidth="1.5"/>
      <path d={`M${cx+16},${cy} A16,16 0 ${angle>Math.PI?1:0},0 ${cx+16*Math.cos(angle)},${cy-16*Math.sin(angle)}`} fill="none" stroke="#7C3AED" strokeWidth="1.5" opacity="0.7"/>
      <line x1={cx} y1={cy} x2={px} y2={py} stroke="#7C3AED" strokeWidth="1.5" opacity="0.6"/>
      <line x1={cosX} y1={py} x2={cosX} y2={cy} stroke="#7C3AED" strokeWidth="1" strokeDasharray="3,2" opacity="0.7"/>
      <line x1={px} y1={sinY} x2={cx} y2={sinY} stroke="#7C3AED" strokeWidth="1" strokeDasharray="3,2" opacity="0.7"/>
      <circle cx={px} cy={py} r="5" fill="#7C3AED"/>
      <text x={px} y={py+1} textAnchor="middle" dominantBaseline="middle" fontSize="7" fill="white" fontWeight="bold">{"\u2605"}</text>
      <text x={cx+r+4} y={cy+3} fontSize="7" fill="#94A3B8">1</text>
      <text x={cx-r-10} y={cy+3} fontSize="7" fill="#94A3B8">-1</text>
      <text x={cx+3} y={cy-r-3} fontSize="7" fill="#94A3B8">1</text>
      <text x={cx+3} y={cy+r+9} fontSize="7" fill="#94A3B8">-1</text>
    </svg>
  );
}

function trigoAngleDiff(a, b) {
  let d = Math.abs(a - b) % (2*Math.PI);
  return d > Math.PI ? 2*Math.PI - d : d;
}

function toTrigoLabel(tex) {
  return tex.replace(/\\t?frac\{([^}]+)\}\{([^}]+)\}/g,"$1/$2")
            .replace(/\\pi/g,"\u03c0").replace(/\\/g,"");
}

function TrigCircleSVG({ current, onPlace, state, playerAngle, levelColor }) {
  const svgRef = useRef();
  const getAngle = useCallback((e) => {
    const svg = svgRef.current; if(!svg) return null;
    const rect = svg.getBoundingClientRect();
    const touch = e.touches?.[0]||e.changedTouches?.[0];
    const cx = touch?touch.clientX:e.clientX;
    const cy = touch?touch.clientY:e.clientY;
    const sc = 310/rect.width;
    const dx=(cx-rect.left)*sc-CX_T, dy=(cy-rect.top)*sc-CY_T;
    if(Math.sqrt(dx*dx+dy*dy)<18) return null;
    let a=Math.atan2(-dy,dx); if(a<0) a+=2*Math.PI; return a;
  },[]);
  const handle=useCallback((e)=>{
    if(state!=="idle") return; e.preventDefault();
    const a=getAngle(e); if(a!==null) onPlace(a);
  },[state,getAngle,onPlace]);

  return (
    <svg ref={svgRef} viewBox="0 0 310 310" width="100%"
      style={{cursor:state==="idle"?"crosshair":"default",touchAction:"none",display:"block",margin:"0 auto"}}
      onClick={handle} onTouchEnd={handle}>
      <rect width="310" height="310" fill="#F8FAFC" rx="14"/>
      <line x1="18" y1={CY_T} x2="295" y2={CY_T} stroke="#94A3B8" strokeWidth="1.5"/>
      <line x1={CX_T} y1="18" x2={CX_T} y2="295" stroke="#94A3B8" strokeWidth="1.5"/>
      <polygon points={`295,${CY_T-4} 302,${CY_T} 295,${CY_T+4}`} fill="#94A3B8"/>
      <polygon points={`${CX_T-4},18 ${CX_T},11 ${CX_T+4},18`} fill="#94A3B8"/>
      <circle cx={CX_T} cy={CY_T} r={R_T} fill="none" stroke="#EF4444" strokeWidth="2"/>
      {TRIGO_L1.slice(0,16).map((p,i)=>(
        <circle key={i} cx={pxT(p.angle)} cy={pyT(p.angle)} r="5.5" fill={p.color} opacity="0.8"/>
      ))}
      <text x={CX_T+R_T+5}   y={CY_T+4}    fontSize="10" fill="#94A3B8">1</text>
      <text x={CX_T-R_T-14}  y={CY_T+4}    fontSize="10" fill="#94A3B8">-1</text>
      <text x={CX_T+4}       y={CY_T-R_T-4}fontSize="10" fill="#94A3B8">1</text>
      <text x={CX_T+4}       y={CY_T+R_T+13}fontSize="10"fill="#94A3B8">-1</text>
      <text x={CX_T+4}       y={CY_T+13}   fontSize="10" fill="#94A3B8">O</text>
      {state==="idle"&&<circle cx={CX_T} cy={CY_T} r={R_T} fill="none" stroke={current?.color||levelColor} strokeWidth="14" opacity="0.07"/>}
      {state==="wrong"&&playerAngle!==null&&(
        <><circle cx={pxT(playerAngle)} cy={pyT(playerAngle)} r="8" fill="#FBBF24"/>
          <text x={pxT(playerAngle)} y={pyT(playerAngle)+1} textAnchor="middle" dominantBaseline="middle" fontSize="11" fill="white" fontWeight="bold">✗</text></>
      )}
      {state!=="idle"&&current&&(()=>{
        const a=current.angle, ptx=pxT(a), pty=pyT(a), col=current.color;
        const lx=CX_T+(R_T+19)*Math.cos(a), ly=CY_T-(R_T+19)*Math.sin(a);
        const anchor=Math.cos(a)>0.1?"start":Math.cos(a)<-0.1?"end":"middle";
        const dyL=Math.sin(a)>0.1?-4:Math.sin(a)<-0.1?12:4;
        const cosAnch=Math.cos(a)>0.15?"start":Math.cos(a)<-0.15?"end":"middle";
        const cosY=Math.sin(a)>=0?CY_T+14:CY_T-6;
        const sinX=Math.cos(a)>=0?CX_T-5:CX_T+5;
        const sinAnch=Math.cos(a)>=0?"end":"start";
        return (<>
          <path d={`M${CX_T+32},${CY_T} A32,32 0 ${a>Math.PI?1:0},0 ${CX_T+32*Math.cos(a)},${CY_T-32*Math.sin(a)}`} fill="none" stroke={col} strokeWidth="2" opacity="0.7"/>
          <line x1={CX_T} y1={CY_T} x2={ptx} y2={pty} stroke={col} strokeWidth="1.8" opacity="0.6"/>
          <line x1={ptx} y1={pty} x2={ptx} y2={CY_T} stroke={col} strokeWidth="1.5" strokeDasharray="5,3" opacity="0.8"/>
          <line x1={ptx-4} y1={CY_T} x2={ptx+4} y2={CY_T} stroke={col} strokeWidth="2.5" opacity="0.95"/>
          <text x={ptx} y={cosY} textAnchor={cosAnch} fontSize="10" fontWeight="bold" fill={col} fontFamily="sans-serif">{current.cosS}</text>
          <line x1={ptx} y1={pty} x2={CX_T} y2={pty} stroke={col} strokeWidth="1.5" strokeDasharray="5,3" opacity="0.8"/>
          <line x1={CX_T} y1={pty-4} x2={CX_T} y2={pty+4} stroke={col} strokeWidth="2.5" opacity="0.95"/>
          <text x={sinX} y={pty+1} textAnchor={sinAnch} dominantBaseline="middle" fontSize="10" fontWeight="bold" fill={col} fontFamily="sans-serif">{current.sinS}</text>
          <circle cx={ptx} cy={pty} r="8" fill={col}/>
          <text x={ptx} y={pty+1} textAnchor="middle" dominantBaseline="middle" fontSize="11" fill="white" fontWeight="bold">{state==="correct"?"\u2713":"\u2605"}</text>
          <text x={lx} y={ly+dyL} textAnchor={anchor} fontSize="11" fontWeight="bold" fill={col} fontFamily="serif">{toTrigoLabel(current.displayTex)}</text>
        </>);
      })()}
    </svg>
  );
}

function CercleTrigoScreen({onBack}) {
  const [trigoScreen, setTrigoScreen] = useState("home"); // home | quiz | result
  const [levelId, setLevelId]         = useState(null);
  const [queue, setQueue]             = useState([]);
  const [idx, setIdx]                 = useState(0);
  const [score, setScore]             = useState(0);
  const [state, setState]             = useState("idle");
  const [playerAngle, setPlayer]      = useState(null);

  const level   = TRIGO_LEVELS.find(l=>l.id===levelId);
  const current = queue[idx];

  const startLevel = (id) => {
    const lv = TRIGO_LEVELS.find(l=>l.id===id);
    setLevelId(id);
    setQueue(shuffle(lv.questions));
    setIdx(0); setScore(0); setState("idle"); setPlayer(null);
    setTrigoScreen("quiz");
  };

  const handlePlace = useCallback((a) => {
    if(state!=="idle"||!current) return;
    const ok = trigoAngleDiff(a, current.angle) <= TRIGO_TOL;
    setPlayer(a); setState(ok?"correct":"wrong");
    if(ok) setScore(s=>s+1);
  }, [state, current]);

  const handleNext = () => {
    if(idx+1>=queue.length){ setTrigoScreen("result"); return; }
    setIdx(i=>i+1); setState("idle"); setPlayer(null);
  };

  if(trigoScreen==="home") return (
    <div className="slide-up" style={{display:"flex",flexDirection:"column",height:"100%",padding:"18px 16px 14px"}}>
      <Back onClick={onBack}/>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
        <div style={{width:36,height:36,borderRadius:10,background:"linear-gradient(135deg,#06B6D4,#0E7490)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>⭕</div>
        <div>
          <h2 style={{fontFamily:"'Nunito',sans-serif",fontSize:17,fontWeight:900,color:"#1E293B"}}>Cercle trigonométrique</h2>
          <p style={{fontSize:11,color:"#64748B"}}>Place l'angle sur le cercle · 20 questions</p>
        </div>
      </div>
      <Scroll>
        {TRIGO_LEVELS.map(lv=>(
          <button key={lv.id} onClick={()=>startLevel(lv.id)}
            style={{padding:"16px 18px",border:"none",borderRadius:16,
              background:`linear-gradient(135deg,${lv.color},${lv.color}cc)`,
              color:"#fff",cursor:"pointer",textAlign:"left",
              boxShadow:`0 3px 14px ${lv.color}33`,marginBottom:4,
              display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <div>
              <div style={{fontFamily:"'Nunito',sans-serif",fontSize:15,fontWeight:800}}>{lv.emoji} {lv.label}</div>
              <div style={{fontSize:12,opacity:.85,marginTop:2}}>{lv.sub}</div>
            </div>
            <span style={{fontSize:20,opacity:.8}}>→</span>
          </button>
        ))}
      </Scroll>
    </div>
  );

  if(trigoScreen==="result") {
    const pct = score/queue.length;
    const stars = pct>=.9?3:pct>=.6?2:pct>=.3?1:0;
    return (
      <div className="slide-up" style={{display:"flex",flexDirection:"column",height:"100%",padding:"24px 18px",alignItems:"center",justifyContent:"center",gap:14}}>
        <Sigma emotion={pct>=.75?"love":pct>=.5?"cool":"thinking"} size={140}/>
        <div style={{fontFamily:"'Nunito',sans-serif",fontSize:22,fontWeight:900,color:"#1E293B"}}>
          {pct===1?"Parfait !":pct>=.75?"Tr\u00e8s bien !":pct>=.5?"Pas mal !":"\u00c0 retravailler\u2026"}
        </div>
        <div style={{display:"flex",gap:4}}>{[1,2,3].map(s=><span key={s} style={{fontSize:32,opacity:s<=stars?1:.18}}>⭐</span>)}</div>
        <div style={{color:"#64748B",fontSize:15,fontWeight:700}}>{score} / {queue.length} correctes</div>
        <div style={{display:"flex",gap:8,width:"100%"}}>
          <button onClick={()=>startLevel(levelId)} style={{flex:1,padding:"13px",border:"none",borderRadius:13,
            background:`linear-gradient(135deg,${level?.color},${level?.color}bb)`,
            color:"#fff",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:800,cursor:"pointer"}}>
            🔄 Rejouer
          </button>
          <button onClick={()=>setTrigoScreen("home")} style={{flex:1,padding:"13px",border:"2px solid #E2E8F0",borderRadius:13,
            background:"#fff",color:"#64748B",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:700,cursor:"pointer"}}>
            ← Niveaux
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="slide-up" style={{display:"flex",flexDirection:"column",height:"100%",padding:"14px 14px 10px",gap:10}}>
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        <button onClick={()=>setTrigoScreen("home")} style={{flexShrink:0,padding:"4px 10px",border:"1.5px solid #E2E8F0",borderRadius:8,background:"#fff",color:"#64748B",fontSize:12,fontWeight:700,cursor:"pointer"}}>← Retour</button>
        <div style={{flex:1,height:6,background:"#E2E8F0",borderRadius:99,overflow:"hidden"}}>
          <div style={{width:`${(idx/queue.length)*100}%`,height:"100%",background:level?.color,borderRadius:99,transition:"width .4s"}}/>
        </div>
        <span style={{fontSize:12,color:"#94A3B8",fontWeight:700}}>{idx+1}/{queue.length}</span>
        <span style={{fontSize:13,fontWeight:800,color:"#F59E0B"}}>✦ {score}</span>
      </div>

      {current&&(
        <div style={{textAlign:"center",background:"#F0F4FF",borderRadius:14,padding:"10px 14px"}}>
          <div style={{fontSize:12,color:"#64748B",marginBottom:4}}>Place sur le cercle l'angle</div>
          <div style={{fontSize:24}}><M tex={current.displayTex}/></div>
          <div style={{fontSize:10,color:level?.color,fontWeight:700,marginTop:2}}>{level?.label} — {level?.sub}</div>
        </div>
      )}

      {current&&<TrigCircleSVG current={current} onPlace={handlePlace} state={state} playerAngle={playerAngle} levelColor={level?.color}/>}

      {state!=="idle"&&current&&(
        <div style={{borderRadius:12,padding:"10px 12px",
          background:state==="correct"?"#ECFDF5":"#FEF2F2",
          border:`2px solid ${state==="correct"?"#10B981":"#EF4444"}`,
          display:"flex",flexDirection:"column",gap:5,flexShrink:0}}>
          <div style={{fontWeight:800,fontSize:13,color:state==="correct"?"#065F46":"#991B1B"}}>
            {state==="correct"?"\u2705 Exact !":"\u274C La position \u2605 est la bonne"}
          </div>
          {current.reductionTex&&<div style={{fontSize:11,color:"#475569",background:"#F1F5F9",borderRadius:7,padding:"4px 8px"}}><M tex={current.reductionTex}/></div>}
          <div style={{fontSize:12,overflow:"hidden"}}><M tex={r_trigo`\cos\!\left(` + current.displayTex + r_trigo`\right)=` + current.cos}/></div>
          <div style={{fontSize:12,overflow:"hidden"}}><M tex={r_trigo`\sin\!\left(` + current.displayTex + r_trigo`\right)=` + current.sin}/></div>
        </div>
      )}

      {state!=="idle"&&(
        <button onClick={handleNext} style={{flexShrink:0,padding:"12px",border:"none",borderRadius:12,
          background:`linear-gradient(135deg,${level?.color},${level?.color}bb)`,
          color:"#fff",fontFamily:"'Nunito',sans-serif",fontSize:14,fontWeight:800,cursor:"pointer"}}>
          {idx+1<queue.length?"Angle suivant \u2192":"Voir mon score \uD83C\uDF89"}
        </button>
      )}
      {state==="idle"&&<div style={{textAlign:"center",fontSize:11,color:"#94A3B8",flexShrink:0}}>👆 Appuie sur le cercle pour placer le point</div>}
    </div>
  );
}

function AutoMaths() {
  const katexReady = useKaTeX();

  // ── Core quiz state ───────────────────────────────────────────────────────
  const [screen,    setScreen]    = useState("splash");
  const [mode,      setMode]      = useState(null);
  const [catId,     setCatId]     = useState(null);
  const [qCount,    setQCount]    = useState(10);
  const [pool,      setPool]      = useState([]);
  const [questions, setQuestions] = useState([]);
  const [score,     setScore]     = useState(0);

  // ── Mission state ─────────────────────────────────────────────────────────
  const [missionId,    setMissionId]    = useState(null);
  const [missionTheme, setMissionTheme] = useState(null);

  // ── Parcours state ────────────────────────────────────────────────────────
  const [profile,   setProfile]   = useState(null);
  const [profReady, setProfReady] = useState(false);
  const [diagResults, setDiagResults] = useState(null);
  const [weekProgram, setWeekProgram] = useState(null);
  const [allProgCache, setAllProgCache] = useState({});
  const [qrXp, setQrXp] = useState(0);
  const [qrBadges, setQrBadges] = useState([]);
  const [trackCat,  setTrackCat]  = useState(null); // catId being tracked
  const [trackSub,  setTrackSub]  = useState(null); // subId being tracked
  const [quizMode,  setQuizMode]  = useState(null); // "practice" | "test" | null
  const [prevStars, setPrevStars] = useState(0);
  const [newStars,  setNewStars]  = useState(0);
  const [streakProgress, setStreakProgress] = useState({ date: new Date().toDateString(), count: 0, completed: false });
  const [streakJustCompleted, setStreakJustCompleted] = useState(false);
  const [qState, setQState] = useState({});
  // ── Compte progressif ─────────────────────────────────────────────────────
  const [lifetimeCorrect, setLifetimeCorrect] = useState(0);
  const [showAccountPrompt, setShowAccountPrompt] = useState(false);
  // ── Sprint state ──────────────────────────────────────────────────────────
  const [sprintResult, setSprintResult] = useState(null); // {score, answered}
  const [sprintBest, setSprintBest] = useState(0);
  const [sprintIsNewBest, setSprintIsNewBest] = useState(false);

  // ── Cartes Sigma state ─────────────────────────────────────────────────────
  const [cardsUnlocked, setCardsUnlocked] = useState([]);
  const [cardsToShow, setCardsToShow]     = useState([]); // cartes à afficher dans CardUnlockModal

  // Load profile on mount
  useEffect(() => {
    loadProfA().then(p => {
      setProfile(p);
      setProfReady(true);
      // Applique immédiatement la taille de police préférée (si profil existe)
      const prefs = getPrefs(p);
      applyFontScale(prefs.fontScale);
    }).catch(() => setProfReady(true));
  }, []);

  // Load streak progress on mount (persiste à travers les sessions du même jour)
  useEffect(() => {
    loadStreakProgress().then(sp => setStreakProgress(sp)).catch(() => {});
    loadSprintBestFinal().then(b => setSprintBest(b)).catch(() => {});
    loadQState().then(s => setQState(s)).catch(() => {});
    loadLifetimeCorrect().then(n => setLifetimeCorrect(n)).catch(() => {});
    loadCardsUnlocked().then(arr => setCardsUnlocked(arr)).catch(() => {});
    loadDiagResults().then(d => { if (d) setDiagResults(d); }).catch(() => {});
    recordWeekendActivity().catch(() => {});
  }, []);

  // Helper centralisé : reconstruit le contexte et vérifie les déblocages.
  // Accepte des overrides pour les valeurs "just updated" pas encore dans l'état React.
  // Retourne la liste des nouvelles cartes (pour afficher la modale).
  const runUnlockCheck = async (overrides = {}) => {
    try {
      const [xpNow, psNow, spNow, remDone, missDone, wkDays,
             maxStreak, activeDays, nbQuiz, catsVisited, bacComp,
             remedCount, comboMax, morning, evening] = await Promise.all([
        loadXP(), loadPerfectScores(), loadSprintCount(),
        loadRemediationDone(), loadMissionThemesDone(), loadWeekendDays(),
        loadMaxStreak(), loadActiveDays(), loadNbQuiz(), loadCatsVisited(),
        loadBacCompleted(), loadRemediationCount(), loadComboMax(),
        loadMorningDone(), loadEveningDone(),
      ]);
      // Calcul de starsTotal à la volée depuis allProg
      let starsTotal = 0;
      try {
        const curr = CURRICULUM[profile?.level] || CURRICULUM.seconde;
        for (const catId of Object.keys(curr.cats)) {
          for (const subId of curr.cats[catId]) {
            const p = await loadProgA(catId, subId);
            if (p?.stars) starsTotal += p.stars;
          }
        }
      } catch(e) {}

      const ctx = {
        profile: overrides.profile !== undefined ? overrides.profile : profile,
        lifetimeCorrect: overrides.lifetimeCorrect !== undefined ? overrides.lifetimeCorrect : lifetimeCorrect,
        xp: overrides.xp !== undefined ? overrides.xp : xpNow,
        streakProgress: overrides.streakProgress !== undefined ? overrides.streakProgress : streakProgress,
        qState: overrides.qState !== undefined ? overrides.qState : qState,
        perfectScores: overrides.perfectScores !== undefined ? overrides.perfectScores : psNow,
        sprintCount: overrides.sprintCount !== undefined ? overrides.sprintCount : spNow,
        remediationDone: overrides.remediationDone !== undefined ? overrides.remediationDone : remDone,
        missionThemesDone: overrides.missionThemesDone !== undefined ? overrides.missionThemesDone : missDone,
        weekendDays: overrides.weekendDays !== undefined ? overrides.weekendDays : wkDays,
        // Nouveaux
        maxStreak, activeDays, nbQuiz, catsVisited,
        bacCompleted: bacComp, remediationCount: remedCount,
        comboMax, morningDone: morning, eveningDone: evening,
        starsTotal,
      };
      const newOnes = await checkNewUnlocks(ctx);
      if (newOnes.length > 0) {
        const updated = await loadCardsUnlocked();
        setCardsUnlocked(updated);
        setCardsToShow(prev => [...prev, ...newOnes]); // queue pour affichage
      }
      return newOnes;
    } catch (e) { return []; }
  };

  // NB: La streak est maintenant incrémentée uniquement quand l'élève atteint
  // STREAK_DAILY_THRESHOLD bonnes réponses dans la journée (voir handleCorrectAnswer).
  // Plus de logique automatique au chargement du profil.

  // ── Quiz helpers ──────────────────────────────────────────────────────────
  const [prevScreen, setPrevScreen] = useState("home");

  const startQuiz = async (qs, n, from) => {
    // Récupère les questions récemment vues pour les déprioriser (sans les exclure totalement)
    let avoidKeys = null;
    try { const recent = await loadRecentQ(); avoidKeys = new Set(recent); } catch {}
    const q = selectQuestionsSmart(qs, n, qState, avoidKeys);
    setPrevScreen(from || screen);
    setPool(qs); setQuestions(q); setScreen("quiz");
  };

  // Smart practice queue: mix review + new questions
  const buildPracticeQ = async (cId, sId) => {
    const allQ = DB[cId]?.[sId] || [];
    const prog  = await loadProgA(cId, sId);
    const failIdx = prog.fail || [];
    // Pick up to 4 failed questions
    const failQ = failIdx.slice(0,4).map(i=>allQ[i]).filter(Boolean);
    // Fill rest with fresh questions — on conserve la progressivité par tiers
    // + anti-répétition : les questions récemment vues sont déprioritées
    let avoidKeys = null;
    try { const recent = await loadRecentQ(); avoidKeys = new Set(recent); } catch {}
    const usedSet = new Set(failIdx);
    const freshPool = allQ.filter((_,i)=>!usedSet.has(i));
    const fresh = progressiveShuffle(freshPool, avoidKeys);
    const needed = 10 - failQ.length;
    // On reprend dans l'ordre progressif (facile → difficile) et on place les
    // questions ratées en premier (elles ont une priorité pédagogique).
    return [...shuffle(failQ), ...fresh.slice(0, needed)].slice(0, 10);
  };

  // ── Parcours launch ───────────────────────────────────────────────────────
  const hStartPractice = async (cId, sId, isDaily=false) => {
    setTrackCat(cId); setTrackSub(sId); setQuizMode(isDaily?"daily":"practice");
    setCatId(cId);
    const prog = await loadProgA(cId, sId);
    setPrevStars(prog.stars||0);
    const qs = await buildPracticeQ(cId, sId);
    setPrevScreen("dashboard");
    setPool(qs); setQuestions(qs); setScreen("quiz");
  };

  const hStartTest = async (cId, sId) => {
    setTrackCat(cId); setTrackSub(sId); setQuizMode("test");
    setCatId(cId);
    const prog = await loadProgA(cId, sId);
    setPrevStars(prog.stars||0);
    const allQ = DB[cId]?.[sId] || [];
    // Anti-répétition : on évite les questions récemment vues
    let avoidKeys = null;
    try { const recent = await loadRecentQ(); avoidKeys = new Set(recent); } catch {}
    const qs = progressiveShuffle(allQ, avoidKeys).slice(0, Math.min(15, allQ.length));
    setPrevScreen("dashboard");
    setPool(qs); setQuestions(qs); setScreen("quiz");
  };

  // ── Finish handler — saves progress ──────────────────────────────────────
  const hFinish = async (sc, failedIdx) => {
    setScore(sc);
    const total = questions.length;
    const pct   = Math.round(sc/total*100);

    // ── XP + Badges (safe, won't block quiz) ────────────────────────────────
    try {
      const xpEarned = sc * XP_PER_CORRECT;
      const currentXP = await loadXP();
      await saveXP(currentXP + xpEarned);
      const currentBadges = await loadBadges();
      const toUnlock = [];
      if(catId==="bac") toUnlock.push("bac_done");
      if(new Date().getHours() >= 22) toUnlock.push("night_owl");
      for(const bid of toUnlock) {
        if(!currentBadges.includes(bid)) await checkAndUnlockBadge(bid);
      }
    } catch(e) { /* Never block quiz for XP errors */ }

    // ── QState : mettre à jour le statut de chaque question du quiz ────────
    try {
      const failSet = new Set(failedIdx || []);
      const currentState = await loadQState();
      let newState = currentState;
      const seenKeys = []; // pour l'anti-répétition
      for (let i = 0; i < questions.length; i++) {
        const q = questions[i];
        const correct = !failSet.has(i);
        // Trouver à quelle (catId, subId, idx) appartient cette question
        // On scanne DB car on ne connaît pas nécessairement catId/subId du pool
        let key = null;
        for (const cId of Object.keys(DB)) {
          for (const sId of Object.keys(DB[cId])) {
            const arr = DB[cId][sId];
            if (!Array.isArray(arr)) continue;
            const idx = arr.indexOf(q);
            if (idx >= 0) {
              key = `${cId}:${sId}:${idx}`;
              break;
            }
          }
          if (key) break;
        }
        if (key) {
          newState = updateQStatus(newState, key, correct);
          seenKeys.push(key);
        }
      }
      await saveQState(newState);
      setQState(newState);
      // Mémoriser les questions vues pour éviter les répétitions au prochain quiz
      if (seenKeys.length > 0) await pushRecentQ(seenKeys);
    } catch(e) { /* Safe */ }

    // ── Lifetime : compter les bonnes réponses totales (pour prompt compte) ─
    try {
      if (sc > 0) {
        const lifetime = await loadLifetimeCorrect();
        const newLifetime = lifetime + sc;
        await saveLifetimeCorrect(newLifetime);
        setLifetimeCorrect(newLifetime);
        // Si pas de profile, vérifier le prompt
        if (!profile) {
          const dismissedAt = await loadPromptDismissedAt();
          if (shouldShowAccountPrompt(newLifetime, dismissedAt)) {
            setShowAccountPrompt(true);
          }
        }
      }
    } catch(e) { /* Safe */ }

    // ── Streak : incrémenter si on atteint le seuil aujourd'hui ───────────
    try {
      if (profile && sc > 0) {
        const prog = await loadStreakProgress();
        const newCount = prog.count + sc;
        const justCompleted = !prog.completed && newCount >= STREAK_DAILY_THRESHOLD;
        const updatedProg = {
          date: prog.date,
          count: newCount,
          completed: prog.completed || newCount >= STREAK_DAILY_THRESHOLD
        };
        await saveStreakProgress(updatedProg);
        setStreakProgress(updatedProg);

        // Si on vient d'atteindre le seuil pour la première fois aujourd'hui,
        // on met à jour la streak du profil.
        if (justCompleted) {
          const today = new Date().toDateString();
          const yesterday = new Date(Date.now() - 86400000).toDateString();
          const lastDay = profile.lastActive ? new Date(profile.lastActive).toDateString() : null;
          let newStreak;
          if (lastDay === today) {
            // Défense : déjà actif aujourd'hui (ne devrait pas arriver car justCompleted=true)
            newStreak = profile.streak || 1;
          } else if (lastDay === yesterday) {
            newStreak = (profile.streak || 0) + 1;
          } else {
            newStreak = 1;
          }
          const updatedProfile = { ...profile, streak: newStreak, lastActive: Date.now() };
          setProfile(updatedProfile);
          saveProfA(updatedProfile);
          setStreakJustCompleted(true);
          // Note: les badges streak3/streak7 sont retirés — remplacés par les cartes
          // Sigma London (3j) et Sigma NYC (7j) qui se débloquent via runUnlockCheck.
        }
      }
    } catch(e) { /* Safe */ }

    if (trackCat && trackSub && quizMode) {
      const prog = await loadProgA(trackCat, trackSub);

      if (quizMode === "practice") {
        const newPc = (prog.pc||0) + sc;
        const newPt = (prog.pt||0) + total;
        const allQ = DB[trackCat]?.[trackSub] || [];
        const newFail = (failedIdx||[]).map(i => {
          const q = questions[i];
          return allQ.findIndex(x=>x===q);
        }).filter(i=>i>=0);
        const merged = [...new Set([...(prog.fail||[]),...newFail])].slice(0,10);
        const correctIdx = questions.map((_,i)=>i).filter(i=>!(failedIdx||[]).includes(i));
        const correctQSet = new Set(correctIdx.map(i=>{
          const q=questions[i];
          return allQ.findIndex(x=>x===q);
        }));
        const prunedFail = merged.filter(i=>!correctQSet.has(i));
        await saveProgA(trackCat, trackSub, {...prog, pc:newPc, pt:newPt, fail:prunedFail, lp:Date.now()});
        setNewStars(prog.stars||0);
      } else {
        const earned = pct>=90?3:pct>=80?2:pct>=60?1:0;
        const bestStars = Math.max(prog.stars||0, earned);
        const bestTb    = Math.max(prog.tb||0, pct);
        await saveProgA(trackCat, trackSub, {...prog, stars:bestStars, tb:bestTb, lt:Date.now()});
        setNewStars(bestStars);
        // XP étoiles (badges first_star / triple_star retirés — couverts par cartes)
        try {
          const currentXP2 = await loadXP();
          const starBonus = (bestStars - (prog.stars||0)) * XP_PER_STAR;
          if(starBonus>0) await saveXP(currentXP2 + starBonus);
        } catch(e) {}
      }
    }

    // ── Daily challenge completion ─────────────────────────────────────────
    if(quizMode==="daily") {
      try {
        const dailyXP = await loadXP();
        await saveXP(dailyXP + XP_DAILY);
        await saveDaily({done:true, date:new Date().toDateString()});
        await checkAndUnlockBadge("daily3");
      } catch(e) {}
    }

    // ── Cartes Sigma : tracking complet pour les 100 cartes ─────────────────
    try {
      // 1. Score parfait
      if (pct === 100 && total > 0) {
        const ps = await loadPerfectScores();
        await savePerfectScores(ps + 1);
      }
      // 2. Mission terminée avec succès (score >= 60%)
      if (mode === "missions" && trackCat && trackSub && pct >= 60) {
        const done = await loadMissionThemesDone();
        const key = `${trackCat}:${trackSub}`;
        if (!done.includes(key)) {
          done.push(key);
          await saveMissionThemesDone(done);
        }
      }
      // 3. Remédiation terminée (vient de l'écran Vigilance)
      if (prevScreen === "vigilance" && total > 0) {
        await saveRemediationDone();
        const rc = await loadRemediationCount();
        await saveRemediationCount(rc + 1);
      }
      // 4. Sujet Bac complété (score >= 60%)
      if (catId === "bac" && trackCat && trackSub && pct >= 60) {
        const bc = await loadBacCompleted();
        await saveBacCompleted(bc + 1);
      }
      // 5. maxStreak (met à jour si streak actuel dépasse)
      if (profile?.streak) {
        const ms = await loadMaxStreak();
        if (profile.streak > ms) await saveMaxStreak(profile.streak);
      }
      // 6. activeDays
      const today = new Date().toISOString().slice(0,10);
      const ads = await loadActiveDays();
      if (!ads.includes(today)) {
        ads.push(today);
        // Ne pas laisser grossir infiniment : on garde les 400 derniers jours
        if (ads.length > 400) ads.splice(0, ads.length - 400);
        await saveActiveDays(ads);
      }
      // 7. nbQuiz
      if (total > 0) {
        const nq = await loadNbQuiz();
        await saveNbQuiz(nq + 1);
      }
      // 8. catsVisited
      if (trackCat) {
        const cv = await loadCatsVisited();
        // On enregistre aussi le catId original (bac, missions) si différent
        const catsToAdd = [];
        if (!cv.includes(trackCat)) catsToAdd.push(trackCat);
        if (catId && catId !== trackCat && !cv.includes(catId)) catsToAdd.push(catId);
        if (catsToAdd.length > 0) {
          await saveCatsVisited([...cv, ...catsToAdd]);
        }
      }
      // 9. starsTotal : recalculé à partir de toutes les entrées allProg
      //    (on évite une clé séparée pour ne pas désynchroniser)
      //    Cf. runUnlockCheck — on le calcule à la volée via loadAllProg.
      // 10. morningDone / eveningDone
      const hour = new Date().getHours();
      if (hour < 10) await saveMorningDone();
      if (hour >= 18) await saveEveningDone();
    } catch(e) { /* Safe */ }

    // ── Vérifier les déblocages de cartes (fire-and-show) ──────────────────
    await runUnlockCheck();

    setScreen(quizMode ? "parcours_result" : "result");
  };

  // ── Standard quiz handlers ────────────────────────────────────────────────
  const hReplay   = () => { setQuestions(progressiveShuffle(pool).slice(0,qCount)); setScreen("quiz"); };
  const hHome     = () => { setScreen("home"); setMode(null); setCatId(null); setQuizMode(null); setTrackCat(null); setTrackSub(null); };
  const hDashboard= () => { setQuizMode(null); setTrackCat(null); setTrackSub(null); setScreen(profile?"dashboard":"home"); };
  const hMode     = m  => {
    setMode(m);
    if (m === "bac") setScreen("bac_subjects");
    else if (m === "missions") { setCatId("missions"); setScreen("subcategory"); }
    else if (m === "train") setScreen("training_modes"); // écran intermédiaire
    else if (m === "express") setScreen("category");
    else if (m === "entrainement") setScreen("category");
    else if (m === "test_aleatoire") setScreen("test_aleatoire");
    else if (m === "sprint") setScreen("sprint");
    else setScreen("category");
  };
  // Choix depuis l'écran intermédiaire S'entraîner
  const hTrainingMode = m => {
    setMode(m);
    if (m === "express") setScreen("category");
    else if (m === "entrainement") setScreen("category");
    else if (m === "test_aleatoire") setScreen("test_aleatoire");
    else setScreen("category");
  };
  const hCat      = cid=> {
    setCatId(cid);
    // En Test aléatoire — Mix dans une catégorie : on demande directement le count
    if (mode === "test_aleatoire") setScreen("count");
    else setScreen("subcategory");
  };
  // Quand des questions sont sélectionnées depuis SubcategoryScreen
  const hSub      = qs => {
    if (mode === "express") {
      setQCount(10);
      startQuiz(qs, 10, screen);
    } else if (mode === "entrainement") {
      // On stocke les questions et on demande le volume (20/50)
      setPendingPool(qs);
      setScreen("count");
    } else {
      // Fallback (missions par ex.) : comportement d'origine
      const n = 20;
      setQCount(n);
      startQuiz(qs, n, screen);
    }
  };
  const [levelType,  setLevelType]  = useState("racines");
  const [pendingPool, setPendingPool] = useState(null);
  const hLevelPicker = (_id, type) => { 
    if (type === 'mission') {
      setMissionId(_id);
      setScreen("mission_select");
    } else {
      setLevelType(type||"racines"); 
      setScreen("level_picker"); 
    }
  };
  const hBacStart = (subId, qs) => { setCatId("bac"); setPrevScreen("bac_subjects"); setPool(qs); setQuestions(shuffle(qs)); setScreen("quiz"); };
  const hCount    = n  => {
    setQCount(n);
    if (mode === "entrainement" && pendingPool) {
      // Entraînement : lance le quiz sur les questions sélectionnées en sous-thèmes
      const qs = pendingPool;
      setPendingPool(null);
      startQuiz(qs, n, "count");
    } else if (mode === "test_aleatoire") {
      // Test aléatoire : global ou par catégorie
      const qs = catId ? getCatQ(catId) : getAllQ();
      startQuiz(qs, n, "count");
    } else {
      // Fallback
      startQuiz(catId ? getCatQ(catId) : getAllQ(), n, "count");
    }
  };
  const hTestGlobal   = () => { setCatId(null); setScreen("count"); };
  const hTestCategory = () => { setScreen("category"); };
  
  // ── Vigilance (Points de vigilance) handlers ─────────────────────────────
  const hVigilance = () => { setScreen("vigilance"); };
  // Séance de remédiation : rassemble jusqu'à 15 questions en difficulté (toutes sous-cat confondues)
  const hRemediation = () => {
    const difficult = [];
    for (const key of Object.keys(qState)) {
      const entry = qState[key];
      if (!entry || entry.status !== "learning") continue;
      // Qualifier comme "en difficulté" si au moins 2 tentatives et >=40% d'échec
      const failRate = entry.attempts > 0 ? 1 - (entry.successes / entry.attempts) : 0;
      if (entry.attempts >= 2 && failRate >= 0.4) {
        const parts = key.split(':');
        if (parts.length !== 3) continue;
        const [cId, sId, idxStr] = parts;
        const idx = parseInt(idxStr);
        const q = DB[cId]?.[sId]?.[idx];
        if (q) difficult.push(q);
      }
    }
    if (difficult.length === 0) return; // sécurité — le bouton ne s'affiche pas si rien
    const selected = shuffle(difficult).slice(0, 15);
    setQCount(selected.length);
    setMode("entrainement"); // traiter comme un entrainement normal pour le routage
    setPool(selected); setQuestions(selected);
    setPrevScreen("vigilance");
    setScreen("quiz");
  };
  // Travailler un thème précis depuis Points de vigilance
  const hWorkTheme = (cId, sId) => {
    const allQ = DB[cId]?.[sId] || [];
    setCatId(cId);
    setMode("entrainement");
    const selected = selectQuestionsSmart(allQ, 10, qState);
    setQCount(selected.length);
    setPool(selected); setQuestions(selected);
    setPrevScreen("vigilance");
    setScreen("quiz");
  };
  
  // ── Sprint handlers ───────────────────────────────────────────────────────
  // Pool : toutes les questions QCM de l'app (celles avec .choices et sans pad/tableau/drag/graph lourd)
  const getSprintPool = () => {
    // Liste blanche : on n'accepte que les QCM strictement textuels.
    // Tout champ non listé ici est rejeté pour éviter qu'une question avec rendu
    // spécial (graphique, tableau, ...) apparaisse sans son visuel dans le sprint.
    const ALLOWED_FIELDS = new Set(['q', 'choices', 'a', 'tip', 'hint', 'altAnswers', 'partialAnswers']);
    return getAllQ().filter(q => {
      if (!q.choices) return false;
      for (const k of Object.keys(q)) {
        if (!ALLOWED_FIELDS.has(k)) return false;
      }
      return true;
    });
  };
  const hSprintFinish = async (result) => {
    // Calcul du score final cohérent avec SprintResultScreen
    const {score, answered, bestCombo = 0} = result;
    const pct = answered > 0 ? Math.round(score / answered * 100) : 0;
    const accuracyScore = Math.round(score * pct / 100);
    const comboBonus = bestCombo * 2;
    const finalScore = accuracyScore + comboBonus;

    setSprintResult(result);
    const isNew = finalScore > sprintBest;
    setSprintIsNewBest(isNew);
    if (isNew) {
      setSprintBest(finalScore);
      await saveSprintBestFinal(finalScore);
    }
    // Lifetime counter (pour prompt de compte progressif)
    try {
      if (result.score > 0) {
        const lifetime = await loadLifetimeCorrect();
        const newLifetime = lifetime + result.score;
        await saveLifetimeCorrect(newLifetime);
        setLifetimeCorrect(newLifetime);
        if (!profile) {
          const dismissedAt = await loadPromptDismissedAt();
          if (shouldShowAccountPrompt(newLifetime, dismissedAt)) {
            setShowAccountPrompt(true);
          }
        }
      }
    } catch(e) {}
    // On profite du sprint pour alimenter le compteur streak (comme un quiz normal)
    try {
      if (profile && result.score > 0) {
        const prog = await loadStreakProgress();
        const newCount = prog.count + result.score;
        const justCompleted = !prog.completed && newCount >= STREAK_DAILY_THRESHOLD;
        const updatedProg = {
          date: prog.date,
          count: newCount,
          completed: prog.completed || newCount >= STREAK_DAILY_THRESHOLD
        };
        await saveStreakProgress(updatedProg);
        setStreakProgress(updatedProg);
        if (justCompleted) {
          const today = new Date().toDateString();
          const yesterday = new Date(Date.now()-86400000).toDateString();
          const lastDay = profile.lastActive ? new Date(profile.lastActive).toDateString() : null;
          let newStreak;
          if (lastDay === today) newStreak = profile.streak || 1;
          else if (lastDay === yesterday) newStreak = (profile.streak || 0) + 1;
          else newStreak = 1;
          const updatedProfile = {...profile, streak:newStreak, lastActive:Date.now()};
          setProfile(updatedProfile);
          saveProfA(updatedProfile);
          setStreakJustCompleted(true);
          // Badges streak3/streak7 retirés — remplacés par cartes London (3j) et NYC (7j)
        }
      }
    } catch(e) {}
    // ── Cartes Sigma : incrémenter le compteur Sprint + vérifier déblocages ─
    try {
      const sc = await loadSprintCount();
      await saveSprintCount(sc + 1);
    } catch(e) {}
    await runUnlockCheck();
    setScreen("sprint_result");
  };
  const hSprintReplay = () => {
    setSprintResult(null); setSprintIsNewBest(false);
    setScreen("sprint");
  };

  // ── Profile handlers ──────────────────────────────────────────────────────
  const hProfileComplete = (prof) => { setProfile(prof); setScreen("diagnostic"); };
  const hDiagComplete = (results) => { setDiagResults(results); saveDiagResults(results).catch(()=>{}); setScreen("diag_result"); };
  const hDiagResultNext = async () => {
    const prog = allProgCache;
    const wp = await generateWeeklyProgram(profile, prog, diagResults);
    setWeekProgram(wp); setScreen("weekly_program");
  };
  const hProgramSession = (day) => { hStartPractice(day.catId, day.subId); };
  const hProgramSkip = () => setScreen("dashboard");
  const hEditProfile     = () => setScreen("setup");
  const hLogout          = () => { setProfile(null); saveProfA(null); setScreen("splash"); };

  // ── Backup handlers ───────────────────────────────────────────────────────
  const hBackup = () => setScreen("backup");
  const hImportDone = async () => {
    // Après import : on recharge tout depuis le storage restauré
    try {
      const p = await loadProfA();
      setProfile(p);
      const sp = await loadStreakProgress(); setStreakProgress(sp);
      const sb = await loadSprintBestFinal(); setSprintBest(sb);
      const qs = await loadQState(); setQState(qs);
      const lc = await loadLifetimeCorrect(); setLifetimeCorrect(lc);
      const cu = await loadCardsUnlocked(); setCardsUnlocked(cu);
      const dr = await loadDiagResults(); if (dr) setDiagResults(dr);
      // Appliquer les préférences immédiatement
      if (p) {
        const prefs = getPrefs(p);
        applyFontScale(prefs.fontScale);
      }
      setScreen(p ? "dashboard" : "home");
    } catch(e) {
      setScreen("splash");
    }
  };

  // ── Export progress for teacher dashboard ────────────────────────────────
  const hExportProgress = async () => {
    // Load XP + badges for QR screen
    try {
      const xp = await loadXP().catch(()=>0);
      const badges = await loadBadges().catch(()=>[]);
      setQrXp(xp); setQrBadges(badges);
      setScreen("qr_export");
    } catch(e) { alert('Erreur export'); }
  };

  const hExportJSON = async () => {
    try {
      const curr = CURRICULUM[profile.level] || CURRICULUM.seconde;
      const entries = [];
      Object.entries(curr.cats).forEach(([c,subs])=>subs.forEach(s=>entries.push([c,s])));
      const progData = {};
      await Promise.all(entries.map(async ([c,s]) => {
        try {
          const r = await _storage.get(PK(c,s));
          if(r?.value) progData[`${c}:${s}`] = JSON.parse(r.value);
        } catch {}
      }));
      const xp = await loadXP().catch(()=>0);
      const badges = await loadBadges().catch(()=>[]);
      const exportData = {
        profile: { name:profile.name, level:profile.level, streak:profile.streak||0 },
        progress: progData,
        xp,
        badges,
        exportedAt: new Date().toISOString(),
      };
      const json = JSON.stringify(exportData, null, 2);
      const blob = new Blob([json], {type:'application/json'});
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `automaths-${profile.name.toLowerCase().replace(/\s/g,'-')}.json`;
      a.click();
      URL.revokeObjectURL(url);
    } catch(e) { alert('Erreur lors de l\'export'); }
  };

  if (!katexReady) return (
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",
      height:"100vh",flexDirection:"column",gap:16,fontFamily:"'DM Sans',sans-serif",
      background:"linear-gradient(170deg,var(--am-bg-dark-1),var(--am-bg-dark-2))"}}>
      <div className="float"><Sigma emotion="thinking" size={64}/></div>
      <div style={{fontFamily:"'Nunito',sans-serif",fontWeight:900,fontSize:22,color:"#fff"}}>
        l'Auto<span style={{color:"#F59E0B"}}>Maths</span>
      </div>
      <p style={{color:"#475569",fontSize:13}}>Chargement…</p>
    </div>
  );

  const th_main = getTheme(profile);
  const currentScale = getPrefs(profile).fontScale;
  const scaleFactor = FONT_SCALES[currentScale]?.factor || 1.0;

  return (
    <>
      <GS profile={profile}/>
      <div style={{
        width:390, height:760, background: th_main.bgLight,
        borderRadius:44, overflow:"hidden", position:"relative",
        boxShadow:"0 30px 80px rgba(0,0,0,.25), 0 0 0 10px #1E293B, 0 0 0 12px #334155",
      }}>
        <div style={{position:"absolute",top:0,left:"50%",transform:"translateX(-50%)",
          width:120,height:26,background:"#1E293B",borderRadius:"0 0 18px 18px",zIndex:10}}/>
        
        <div style={{height:"100%",overflowY:"auto",paddingTop:26,
          // Zoom via la propriété CSS `zoom` (supportée Chrome/Safari/Firefox).
          // Avantage vs transform:scale : ne casse pas les positionnements
          // absolus, les modales, les dropdowns. Simple et fiable.
          zoom: scaleFactor,
        }}>

          {screen==="splash"        && <SplashScreen    onStart={()=>setScreen(profile?"dashboard":"home")} onMySpace={()=>setScreen(profile?"dashboard":"setup")} onRestore={()=>setScreen("backup")} profile={profile}/>}
          {screen==="setup"         && <ProfileSetupScreen onComplete={hProfileComplete} onBack={()=>setScreen("splash")} onRestore={()=>setScreen("backup")}/>}
          {screen==="qr_export"    && profile && <QRExportScreen profile={profile} allProg={allProgCache} xp={qrXp} badges={qrBadges} onBack={()=>setScreen("dashboard")}/>}
          {screen==="send_teacher" && profile && <SendToTeacherScreen profile={profile} onBack={()=>setScreen("backup")}/>}
          {screen==="backup"       && <BackupScreen onBack={()=>setScreen(profile?"dashboard":"splash")} onImportDone={hImportDone} onSendTeacher={()=>setScreen("send_teacher")} hasProfile={!!profile}/>}
          {screen==="reminder"     && <ReminderScreen onBack={()=>setScreen("dashboard")}/>}
          {screen==="preferences"  && profile && <PreferencesScreen profile={profile} onSave={(p)=>{setProfile(p);setScreen("dashboard");}} onBack={()=>setScreen("dashboard")}/>}
          {screen==="diagnostic"    && profile && <DiagnosticScreen profile={profile} onComplete={hDiagComplete}/>}
          {screen==="diag_result"   && profile && diagResults && <DiagnosticResultScreen profile={profile} diagResults={diagResults} onStart={hDiagResultNext}/>}
          {screen==="weekly_program"&& profile && weekProgram  && <WeeklyProgramScreen profile={profile} program={weekProgram} allProg={allProgCache} onStartSession={hProgramSession} onSkip={hProgramSkip}/>}
          {screen==="dashboard"     && profile && <DashboardScreen profile={profile} diagResults={diagResults} cardsUnlocked={cardsUnlocked} qState={qState} onStartPractice={hStartPractice} onStartTest={hStartTest} onGoHome={()=>setScreen("home")} onEditProfile={hEditProfile} onLogout={hLogout} onExport={hExportProgress} onBackup={hBackup} onReminder={()=>setScreen("reminder")} onPreferences={()=>setScreen("preferences")} onVigilance={hVigilance} onCollection={()=>setScreen("collection")} onShowProgram={async()=>{const wp=await generateWeeklyProgram(profile,allProgCache,diagResults);setWeekProgram(wp);setScreen("weekly_program");}}/>}
          {screen==="home"          && <HomeScreen onMode={hMode} profile={profile} onDashboard={profile?hDashboard:null} onSplash={()=>setScreen("splash")} streakProgress={streakProgress}/>}
          {screen==="test_aleatoire" && <TestAleatoireScreen onGlobal={hTestGlobal} onCategory={hTestCategory} onBack={()=>setScreen(mode==="test_aleatoire"?"training_modes":"home")}/>}
          {screen==="training_modes" && <TrainingModesScreen onMode={hTrainingMode} onBack={()=>setScreen("home")}/>}
          {screen==="sprint"        && <SprintScreen    pool={getSprintPool()} onFinish={hSprintFinish} onBack={()=>{setSprintResult(null);setScreen("home");}}/>}
          {screen==="sprint_result" && sprintResult && <SprintResultScreen result={sprintResult} best={sprintBest} isNewBest={sprintIsNewBest} onReplay={hSprintReplay} onHome={()=>{setSprintResult(null);setSprintIsNewBest(false);setStreakJustCompleted(false);setScreen("home");}}/>}
          {screen==="vigilance"     && profile && <VigilanceScreen profile={profile} qState={qState} onBack={()=>setScreen("dashboard")} onRemediation={hRemediation} onWorkTheme={hWorkTheme}/>}
          {screen==="collection"    && <CollectionScreen onBack={()=>setScreen(profile?"dashboard":"home")} cardsUnlocked={cardsUnlocked}/>}
          {screen==="category"      && <CategoryScreen  onCat={hCat} onBack={()=>setScreen((mode==="express"||mode==="entrainement")?"training_modes":mode==="test_aleatoire"?"test_aleatoire":"home")} subtitle={mode==="express"?"Choisis une catégorie":mode==="entrainement"?"Choisis une catégorie":mode==="test_aleatoire"?"Toutes les questions de la catégorie":"Puis choisis des sous-thèmes"}/>}
          {screen==="subcategory"   && <SubcategoryScreen catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen(mode==="missions"?"home":"category")} onLevelPicker={hLevelPicker} defaultNiveau={profile?LEVEL_MAP[profile.level]||null:null}/>}
          {screen==="mission_select" && <MissionScreen missionId={missionId} onBack={()=>setScreen("subcategory")} onSelectTheme={(theme)=>{
            setMissionTheme(theme);
            if(theme.useBacBlanc) {
              // Bac blanc : tire directement 30 questions dans tout le programme
              const qs = buildBacBlancPool(theme.useBacBlanc, 30);
              if (qs.length === 0) {
                alert("Aucune question disponible pour ce bac blanc. Vérifie le programme.");
                return;
              }
              setQuizMode("test"); // Mode évaluation — pas de rappel de cours
              setCatId("bac");     // Utilise le style visuel "bac" (couleur or)
              setTrackCat(null); setTrackSub(null); // Pas de progression sur une sub spécifique
              setPool(qs);
              setQuestions(qs);
              setPrevScreen("mission_select");
              setScreen("quiz");
            } else if(theme.useLevelPicker) {
              setLevelType(theme.levelType);
              setScreen("level_picker");
            } else {
              setScreen("mission_theme");
            }
          }}/>}
          {screen==="mission_theme" && missionTheme && <MissionThemeScreen theme={missionTheme} missionId={missionId} onBack={()=>setScreen("mission_select")} onStart={(qs, themeId)=>{
            setPrevScreen("mission_theme");
            setQuestions(qs);
            setScore(0);
            setScreen("quiz");
          }}/>}
          {screen==="level_picker"  && levelType==="relatifs"      && <RelatifLevelScreen       catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen(missionId ? "mission_select" : "subcategory")}/>}
          {screen==="level_picker"  && levelType==="reduction"     && <ReductionLevelScreen     catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen(missionId ? "mission_select" : "subcategory")}/>}
          {screen==="level_picker"  && levelType==="racines"       && <RacinesLevelScreen       catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen("subcategory")}/>}
          {screen==="level_picker"  && levelType==="identites"     && <IdentitesLevelScreen     catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen(missionId ? "mission_select" : "subcategory")}/>}
          {screen==="level_picker"  && levelType==="factorisation" && <FactorisationLevelScreen catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen(missionId ? "mission_select" : "subcategory")}/>}
          {screen==="level_picker"  && levelType==="denominateur"  && <DenomLevelScreen         catId={catId} qCount={mode==="express"?10:20} onStart={hSub} onBack={()=>setScreen(missionId ? "mission_select" : "subcategory")}/>}
          {screen==="level_picker"  && levelType==="cercle_trigo"  && <CercleTrigoScreen onBack={()=>setScreen("subcategory")}/>}
          {screen==="bac_subjects"   && <BacSubjectScreen onStart={hBacStart} onBack={()=>setScreen("home")}/>}
          {screen==="count"         && <CountScreen     catId={mode==="bac"?null:(mode==="test_aleatoire"&&!catId?null:catId)} allMode={mode==="bac"||(mode==="test_aleatoire"&&!catId)} options={mode==="entrainement"||mode==="test_aleatoire"?[20,50]:[10,20]} onCount={hCount} onBack={()=>setScreen(mode==="entrainement"?"subcategory":mode==="test_aleatoire"?"test_aleatoire":mode==="bac"?"home":"category")}/>}
          {screen==="quiz"          && <QuizScreen      questions={questions} catId={catId||"fonctions"} subId={trackSub} quizMode={quizMode} onFinish={hFinish} onBack={()=>setScreen(prevScreen)}/>}
          {screen==="result"        && <ResultScreen    score={score} total={questions.length} catId={catId||"fonctions"} onReplay={()=>{setStreakJustCompleted(false);hReplay();}} onHome={()=>{setStreakJustCompleted(false);hHome();}} streakJustCompleted={streakJustCompleted} streakCount={profile?.streak||0}/>}
          {screen==="parcours_result"&&<PostPracticeResultScreen score={score} total={questions.length} catId={trackCat} subId={trackSub} mode={quizMode} prevStars={prevStars} newStars={newStars} onRetry={()=>quizMode==="practice"?hStartPractice(trackCat,trackSub):hStartTest(trackCat,trackSub)} onDashboard={hDashboard} onHome={hHome}/>}

        </div>
        <div style={{position:"absolute",bottom:8,left:"50%",transform:"translateX(-50%)",
          width:120,height:5,background:"#CBD5E1",borderRadius:99}}/>
      </div>
      {/* Modal compte progressif — overlay visible sur tous les écrans quand déclenché */}
      {showAccountPrompt && !profile && (
        <AccountPromptModal
          lifetime={lifetimeCorrect}
          onAccept={() => { setShowAccountPrompt(false); setScreen("setup"); }}
          onDismiss={async () => {
            await savePromptDismissedAt(lifetimeCorrect);
            setShowAccountPrompt(false);
          }}
        />
      )}
      {/* Modal de déblocage de carte — overlay prioritaire sur tous les écrans */}
      {cardsToShow.length > 0 && (
        <CardUnlockModal
          cards={cardsToShow}
          onClose={() => { setCardsToShow([]); setScreen("collection"); }}
        />
      )}
    </>
  );
}


// ── Service Worker : enregistrement + détection de mise à jour ──────────────
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('/service-worker.js').then(reg => {
    reg.addEventListener('updatefound', () => {
      const newSW = reg.installing;
      newSW.addEventListener('statechange', () => {
        if (newSW.state === 'activated' && navigator.serviceWorker.controller) {
          location.reload();
        }
      });
    });
  });

  let refreshing = false;
  navigator.serviceWorker.addEventListener('controllerchange', () => {
    if (!refreshing) {
      refreshing = true;
      location.reload();
    }
  });
}

// ── Render ───────────────────────────────────────────────────────────────────
const domRoot = document.getElementById('root');
if (domRoot) {
  ReactDOM.createRoot(domRoot).render(React.createElement(AutoMaths));
}
